INSERT INTO `university` VALUES (2, 'beida', '123', '北京大学', ' ', 'UNIVERSITY', '010-62751407', 'qhdax@qq.com', '审核通过', 31, '北京市海淀区颐和园路5号', '教育部', '“双一流”建设高校', 'https://www.pku.edu.cn', '本科', '<h2 style=\"text-align: left;\">学校领导</h2><p>郝　平</p><p>北京大学党委书记</p><p><br></p><p style=\"text-indent: 2em;\">郝平，男，汉族，1959年9月生，籍贯山东青岛，1982年6月入党，1982年8月参加工作，北京大学国际关系学专业毕业，研究生学历，博士学位，教授，博士生导师。</p><p style=\"text-indent: 2em;\">北京大学党委书记。主持党委全面工作。</p><p style=\"text-indent: 2em;\">1978年至1982年，北京大学历史学系世界历史专业学生。1982年至1986年，在北京大学校长办公室等校机关工作。1986年至1991年，任北京大学学生工作部副部长。1991年至1992年，美国东西方中心交流访问进修。1992年至1995年，美国夏威夷大学历史系硕士研究生。1996年至2001年，任北京大学国际合作部部长、校长助理（1997.04）、教育基金会副理事长（1998.09）、党委常委（1999.02）（其间：1995-1999年在职攻读北京大学国际关系学专业博士研究生）。2001年至2005年，任北京大学副校长、党委常委。2005年至2009年，任北京外国语大学校长。2009年至2016年，任教育部副部长、党组成员，中国联合国教科文组织全国委员会主任、中国红十字会副会长（2011.09-2016.12），联合国教科文组织第37届大会主席（2013.11-2015.11）。2016年12月至2018年10月，任北京大学党委书记、校务委员会主任。2018年10月至2022年6月，任北京大学党委副书记、校长。2022年6月任北京大学党委书记。</p><p style=\"text-indent: 2em;\">十九届中央委员会候补委员，十一届全国政协委员。</p><p style=\"text-indent: 2em;\">主要专著有：《北京大学创办史实考源》《孙中山革命与美国》《无奈的结局——司徒雷登与中国》。</p><p style=\"text-indent: 2em; text-align: left;\"><br></p><p style=\"text-indent: 2em; text-align: left;\">龚旗煌</p><p style=\"text-indent: 2em; text-align: left;\">北京大学党委副书记、校长</p><p style=\"text-indent: 2em; text-align: left;\"><br></p><p style=\"text-indent: 2em;\">龚旗煌，男，汉族，1964年8月出生，籍贯福建省莆田市，中共党员，1985年7月参加工作，理学博士，博雅讲席教授，教育部长江学者特聘教授，中国科学院院士，发展中国家科学院院士。</p><p style=\"text-indent: 2em;\">北京大学党委副书记、校长，兼任教务长、研究生院院长、教代会执委会主任。主持行政全面工作。</p><p style=\"text-indent: 2em;\">1979-1983年，北京大学物理系本科生；1983-1989年，北京大学物理系硕博连读研究生；1989-1991年，北京大学化学系/物理系博士后；1991年至今，先后任北京大学物理系（学院）讲师（1991年）、副教授（1991年）、教授（1995年），教育部长江学者特聘教授（1998年度），北京大学博雅讲席教授（2016年）。1988-1989年，作为联合培养博士生，在英国曼彻斯特大学学习；1994-1995年，作为前沿科学研究员，在日本理化学研究所访问研究；2008年，作为DAAD学者在德国维尔兹堡大学进行合作研究。2007年、2010年和2018年分别当选为英国皇家物理学会会士、美国光学学会会士和国际光学工程学会会士，2013年当选为中国科学院信息技术科学部院士，2018年当选为发展中国家科学院院士。</p><p style=\"text-indent: 2em;\">历任北京大学物理学院副院长（2009年11月-2015年7月）、北京大学发展规划部副部长（挂职，2012年3月-2014年3月）、北京大学研究生院常务副院长（2015年7月-2017年10月）。2017年7月至2019年12月任北京大学党委常委、副校长，2018年10月至今兼任教务长，2019年8月至今兼任研究生院院长，2019年12月至2022年6月任北京大学党委常委、常务副校长。2022年6月任北京大学党委副书记、校长。</p><p style=\"text-indent: 2em;\">历任北京大学人工微结构和介观物理国家重点实验室主任（2001年4月-2017年3月）、学术委员会主任（2017年3月至今）。现任国际光学委员会（ICO）副主席、中国科协十届常务委员、北京市科协副主席、中国光学学会理事长、中国物理学会副理事长、中国学位与研究生教育学会副会长。</p><h2 style=\"text-align: left;\">学校简介</h2><p style=\"text-indent: 2em; text-align: left;\">北京大学创办于1898年，初名京师大学堂，是中国第一所国立综合性大学，也是当时中国最高教育行政机关。辛亥革命后，于1912年改为现名。</p><p style=\"text-indent: 2em; text-align: left;\">作为新文化运动的中心和“五四”运动的策源地，作为中国最早传播马克思主义和民主科学思想的发祥地，作为中国共产党最早的活动基地，北京大学为民族的振兴和解放、国家的建设和发展、社会的文明和进步做出了不可替代的贡献，在中国走向现代化的进程中起到了重要的先锋作用。爱国、进步、民主、科学的传统精神和勤奋、严谨、求实、创新的学风在这里生生不息、代代相传。</p><p style=\"text-indent: 2em; text-align: left;\">1917年，著名教育家蔡元培出任北京大学校长，他“循思想自由原则，取兼容并包主义”，对北京大学进行了卓有成效的改革，促进了思想解放和学术繁荣。陈独秀、李大钊、毛泽东以及鲁迅、胡适等一批杰出人才都曾在北京大学任职或任教。</p><p style=\"text-indent: 2em; text-align: left;\">1937年卢沟桥事变后，北京大学与清华大学、南开大学南迁长沙，共同组成长沙临时大学。不久，临时大学又迁到昆明，改称国立西南联合大学。抗日战争胜利后，北京大学于1946年10月在北平复学。</p><p style=\"text-indent: 2em; text-align: left;\">中华人民共和国成立后，全国高校于1952年进行院系调整，北京大学成为一所以文理基础教学和研究为主的综合性大学，为国家培养了大批人才。据不完全统计，北京大学的校友和教师有400多位两院院士，中国人文社科界有影响的人士相当多也出自北京大学。</p><p style=\"text-indent: 2em; text-align: left;\">改革开放以来，北京大学进入了一个前所未有的大发展、大建设的新时期，并成为国家“211工程”重点建设的两所大学之一。</p><p style=\"text-indent: 2em; text-align: left;\">1998年5月4日，北京大学百年校庆之际，国家主席江泽民在庆祝北京大学建校一百周年大会上发表讲话，发出了“为了实现现代化，我国要有若干所具有世界先进水平的一流大学”的号召。在国家的支持下，北京大学适时启动“创建世界一流大学计划”，从此，北京大学的历史翻开了新的一页。</p><p style=\"text-indent: 2em; text-align: left;\">2000年4月3日，北京大学与原北京医科大学合并，组建了新的北京大学。原北京医科大学的前身是国立北京医学专门学校，创建于1912年10月26日。20世纪三、四十年代，学校一度名为北平大学医学院，并于1946年7月并入北京大学。1952年在全国高校院系调整中，北京大学医学院脱离北京大学，独立为北京医学院。1985年更名为北京医科大学，1996年成为国家首批“211工程”重点支持的医科大学。两校合并进一步拓宽了北京大学的学科结构，为促进医学与人文社会科学及理科的结合，改革医学教育奠定了基础。</p><p style=\"text-indent: 2em; text-align: left;\">近年来，在“211工程”和“985工程”的支持下，北京大学进入了一个新的历史发展阶段，在学科建设、人才培养、师资队伍建设、教学科研等各方面都取得了显著成绩，为将北大建设成为世界一流大学奠定了坚实的基础。今天的北京大学已经成为国家培养高素质、创造性人才的摇篮、科学研究的前沿和知识创新的重要基地和国际交流的重要桥梁和窗口。</p><p style=\"text-indent: 2em; text-align: left;\">现任校党委书记邱水平、校长郝平。</p><h2 style=\"text-align: left;\">周边环境</h2><p><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px; font-family: 宋体;\">北京大学校园又称燕园，与圆明园、颐和园相毗邻，在明清两代曾是皇家的“赐园”</span><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px; font-family: Verdana;\">，学校往南是电子商业繁荣的中关村</span><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px; font-family: 宋体;\">。未名湖区湖光塔影，飞阁流丹，题词碑刻随处可见</span><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px; font-family: Verdana;\">，身处其中，流连徘徊，乐此不彼</span><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px; font-family: 宋体;\">；教学区端宁恢弘，林荫大道和爬满常春藤的建筑山墙让人难以忘怀。“槛外山光，窗中云影”，这里正是读书学习之佳处。</span></p><h2 style=\"text-align: left;\">通讯地址</h2><p><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px;\">北京市海淀区颐和园路5号</span></p>', 4.75);
INSERT INTO `university` VALUES (3, 'qinghua', '123', '清华大学', 'http://localhost:9090/files/download/1751937933687-清华.jpg', 'UNIVERSITY', '010-62770334', 'zsb@mail.tsinghua.edu.cn', '审核通过', 31, '清华大学招生办公室', '教育部', '“双一流”建设高校', 'https://www.tsinghua.edu.cn/', '本科', '<h2 style=\"text-align: left;\">学校领导</h2><p style=\"text-indent: 2em; text-align: left;\">校党委书记 &nbsp; 邱勇 &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;校长 &nbsp; 李路明</p><p style=\"text-indent: 2em; text-align: left;\">详见：https://www.tsinghua.edu.cn/xxgk/xrld.htm</p><h2 style=\"text-align: left;\">学校简介</h2><p style=\"text-indent: 2em; text-align: left;\"><strong>清华大学概览</strong></p><p style=\"text-indent: 2em; text-align: left;\">-----------------------------------------------------------------</p><p style=\"text-indent: 2em; text-align: left;\">清华大学是中国著名的高等学府，坐落于北京西北部风景秀丽的清华园。学校始建于1911 年。一个世纪以来，清华大学的发展始终与国家和民族的命运兴衰与共。“自强不息、厚德载物”的校训，“行胜于言”的校风，“严谨、勤奋、求实、创新”的学风，以“爱国奉献、追求卓越”为核心的清华精神，以及“中西融会、古今贯通、文理渗透”的办学特色，对学校的发展产生了深远的影响。<br> &nbsp; &nbsp;水木清华滋润了莘莘学子。清华大学建校100 年来，为社会培养毕业生近17万人。他们中的很多人成为学术大师、治国栋梁、兴业之士，以及各行各业的优秀人才，为民族振兴、国家富强，为科技发展、文化教育、经济建设与社会进步作出了重要贡献。<br> &nbsp; &nbsp;清芬挺秀，华夏增辉。今天的清华大学面临前所未有的历史机遇，学校将继承优良传统，发挥综合优势，加强基础建设，加快发展步伐，跻身于世界一流大学的行列，为实现中华民族的伟大复兴而努力奋斗！</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>雄厚的师资队伍</strong></p><p style=\"text-indent: 2em; text-align: left;\">-----------------------------------------------------------------</p><p style=\"text-indent: 2em; text-align: left;\">清清华大学培育和凝聚了一批又一批高水平的专家学者。近年来，学校遵循“引进与培养并举”的方针，加强青年教师队伍建设，在国内外选聘优秀人才，师资队伍水平稳步提高。<br> &nbsp; &nbsp;学校现有教师3036 人，其中45 岁以下青年教师1814 人。教师中具有正高级职务的1254 人，具有副高级职务的1257 人。教师中，诺贝尔奖获得者1名，图灵奖获得者1名，中国科学院院士37 名、中国工程院院士33 名。13 名教授荣获国家级“高等学校教学名师奖”。<br> &nbsp; &nbsp;学校通过设立“学术新人奖”、“青年教师教学优秀奖”以及实施“百名人才引进计划”、“骨干人才支持计划”等措施，优化队伍结构、提高队伍质量，青年教师队伍迅速成长。先后有146人获得“国家杰出青年科学基金”，101 人和51 人入选教育部“长江学者奖励计划”特聘教授和讲座教授，47人获得教育部“跨世纪人才基金”，18 人获得教育部“高校优秀青年教师奖”。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>多学科交叉的综合优势</strong></p><p style=\"text-indent: 2em; text-align: left;\">-----------------------------------------------------------------</p><p style=\"text-indent: 2em; text-align: left;\">经过多年的建设，清华大学已基本形成了综合性的学科布局。目前，清华大学共有本科专业66个，第二学位专业7个。截至2011年3月，清华大学共有博士学位授权点253个、硕士学位授权点271个，其中一级学科博士、硕士学位授权点45个，一级学科硕士学位授权点7个，二级学科博士、硕士学位授权点253个，二级学科硕士学位授予权点18个，分布在哲学、经济学、法学、教育学、文学、历史学、理学、工学、医学、管理学、艺术学等11个学科门类。<br> &nbsp; &nbsp;截至2011年3月，清华大学共有22个一级学科国家重点学科，15个二级学科国家重点学科，其中一级学科国家重点学科数居全国首位。在教育部学位中心组织的最近一轮一级学科评估中，清华大学共有38个学科参评，学科整体水平名列高校第一的学科共12个，位列全国高校之首。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>广泛的海外合作交流</strong></p><p style=\"text-indent: 2em; text-align: left;\">-----------------------------------------------------------------</p><p style=\"text-indent: 2em; text-align: left;\">清华大学积极开展多渠道、高层次、实质性的海外合作交流，与一批世界知名大学和机构建立了战略伙伴关系，在涉及全球性重大问题的科学研究、技术发展和决策咨询等方面发挥了越来越重要的作用；通过联合培养、交换生、国际会议等多种形式，不断拓展面向世界的人才培养和高水平的学术交流；积极参与大学国际组织和联盟，促进双边及多边合作；精心策划和推进重大海外文化和学术交流活动，全力提升学校的国际影响力和知名度。<br> &nbsp; &nbsp;学校着力促进高层次、规模化和规范化的项目发展。2010 年，学校师生共派出8010 人次。全年共选派各类学生约3300 人次，其中参加联合学位项目和联合培养180 余人次，攻读学位50 余人次，合作研究和进修270 余人次，交换生项目380人次，参加国际会议1060 余人次，海外实习项目约110 人次，暑期课程约770人次，各类竞赛110 余人次，其他短期交流项目约100人次。全年出访教职员工4700 余人次。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>科学的人才培养理念</strong></p><p style=\"text-indent: 2em; text-align: left;\">-----------------------------------------------------------------</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>本科招生</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学共有本科专业66个，第二学位专业7个，目前本科在校生13740余 人（不含留学生）。<br>2010 年，清华大学共招收普通本科新生3346人，其中工学2092 人，理学440 人，文学427人（其中艺术类226人），管理学93人，经济学136人，医学84人，法学74人。</p><p style=\"text-indent: 2em; text-align: left;\">2010年，来自全国26个省（市、自治区）的38位理科第一名和7个省（市、自治区）的8位文科第一名被我校录取；理科实考分前10名考生中的四分之三以及文科实考分前10名考生中的四分之一被我校录取；我校在绝大多数省份的文理科录取分数线均居全国高校首位。</p><p style=\"text-indent: 2em; text-align: left;\">2003年开展自主招生工作以来，清华大学一直在不断探索多元评价、科学合理的人才选拔体系。2010年，清华大学联合上海交通大学、中国科学技术大学、西安交通大学和南京大学，与专业考试机构合作，推出了五校联考的新的自主选拔模式。在这一选拔测试中，包括统一举行的“高水平大学自主选拔学业能力测试”（简称AAA测试），以及各大学单独举行的个性科目测试和面试。AAA测试的内容和命题要求由高校共同提出，具体的命题、考试实施、阅卷等则由专业化考试机构完成。考生的AAA测试成绩可以在五所高校内通用。这不仅提高了测试的专业水平，降低了考生成本，也提高了考试的公信力。2011年，浙江大学和中国人民大学加入联考。学生学习与发展指导学生的学习与发展是人才培养的重要内容。2009 年11 月清华大学成立学生学习与发展指导中心，为学生的学习与发展提供专业化的指导、咨询和支持服务，有针对性地解决学生学习与发展问题，拓展学生的学习能力，提高学生学习质量。中心贯彻“全过程匹配各类教育资源因材施教”理念，整合资源、努力创新机制，为学生个性发展提供订单式服务，推进学生学习与发展指导工作，服务学生成长成才。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>学生经济资助体系</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学历来高度重视学生经济资助工作。在社会各界的关心和支持下，学校多方筹集资金，逐步建立和完善了“助、勤、奖、贷、补”多种渠道相互补充的经济资助体系，实现了清华大学“决不让任何一个勤奋而有才华的学生因家庭经济困难而失学”的郑重承诺。<br>从2006 年开始，清华大学全面实施新经济资助体系。广大校友发起设立“清华校友励学金”捐资助学工程，专门用于资助家庭经济困难的学生。2010 年，清华校友捐资设立153 项校友励学金，资助学生约900人次。截至目前，政府、社会各界和学校共设立奖助学金300 余项，奖励资助学生超过9000 人次。<br>学校提供大量校内勤工助学岗位，2010 年，全校共有超过3000 人次参加校设勤工助学岗位劳动。自1998 年清华大学在全国高校率先开辟“绿色通道”以来，学校每年在新生入学报到现场为学费不足的学生办理临时贷款。2010 年，“绿色通道”为近400 名本科生办理临时贷款，帮助了学生顺利入学。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>毕业与就业</strong></p><p style=\"text-indent: 2em; text-align: left;\">学校设有集教育、指导、服务、管理于一体的就业指导中心，以帮助学生了解就业市场、明晰就业政策，获取招聘信息、拥有更多选择，掌握择业技巧、规划职业生涯，树立正确的人生观、价值观和择业观，积极到国家重要行业和领域建功立业。目前，清华大学就业指导中心建立了以“大礼堂计划”为统领的较为完善的毕业生就业服务体系，从政策支撑、招聘服务到就业创业指导、就业研究、队伍保障，全程化、全员化的就业工作模式能够更为有效地服务于国家发展的战略需要和毕业生职业生涯的科学发展。<br>清华毕业生的优良素质得到社会的广泛认可。毕业生的供需比和就业率一直保持较高水平。在充分选择的前提下，有近八成的毕业生选择到国家重要行业和领域就业。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>丰富多彩的校园生活</strong></p><p style=\"text-indent: 2em; text-align: left;\">-----------------------------------------------------------------</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>素质拓展计划</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学自1997 年开始酝酿大学生素质拓展计划，1998 年在全国高校中率先实施。该计划着眼于提高学生的全面素质，建立了一套规范、科学、有效的第二课堂学生素质拓展项目平台和学生素质拓展认证平台，对有益于学生全面素质提高的项目给予资金支持和方法指导，对学生参与素质拓展项目情况给予记录和认证。自素质拓展计划实施以来，5200 多个学生素质拓展项目得以实施，“给你天空，助你飞翔”的理念深入人心，学生素质拓展计划已经成为推动学生全面发展的重要渠道。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>课外学术科技与创新创业活动</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学广泛开展学生课外学术科技与创新创业活动，培养学生的创新精神和创新能力，设立种子基金、大学生研究训练计划（SRT）“挑战杯”专项、累进支持基金等支持项目，建设学生课外学术科技活动基地，搭建星火论坛等创新交流平台，整合创业教育资源成立学生创业导师团，形成了以“挑战杯”为龙头，机械创新设计大赛、电子设计大赛、数学建模竞赛、结构设计大赛、智能体大赛，人文知识竞赛等40多项专业赛事为主体的赛事体系，为学生提供锻炼、成长和展示的舞台。此外，博士生论坛、研究生学术新秀评比、研究生咖啡厅学术沙龙等研究生课外学术活动也异彩纷呈。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>社会实践</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学学生社会实践以“受教育、长才干、作贡献”为指导思想，涵盖国情考察、支教扶贫、社会调研、专业实习、科技服务、校友访谈、挂职锻炼等多种形式，涌现出了以博士生实践服务团、中美大学生教育扶贫、“两岸同心”大学生志愿者西部行、大学生志愿者千乡万村环保科普等为代表的一批品牌项目，呈现出组织规模化、项目品牌化、基地规范化、机制长效化、合作多样化的良好发展态势。<br>在社会实践中“知国情、悟责任、立志向”已经成为清华重要的一项传统，选择在社会实践中度过一个充实而有意义的假期，也已经成为清华学生的一种习惯。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>社会工作岗位锻炼</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学始终提倡学生参加社会工作岗位锻炼，培养和锻炼学生的奉献服务、追求卓越、求真务实的精神以及团队合作、组织协调、沟通表达的能力。目前本科毕业生中，约有90% 以上的学生在大学期间至少参加过一年的社会工作，社会工作岗位锻炼的实施效果进一步提高。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>社团协会</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华的学生社团具有悠久的历史和深厚的文化底蕴。早在上世纪二三十年代，清华的社团累计已达几十个，如清华周刊社、美术社、戏剧社、文学社等等，其创始人中不乏闻一多、梁实秋、顾毓琇等清华名人。上世纪九十年代后，清华的学生社团依托学校良好的教育环境，出现了大规模的繁荣景象，一大批与时俱进，顺应学生需求的新协会应运而生。截至2010年12月，全校共有注册的学生社团127家，涵盖人文社科、科技、公益、文艺、体育五大类别，注册会员总数超过两万人次。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>志愿活动</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学紫荆志愿者服务总队以“自我实践、服务他人、自我教育、推动社会”为宗旨，坚持立足校园、辐射社区、面向社会的原则，深入开展具有清华特色的丰富多彩的大学生志愿公益活动。截至2010 年底，全校注册紫荆志愿者人数达18340余人，总服务认证时间达361470多小时。在志愿服务的注册认证规范合理的基础上，设立全校性的志愿服务分级嘉许制度，激励志愿者的服务热情，促进全校浓厚和谐的志愿公益氛围的形成。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>文艺活动</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学学生艺术团成立于1958 年，目前拥有军乐队、民乐队、合唱队、交响乐队、舞蹈队、话剧队、国际标准舞队、键盘队、美术社、京剧队、曲艺队11 支队伍约1000 名团员。学生艺术团以“弘扬民族文化，倡导高雅艺术”为宗旨，本着“从同学中来，到同学中去”的原则，以“反映时代精神，表现校园生活”为己任，丰富和推动了校园文化建设，是学校开展艺术教育、培养优秀人才的第二课堂。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>体育活动</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学体育代表队成立于1954 年，目前拥有29 个项目35支代表队，在册队员500 余名，是全国高校中规模最大最完整的学校体育代表队之一。体育代表队以“全面发展、育人至上、体魄与人格并重”为理念，倡导“体教结合”的教育方针，努力培养德智体全面发展的学生运动员。目前学校自己培养的国家运动健将近80 人。以“马约翰杯”为主线的系列体育赛事贯穿全年，覆盖全体学生，在推动群众性体育活动方面发挥了重要作用。“为祖国健康工作五十年”已经成为影响数代清华人的口号。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>优美的环境、完善的设施</strong></p><p style=\"text-indent: 2em; text-align: left;\">-----------------------------------------------------------------</p><p style=\"text-indent: 2em; text-align: left;\">校园内绿草茵茵、树木成荫，各个不同时期的建筑形成各具风格的建筑群落。截至2010 年底，校园内共有乔木4.5 万株，灌木20万株，竹子8.7 万棵，宿根花卉4.4 万株，色块27.4 万株，树龄在百年以上的古树240 棵。校园内的树木种类达1210 种，全校绿化面积135 万多平方米，绿化覆盖率54.8% 。<br>校园内教学设施完备，生活条件便利。新建的紫荆学生公寓占地约28.6 公顷，总建筑面积约37 万平方米，区域内超市、银行、邮局等配套服务设施齐全，能够满足广大学生的日常学习、生活需要；校园内19 个食堂餐厅为5万余名师生员工提供优质的饮食服务，其中建筑面积为1.3 万平方米的“紫荆园”是国内高校较大的学生餐厅，可容纳3000 余人同时就餐。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>图书馆</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学图书馆系统由校图书馆及人文、经管、法律、建筑、美术和医学等专业图书馆组成，建筑总面积6.16万平方米（含分馆），阅览座位3500余席。馆藏总量约有400.8万册（件），形成了包括理、工、文、法、管理、艺术、医学等学科的多种类型、多种载体的综合性馆藏体系，其中馆藏珍品还包括一批中外文古籍善本、甲骨、青铜器和名人字画。<br>近年来，图书馆的电子化建设取得了重要进展。逐步建立起比较先进、完备的信息基础设施；配置了比较丰富的电子化学术信息资源，文摘索引类二次文献已基本覆盖学校现有学科，学术性全文电子期刊5.7万种，电子图书约有238.5万册，安装在本地服务器中的资源数据总量超过70TB；采用了先进新型的服务方式，密切与教师学生的联系，针对学校教学科研工作的需求开展服务工作；初步形成了一个以信息服务为核心的全方位、多层次、开放式、高效率的文献信息服务体系，成为建设一流大学的重要支撑。清华大学正加速建设一个资源高度共享的、智能化的多媒体教学信息网络，改善教学科研环境，拓展电子化图书馆的服务功能，为人才培养和科学研究提供有力支持。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>学生文化活动中心</strong></p><p style=\"text-indent: 2em; text-align: left;\">建筑面积4000 多平方米，设有音乐、美术及舞蹈教室，展览厅、报告厅、表演厅，以及40 多间琴房，各种文艺社团都在此活动。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>综合体育中心</strong></p><p style=\"text-indent: 2em; text-align: left;\">建筑面积约12600 平方米，可容纳约5000 观众，用于体育比赛、大型演出、集会和体育课，并为学校体育代表队的训练和学生日常锻炼提供场所。2008 年，综合体育中心承担了北京2008 年第二十九届奥林匹克运动会篮球训练和北京2008 世界残疾人奥运会轮椅篮球训练任务。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>游泳馆</strong></p><p style=\"text-indent: 2em; text-align: left;\">建筑面积约9700 平方米，具备国际标准长度泳道和标准高度的跳台、跳板及陆上训练场地，是一所符合国际标准的比赛场馆。综合体育中心和游泳馆一起承办了第21 届世界大学生运动会中的跳水、篮球等重大项目比赛。2008 年，游泳馆承担了北京2008 年第二十九届奥林匹克运动会水球和跳水训练任务。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>新射击馆</strong></p><p style=\"text-indent: 2em; text-align: left;\">2009 年11 月，清华大学新射击馆“维学馆”落成启用。新射击馆坐落在东大操场东侧，与东体育馆共同组成东操场的东、西看台。新射击馆建筑面积10700 多平方米，建有10 米靶56 个，25 米靶两组，50 米靶10 个。新射击馆作为清华射击队的主训练场馆，同时承担学生射击课程任务，具备承担国际级赛事的能力。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>强有力的可持续发展保障体系</strong></p><p style=\"text-indent: 2em; text-align: left;\">-----------------------------------------------------------------</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>教育基金会</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华大学教育基金会是经中华人民共和国民政部批准成立的全国性非公募基金会，2008 年3月被中华人民共和国民政部评为“4A 级社会组织”，这是国家对非公募基金会给予的最高级别认证。基金会的基金主要用于：支持清华大学教育事业的发展，用于改善教学设施，包括建筑物、仪器设备、图书资料；奖励优秀学生，奖励优秀教师；资助基础研究、教学研究和著作出版；资助教师出国深造及参加国际学术合作和国际学术会议。对特定项目捐赠，可以按捐赠者的愿望和意见定向使用。</p><p style=\"text-indent: 2em; text-align: left;\"><br></p><p style=\"text-indent: 2em; text-align: left;\"><strong>校友总会</strong></p><p style=\"text-indent: 2em; text-align: left;\">清华校友总会的前身是1913 年成立的“清华学校留美同学会”和1933 年成立的“清华同学会总会”。清华校友总会成立于1981 年4月，现任会长是顾秉林校长。其宗旨是加强国内外校友之间、校友与母校之间的联系和团结，服务广大校友，发扬清华的优良传统，为中华民族的富强和祖国的统一，为母校的发展作出贡献。今天的清华校友组织已经遍及海内外。据不完全统计，全国内地31个省市以及香港特别行政区、澳门特别行政区、台湾地区建立了150多个校友会组织，在海外12个国家建立了50多个校友组织。2006 年开始，由清华校友总会面向广大校友发起的、旨在帮助家庭经济困难学生顺利完成学业的“清华校友励学金工程”正式启动并取得重大进展，校友励学金已经成为学校新的资助体系重要支撑。<br>截止到2010年底，共筹集励学金6297万元，其中励学基金3678万元，总共发放2308万元，共资助5018人次，占全校本科生资助额度的三分之一以上。励学金工程激发了校友回馈母校的热情，成为校友支持学校人才培养的直接渠道。受助同学对新资助体系的满意度超过98%，产生了良好的社会影响。</p><p style=\"text-indent: 2em; text-align: left;\">“人才培养”是学校的根本任务。校友总会提出，校友工作要融入学校人才培养工作主流。经过不断努力，已经形成“校友育人”的良好局面，校友资源已经成为学校人才培养的文化传承资源、就业引导资源、助困励学资源和教育研究资源。</p><h2 style=\"text-align: left;\">周边环境</h2><p><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px;\"> &nbsp;清华大学校园，地处北京西北郊繁盛的园林区，是在几处清代皇家园林的遗址上发展而成的。清华校园周围高等学府（如北京大学、北京语言文化大学、北京科技大学、北京航空航天大学）和名园古迹（如圆明园、颐和园）林立，园内林木俊秀，水木清华；清澈的万泉河水从腹地婉蜓流过，勾连成一处处湖泊和小溪，滋润着一代代清华学子高洁的志趣和情操。</span></p><h2 style=\"text-align: left;\">通讯地址</h2><p><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px;\">清华大学招生办公室 通讯地址：北京市海淀区清华大学招生办公室 邮政编码:100084 咨询电话:010－62770334，62782051 图文传真:010－62782061 电子邮箱:zsb@mail.tsinghua.edu.cn 清华大学本科招生网:http://www.join-tsinghua.edu.cn</span></p>', 4.50);
INSERT INTO `university` VALUES (4, 'zgrm', '123', '中国人民大学', 'http://localhost:9090/files/download/1751938070671-中国人民大学.jpg', 'UNIVERSITY', '400-0123-517', 'zgrm@qq.com', '审核通过', 31, '北京市海淀区中关村大街59号', '教育部', '“双一流”建设高校', 'https://www.ruc.edu.cn/', '本科', '<h2 style=\"text-align: left;\">学校领导</h2><p style=\"text-indent: 2em; text-align: left;\">党委书记：张东刚</p><p style=\"text-indent: 2em; text-align: left;\">校长：林尚立</p><h2 style=\"text-align: left;\">学校简介</h2><p style=\"text-indent: 2em; text-align: left;\">中国人民大学（Renmin University of China）是中国共产党创办的第一所新型正规大学，直属于教育部，由教育部与北京市共建。现任党委书记为张东刚、校长为林尚立。</p><p style=\"text-indent: 2em; text-align: left;\"><strong>历史沿革和领导关怀</strong></p><p style=\"text-indent: 2em; text-align: left;\">中国人民大学前身是1937年诞生于抗日战争烽火中的陕北公学，以及后来的华北联合大学和北方大学、华北大学。学校始终与党和国家同呼吸、共命运，始终得到党中央的亲切关怀和高度重视。</p><p style=\"text-indent: 2em; text-align: left;\">陕北公学时期，毛泽东同志非常关心学校办学工作，先后十次来校发表演讲，他曾说：“中国不会亡，因为有陕公。” 根据中共中央政治局的建议，1949年12月16日，中央人民政府政务院第十一次政务会议决定成立中国人民大学。1950年10月3日，刘少奇同志出席学校开学典礼并发表讲话，指出中国人民大学“是我们新中国办的第一所新式大学，是中国历史上前所未有过的大学，中国将来的许多大学都要学习我们中国人民大学的经验，按照中国人民大学的样子来办”。这是“新中国的完全新式的高等教育的起点”。学校迅速发展成为一所具有重大影响力的以培养马列主义理论人才和财经、政法干部为主的综合性大学。改革开放后，邓小平同志指出，学校“主要培养财贸、经济管理干部和马列主义理论工作者”。江泽民同志于2002年来校考察指导工作，强调发展繁荣哲学社会科学，鼓励学校“成为以人文社会科学为主的世界知名的一流大学”。胡锦涛同志于2008年、2010年视察学校，勉励学校弘扬光荣传统，“办出特色、办出水平 ”，努力创建“人民满意、世界一流”大学。</p><p style=\"text-indent: 2em; text-align: left;\">习近平同志曾于2005年、2006年、2009年、2012年、2022年先后五次到学校出席活动、视察工作。进入新时代，2017年，习近平总书记致信祝贺学校建校80周年，充分肯定学校的办学成绩，明确指出中国人民大学在“我国人文社会科学领域独树一帜”，并殷切希望学校“围绕解决好为谁培养人、培养什么样的人、怎样培养人这个根本问题，坚持立德树人，遵循教育规律，弘扬优良传统，扎根中国大地办大学，努力建设世界一流大学和一流学科”。2022年4月25日，习近平总书记专程到学校考察调研并发表重要讲话，他指出，中国人民大学在抗日烽火中诞生，在党的关怀下发展壮大，具有光荣的革命传统和鲜明的红色基因，始终不变的是“为党育人、为国育才”，展现了“党办的大学让党放心、人民的大学不负人民”的精神品格，他勉励学校坚持党的领导，坚持马克思主义指导地位，坚持为党和人民事业服务，落实立德树人根本任务，传承红色基因，扎根中国大地办大学，走出一条建设中国特色、世界一流大学的新路。</p><p style=\"text-indent: 2em; text-align: left;\"><strong>办学特色和优势</strong></p><p style=\"text-indent: 2em; text-align: left;\">建校以来，中国人民大学始终坚持党的领导，传承红色基因，扎根中国大地，形成了“人民共和国建设者”的摇篮、人文社会科学高等教育的重镇、马克思主义教学与研究的高地三大办学特色，为我国哲学社会科学的发展和繁荣，为中国特色社会主义现代化建设事业作出了重要贡献，成为中国共产党探索创办新型高等教育，扎根中国大地办大学的典范和缩影，被誉为我国人文社会科学高等教育领域的一面旗帜。从1950年至今，国家历次确立重点大学，中国人民大学均位居其中。学校是国家“985工程”“211工程”重点建设大学，2017年首批入选国家“世界一流大学和一流学科”建设名单。</p><p style=\"text-indent: 2em; text-align: left;\">中国人民大学以“独树一帜的人文社会科学”为学科整体建设目标，致力于构建“引领的马克思主义理论学科，卓越的基础学科、顶尖的社科学科、创新的交叉学科”学科布局。目前学校拥有8个国家重点一级学科，8个国家重点二级学科，在人文社会科学领域均居全国第一。学校设有学士学位专业86个，一级学科硕士学位授权点34个、一级学科博士学位授权点25个，专业学位类别硕士学位授权点32个、专业学位类别博士学位授权点1个;有博士后科研流动站21个。在教育部2017年公布的全国第四轮学科评估结果中，中国人民大学获评A类学科的总数共14个，其中理论经济学、应用经济学、法学、社会学、新闻传播学、统计学、工商管理、公共管理、马克思主义理论获评A+，政治学、哲学获评A，图书情报与档案管理、中国史、中国语言文学获评A-，A+学科数量位列全国高校第四；在教育部首轮“双一流”建设评价中，学校14个一流学科表现优异，继续入选第二轮“双一流”建设学科名单。理工学科按照“卓越的基础学科”定位不断优化布局并迅速发展，有力推动了学校创新交叉学科发展。</p><p style=\"text-indent: 2em; text-align: left;\">中国人民大学历来人才荟萃、名家云集。全国高等教育领域仅有的两位“人民教育家”国家荣誉称号获得者卫兴华教授和高铭暄教授均出自中国人民大学。学校有22人担任国务院学位委员会第八届学科评议组成员，47人入选新一届教育部高等学校教学指导委员会委员，共有132人入选国家重大人才工程、508人享受国务院政府特殊津贴、136人入选国家重大青年人才工程。截至2024年1月，学校有专任教师1956人，其中教授801人，副教授751人。</p><p style=\"text-indent: 2em; text-align: left;\"><strong>社会贡献和影响</strong></p><p style=\"text-indent: 2em; text-align: left;\">从陕北公学时期至今，学校共培养了38万余名高水平建设者和各行各业优秀人才。新中国法学、新闻学等学科的第一位博士，人文社会科学第一位外国留学生博士，第一批政治经济学、世界经济、货币银行学、统计学等专业的博士皆出自中国人民大学。对中国改革开放具有里程碑意义的两篇文章——《实践是检验真理的唯一标准》和《东方风来满眼春》均出自人大人之手。进入新时代，学校以“复兴栋梁、强国先锋”为人才培养目标，教育引导学生坚定中国特色社会主义道路自信、理论自信、制度自信、文化自信，在全面建设社会主义现代化国家新征程中勇当开路先锋、争当事业闯将。截至2024年1月，学校有在学学生28224人，其中本科生11749人、硕士生11400人、博士生5075人。</p><p style=\"text-indent: 2em; text-align: left;\">长期以来，中国人民大学为我国哲学社会科学繁荣发展作出了奠基性、引领性贡献，新中国的经济学、法学、新闻学、马克思主义理论等诸多学科由中国人民大学首先创立并走向全国。进入新时代，学校坚持把马克思主义基本原理同中国具体实际相结合、同中华优秀传统文化相结合，不断推进知识创新、理论创新、方法创新，积极传播中国声音、中国理论、中国思想，加快构建以中国自主的知识体系为内核的中国特色哲学社会科学学科体系、学术体系、话语体系。学校主持构建了“中国—中东欧国家高校联合会经济学学科建设共同体”、世界人文社会科学高校联盟、国际文化交流学术联盟等平台，开设了全球首个“管理学三学士国际项目”。截至2024年1月，学校同61个国家和地区的312所高校和国际组织建立了伙伴关系，参与了7所海外孔子学院建设。</p><p style=\"text-indent: 2em; text-align: left;\">中国人民大学坚持立足中国实际，解决中国问题，以回答中国之问、世界之问、人民之问、时代之问为学术己任，致力于研究重大政治、经济、文化和社会问题，为国家经济建设和社会发展提供强大的理论保证和有力的智力支持，成为国家重要智库。学校相关学科专家学者参与了新中国宪法、民法典、刑法等所有重要法律，以及历次财税体制改革等国家重要方案的起草和修改工作。经中央批准，学校设立了全国首家习近平新时代中国特色社会主义思想研究院和全国首家党史党建研究院；国家发展与战略研究院成为首批试点建设的国家高端智库，2019年在首次国家高端智库综合评估中成为唯一一家进入第一档次的高校智库；重阳金融研究院和首都发展与战略研究院也是具有重要影响的中国特色新型智库。</p><p style=\"text-indent: 2em; text-align: left;\">当前，中国人民大学全体师生员工正高举中国特色社会主义伟大旗帜，以习近平新时代中国特色社会主义思想为指导，全面学习贯彻党的二十大精神，深入学习贯彻习近平总书记在中国人民大学考察调研时重要讲话精神和习近平总书记致中国人民大学建校80周年贺信精神，落实学校第十五次党代会部署，不忘“为党育人、为国育才”光荣使命，坚守“听党话、跟党走”精神信念，弘扬“党办的大学让党放心、人民的大学不负人民”精神品格，紧扣“六面旗帜”，围绕“八项工作”，全面实施“新路建设十大工程”，举旗帜、当旗手、做先锋，坚定不移走好建设中国特色、世界一流大学新路，加快建设“让党放心、人民满意、世界一流”的中国人民大学，为全面建设社会主义现代化国家、全面推进中华民族伟大复兴作出新的更大贡献！</p><h2 style=\"text-align: left;\">周边环境</h2><p style=\"text-indent: 2em; text-align: left;\">首都北京平台大、梦幻海淀联动多。北京是国家的首都，是国家政治、经济、文化中心、双奥之城。中国人民大学位于北京市海淀区中关村大街 59 号，居于海淀区重点高校圈核心地带，交通便利，资讯发达。作为全国政治、经济、文化、金融中心，北京拥有着独一无二的人文社科研习氛围，而地处北三环、背靠中关村的地理位置优势使人大学生得以充分享用北京丰富的资源。</p><p style=\"text-indent: 2em; text-align: left;\">3 公里高校圈，半小时生活圈。周边高校云集，北大、清华、北航、北师、北邮、民大、北外等重点高校环绕，共享无尽学术资源；公共交通线路交汇，国家图书馆、各大博物馆、美术馆、体育馆、剧院、电影院等均在半小时车程内，文体资源丰富；国家部委、大型事业单位、金融机构、新闻媒体、世界 500 强企业等集聚，实习就业选择众多。</p><h2 style=\"text-align: left;\">通讯地址</h2><p><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px;\">北京市海淀区中关村大街59号</span></p>', 3.00);
INSERT INTO `university` VALUES (5, 'bjjt', '123', '北京交通大学', 'http://localhost:9090/files/download/1751938118096-北京交通大学.jpg', 'UNIVERSITY', '010-51688441', 'bjjt@qq.com', '审核通过', 31, '北京交通大学本部校区：北京市海淀区上园村3号，邮编100044 北京交通大学威海校区：山东省威海市文登', '教育部', '“双一流”建设高校', 'https://www.bjtu.edu.cn/', '本科', '<h2 style=\"text-align: left;\">学校领导</h2><p style=\"text-indent: 2em;\"><strong>陈子季 &nbsp;党委书记</strong> &nbsp; </p><p style=\"text-indent: 2em;\"><strong>余祖俊 &nbsp; 校长、党委副书记</strong> &nbsp; &nbsp;</p><p style=\"text-indent: 2em;\"><strong>详情请点击网址查看：https://www.bjtu.edu.cn/xxgk/xxjj/index.htm</strong></p><p style=\"text-indent: 2em;\"> <br></p><p style=\"text-indent: 2em;\"> </p><p style=\"text-indent: 2em;\"> </p><h2 style=\"text-align: left;\">学校简介</h2><p style=\"text-indent: 2em;\">教育部直属全国重点大学</p><p style=\"text-indent: 2em;\">教育部、交通运输部、北京市人民政府和中国国家铁路集团有限公司共建</p><p style=\"text-indent: 2em;\">国家“211工程”</p><p style=\"text-indent: 2em;\">“985工程优势学科创新平台”</p><p style=\"text-indent: 2em;\">“双一流”建设高校</p><p style=\"text-indent: 2em;\"><strong> &nbsp;详情请点击网址查看：北京交通大学</strong></p><p style=\"text-indent: 2em;\"> </p><h2 style=\"text-align: left;\">周边环境</h2><p style=\"text-indent: 28px;\"><span style=\"font-size: 14px; font-family: 宋体;\">学校在被称为“学府胜地”的北京市海淀区建有东西两个校区，总面积近1000亩，建筑面积100余万平方米；在山东省威海市建有威海校区，以中外合作办学为特色，占地面积1000余亩；各校区均具备完善的教学、科研设施，校园环境优美。在河北省黄骅市建有北京交通大学海滨轨道交通综合研发实验基地；在北京市丰台区打造国际一流的轨道交通“产学研用”一体化创新基地；在河北省唐山市成立唐山研究院，着力打造技术研发、成果转化的示范区；建有深圳研究院、长三角研究院以及威海研究院，为拓宽社会资源，推动学校人才培养与科学研究做出积极贡献。目前，雄安校区已开启大规模建设，学校一校多区协同发展进入崭新阶段。</span></p><p style=\"text-indent: 28px;\"><span style=\"font-size: 14px; font-family: 宋体;\">北京交通大学本部地处北京市海淀区西直门，恰在北京二环边上，是距离天安门最近的重点大学之一，学校临近国家图书馆、中关村、北京展览馆、北京动物园、西直门地铁站、各大型超市等，地理位置优越且交通便利。更是与中央财经大学、北京师范大学、北京电影学院等多所院校相邻，各路人才云集于此，学习交流零距离。</span></p><p style=\"text-indent: 2em;\"><br></p><h4 style=\"text-align: left;\">通讯地址</h4><p>北京交通大学本部校区：北京市海淀区上园村3号，邮编100044 北京交通大学威海校区：山东省威海市文登区南海新区现代路69号，邮编264400</p>', 4.00);
INSERT INTO `university` VALUES (6, 'bjgy', '123', '北京工业大学', 'http://localhost:9090/files/download/1751939577295-北京工业.jpg', 'UNIVERSITY', '01067391609', 'bjgy@qq.com', '审核通过', 31, '平乐园校区：北京市朝阳区平乐园100号； 通州校区：北京市通州区潞苑南大街1145号。', '地方', '“双一流”建设高校', 'https://www.bjut.edu.cn/', '本科', '<h2 style=\"text-align: left;\">学校领导</h2><p style=\"text-align: justify;\">柏彦故地，巍巍学府。春秋代序，峥嵘航路。1950年，朝鲜战争爆发。抗美援朝战场上，敌我空军力量悬殊。战争的迫切需求推动了新中国航空工业从修理向制造过渡，国家“急需办一所航空大学”。1951年，国家决定将北洋大学、厦门大学、西北工学院航空系并入清华大学航空工程学系，成立清华大学航空工程学院；将云南大学航空工程系并入四川大学航空系；将西南工业专科学校航空专修科并入华北大学工学院航空工程系。1952年，根据全国高等学校院系调整的要求，设立北京航空学院，由北京工业学院航空系（1951年11月18日，华北大学工学院更名为北京工业学院）、清华大学航空工程学院、四川大学航空系合并成立。1952年10月25日，北京航空学院成立大会在北京工业学院礼堂（原中法大学旧址）举行。1988年，北京航空学院更名为北京航空航天大学（简称北航）。</p><p style=\"text-align: justify;\">作为新中国第一所航空航天高等学府，北航萌发于民族觉醒之时，诞生于国家奋发之际，成长于民族复兴之中。从航空救国到航空报国、航天报国，再到服务航空强国、航天强国建设，学校始终传承红色基因，把服务国家作为最高追求，矢志不渝培养一流人才，打造国之重器，始终奋进在中国高等教育第一方阵前列。100位两院院士和25万余名优秀建设者从这里走出，践行“德才兼备，知行合一”的校训，弘扬“艰苦朴素、勤奋好学、全面发展、勇于创新”的校风，研制发射（试飞）成功的多种型号飞行器填补了国内多项空白，谱写出了一篇篇培育栋梁、为国铸剑、追求卓越的绚丽华章。</p><p style=\"text-align: justify;\">北航现隶属于工业和信息化部，在北京市拥有学院路校区、沙河校区，2023年建成启用北航杭州国际校园。学院路校区、沙河校区、杭州国际校园总占地约4000亩。建校以来，北航一直是国家重点建设的高校，是全国第一批16所重点高校之一，也是80年代恢复学位制度后全国第一批设立研究生院的22所高校之一，1995年进入“211工程”，2001年进入“985工程”，2017年入选国家“双一流”建设高校名单。学校第十六次党员代表大会提出了建设扎根中国大地的世界一流大学的远景目标。</p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校学科繁荣，特色鲜明。现有80个本科专业。动态优化调整后，拥有36个一级学科（其中34个博士学位授权一级学科点，36个硕士学位授权一级学科点），26个博士后科研流动站，涵盖工、理、管、文、法、经、哲、教育、医、交叉10个学科门类。学校紧紧围绕国家战略需求和国际学术前沿，突出特色、质量和贡献，明确“顶尖工科、一流理科、精品文科、优势医工”学科建设方针，持续优化学科布局、凝练学科方向，促进学科交叉融合，完善学科带头人体系，推动学科、平台、团队一体化统筹推进，以科教协同平台推动教育科技人才工作深度融合。航空航天、信息、理科、文科、医工交叉五大学科群建设成效显著，8个学科入选“双一流”建设学科，在航空宇航科学与技术、仪器科学与技术、材料科学与工程、软件工程、控制科学与工程、计算机科学与技术、力学、交通运输工程、管理科学与工程、生物医学工程等学科领域具有引领优势，高峰学科占博士点比例超30%，形成了空天信优势突出、理工文医深度交叉、新方向持续引领的学科发展新格局，国防科技主干学科稳居国内一流水平。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校名师荟萃，人杰地灵。坚持人才是第一资源，深入实施人才强校战略，发布“蓝天新时代人才行动计划”，系统谋划人才队伍发展蓝图。成立国际前沿交叉科学研究院，面向世界学术前沿建设一批国际科技创新中心，突出“共建共有共享”的建设思路，大力引进海外优秀人才。深化分类卓越的人才人事制度改革，推动分系列发展评价贯穿教师成长发展全过程、全周期，师资队伍建设再上新台阶。学校教职工总数6141人，其中专任教师3108人。专任教师中，79%具有高级职称，88%具有博士学位。入选各类国家重大人才工程679人次，其中在校工作两院院士37人，领军人才284人次、青年人才358人次，国家级创新团队45个。人才队伍中涌现出众多国家一等奖获得者、领域专家和型号总师，以及一大批年轻有为、造诣精深的专家学者。完善“思想引领、榜样示范、底线约束”三位一体的教师思政工作体系，加强师德师风建设，设立“立德树人奖”作为最高荣誉，连续6年评选表彰74位师德楷模。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校精育良才，立德树人。现有在校生37656人，其中本科生16294人、研究生20240人、留学生1122人。学校坚持为党育人、为国育才，全面实施新时代人才培养领航行动计划，提出了“厚植情怀、强化基础、突出实践、科教融通”的人才培养方针，打造“强情怀、强基础、强实践、强融通”的人才培养“四强”模式，持续推动科研优势转化为人才培养优势，构建高质量人才培养体系，全面提高人才自主培养质量。积极构建思政课程、课程思政与学生工作相互浸润、三位一体的思政育人体系，完善“大思政”育人格局。教学工作体系不断完善，拥有国家级一流本科专业建设点49个，省部级一流本科专业建设点11个，国家级实验教学示范中心5个，国家级虚拟仿真实验中心3个，教育部虚拟教研室建设试点12个。建立全国示范性工程专业学位研究生联合培养基地3个、工信部校企协同育人示范基地6个。名师、名课、名教材和教学成果建设成效显著，现有国家级教学名师9名、教学团队5个，“全国高校黄大年式教师团队”3个，国家级一流本科课程74门，全国专业学位研究生在线示范课4门，获国家级教材建设优秀教材奖3项，12项成果获2022年高等教育国家级教学成果奖，其中一等奖4项。学校致力于拔尖创新人才自主培养，强化“大类招生”“大类培养”“书院制”改革，开设10个本博贯通试验班，8个专业入选“强基计划”，5个专业入选“拔尖计划2.0”。首批入选国家试点学院、国家卓越工程师学院、未来技术学院、国家集成电路学院、特色化示范性软件学院、“一流网络安全学院建设示范项目高校”创新创业学院等国家级人才培养示范项目。与北京协和医学院共建“协和医班”，探索复合型拔尖创新人才培养新模式。建设杭州国际校园，培养国际化高精尖创新人才。打造“基础教学、校内竞赛、国内平台、国际舞台”四位一体的学生科创体系，连续34年举办北航“冯如杯”竞赛，吸引了9万余名学生开展创新研究，点亮学生科学思维，提升科学探索能力。本科生“冯如三号”无人机团队两创世界纪录，学生大型综合项目“北航4号”临近空间火箭动力飞行器、亚太空间合作组织大学生小卫星项目主星“北航亚太一号”先后成功发射。在全国“挑战杯”竞赛中唯一连续18届捧得“优胜杯”，3次获最高荣誉“挑战杯”。近年来，学校生源质量稳步提升，大部分省份招生生源高考成绩平均排名在前5‰，部分省份已进入全省排名前1‰，理工类生源整体质量稳居全国前9名。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校服务国家，锐意创新。自觉履行高水平科技自立自强的使命担当，突出“四个面向”，坚持“四大”模式，强化有组织科研，着力强化纵向创新链、横向交叉链，引导和支持创新要素向关键瓶颈技术汇聚，产学研用深度融合，打造一流创新平台和一流科研团队，全面提升科技创新能力。作为副主任单位承建2个国家实验室，参与8个国家实验室建设。获批建设1个国家重大科技基础设施。牵头建设7个全国重点实验室，共建7个全国重点实验室。另有10个国家级科技创新基地、4个北京市高精尖创新中心、111个省部级重点实验室。强化关键技术攻关，牵头承担“机载”“高分”等百余项重大任务，在无人机、增材制造、发动机叶片涂层、紧缩场、电磁兼容等关键核心技术领域啃下“硬骨头”，学校团队参与论证并助力研制的国产大飞机C919成功首飞。“十五”以来，共获国家三大科技奖励80项，2004年以来获得15项国家级科技奖励一等奖、3项国家自然科学二等奖，创造了一所大学连续获国家高等级科技奖的纪录，被社会誉为科技创新的“北航模式”。学术论文数量和质量协同增长，在《自然》《科学》等顶级期刊持续发表科研成果。大力推进协同创新，与航天、航空、船舶、兵器、电子、发动机等国家重点骨干企业开展战略合作。联合中国工程院成立中国航空工程科技发展战略研究院，打造我国航空工程科技领域首个国家级智库，强化国家战略科技力量。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校面向全球，开放交融。坚持党管外事原则，坚持服务外交大局，坚持世界一流愿景，持续深化“UPS国际化发展战略”，积极构建全域全方位的全球北航工作格局。拓展和深化与国际著名高等学校、一流研究机构、知名跨国公司及国际组织的交流合作，与全球200余所高校、研究机构、公司及国际组织等建立了长期、稳定的合作伙伴关系。发起成立及加入了“欧洲顶尖工科大学联盟（T.I.M.E.）”“一带一路航天创新联盟”“国际宇航联合会”等13个国际大学联盟及学术组织。与法国中央理工大学集团联合创办中法工程师学院，历经18年发展，被誉为“中法高等教育国际合作典范”。在教育部、工业和信息化部悉心指导和浙江省全力支持下，与法国国立民航大学共建中法航空学院，扎实推进中法航空研究院建设，积极探索高水平、精英式、本硕贯通的国际卓越工程师教育培养新范式。成立费尔北京研究院、中法未来城市实验室、中英空间科学与技术联合实验室、中德先进制造联合实验室等41个高端国际教育科技合作平台。获批成立11个国家级“高等学校学科创新引智基地”，师资队伍国际化程度不断加深，国际科研合作成果显现。大力实施“远航计划”，通过双学位、联合培养、校际学生交换、海外实习以及国际暑期学校、科技竞赛、文化交流等形式，全力推动我校学生参与国际化培养、丰富海外经历、促进多元文化交流。在全球范围内吸引优秀学生，国际学生规模、生源质量、培养层次、教育水平进入全国高校前列。获批设立了“联合国附属空间科学与技术教育亚太区域中心（中国）”、“亚太空间合作组织教育培训中国中心”和“北斗国际交流培训中心”。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校党建领航，内涵发展。突出党的政治建设统领，坚持把习近平新时代中国特色社会主义思想作为办学根本遵循，以实际行动坚决做到“两个维护”。把党的领导贯穿办学治校、教书育人全过程，完善党委领导下的校长负责制的组织体系、制度体系、工作机制，健全党委常委会和校长办公会议事规则。严格执行民主集中制，全面优化校级常设议事协调组织，完善分级分类的决策机制。建立上下贯通、执行有力的“三大会议”“学习日”机制，推动中央精神直达一线。坚持系统观念，全面深化综合改革，推进治理体系和治理能力现代化，以高质量党建引领高质量发展。大力弘扬以“空天报国”为内核的北航精神，布局新校史馆、航空航天博物馆等文化场所，建设“空天报国”主题雕塑、“天空之境”等文化地标，打造北航大讲堂、北航艺术节、“感动北航”人物评选等特色文化品牌，创作排演《罗阳》等“校园大师剧”，弘扬一流大学精神，孕育一流大学气质。推进校园媒体融合向纵深发展，精心打造以官微“航小萱”为核心的新媒体传播矩阵，聚焦大事热点、聚焦基层一线，营造崇尚立德树人成效、崇尚学术成就的浓郁氛围，激发师生爱校荣校热情，激发干事创业内生动力。2016年，学校党委被党中央授予“全国先进基层党组织”。2021年，获评全国脱贫攻坚先进集体、“首都文明校园”。2022年，获批教育部“全国党建工作示范高校”培育创建单位。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">新时代赋予新使命，新征程呼唤新作为。学校将坚持以习近平新时代中国特色社会主义思想为指导，深入学习贯彻党的二十大精神，深刻领悟“两个确立”的决定性意义，增强“四个意识”、坚定“四个自信”、做到“两个维护”，坚定信心、乘势而上，以更加奋发有为的精神状态推动学校高质量内涵式发展，加快建设中国特色世界一流大学，为中国特色社会主义教育强国建设提供有力支撑，为全面建设社会主义现代化国家作出更大贡献！</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">（数据截至2024年6月）</span></p><p style=\"text-align: justify;\"><br></p><p style=\"text-align: justify;\"><br></p><p style=\"text-indent: 2em;\"><br></p><h2 style=\"text-align: left;\">周边环境</h2><p><span style=\"color: black; font-family: 宋体;\"> &nbsp; &nbsp;北京航空航天大学地处北京中关村高科技园核心区的学院路上，毗邻国家奥林匹克中心，邻近新东方外语学校，贴近四环路；北京软件出口基地、高科技北航园区均落户北航校园。</span></p><h2 style=\"text-align: left;\">通讯地址</h2><p>北京市海淀区学院路37号</p>', 2.00);
INSERT INTO `university` VALUES (7, 'bjhkht', '123', '北京航空航天大学', 'http://localhost:9090/files/download/1751939642423-北京航空.jpg', 'UNIVERSITY', '010-83429695', 'bjhkht@qq.com', '审核通过', 31, '北京市海淀区学院路37号', '其他部委', '“双一流”建设高校', 'https://www.buaa.edu.cn/', '本科', '<h2 style=\"text-align: left;\">学校领导</h2><p style=\"text-align: justify;\">柏彦故地，巍巍学府。春秋代序，峥嵘航路。1950年，朝鲜战争爆发。抗美援朝战场上，敌我空军力量悬殊。战争的迫切需求推动了新中国航空工业从修理向制造过渡，国家“急需办一所航空大学”。1951年，国家决定将北洋大学、厦门大学、西北工学院航空系并入清华大学航空工程学系，成立清华大学航空工程学院；将云南大学航空工程系并入四川大学航空系；将西南工业专科学校航空专修科并入华北大学工学院航空工程系。1952年，根据全国高等学校院系调整的要求，设立北京航空学院，由北京工业学院航空系（1951年11月18日，华北大学工学院更名为北京工业学院）、清华大学航空工程学院、四川大学航空系合并成立。1952年10月25日，北京航空学院成立大会在北京工业学院礼堂（原中法大学旧址）举行。1988年，北京航空学院更名为北京航空航天大学（简称北航）。</p><p style=\"text-align: justify;\">作为新中国第一所航空航天高等学府，北航萌发于民族觉醒之时，诞生于国家奋发之际，成长于民族复兴之中。从航空救国到航空报国、航天报国，再到服务航空强国、航天强国建设，学校始终传承红色基因，把服务国家作为最高追求，矢志不渝培养一流人才，打造国之重器，始终奋进在中国高等教育第一方阵前列。100位两院院士和25万余名优秀建设者从这里走出，践行“德才兼备，知行合一”的校训，弘扬“艰苦朴素、勤奋好学、全面发展、勇于创新”的校风，研制发射（试飞）成功的多种型号飞行器填补了国内多项空白，谱写出了一篇篇培育栋梁、为国铸剑、追求卓越的绚丽华章。</p><p style=\"text-align: justify;\">北航现隶属于工业和信息化部，在北京市拥有学院路校区、沙河校区，2023年建成启用北航杭州国际校园。学院路校区、沙河校区、杭州国际校园总占地约4000亩。建校以来，北航一直是国家重点建设的高校，是全国第一批16所重点高校之一，也是80年代恢复学位制度后全国第一批设立研究生院的22所高校之一，1995年进入“211工程”，2001年进入“985工程”，2017年入选国家“双一流”建设高校名单。学校第十六次党员代表大会提出了建设扎根中国大地的世界一流大学的远景目标。</p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校学科繁荣，特色鲜明。现有80个本科专业。动态优化调整后，拥有36个一级学科（其中34个博士学位授权一级学科点，36个硕士学位授权一级学科点），26个博士后科研流动站，涵盖工、理、管、文、法、经、哲、教育、医、交叉10个学科门类。学校紧紧围绕国家战略需求和国际学术前沿，突出特色、质量和贡献，明确“顶尖工科、一流理科、精品文科、优势医工”学科建设方针，持续优化学科布局、凝练学科方向，促进学科交叉融合，完善学科带头人体系，推动学科、平台、团队一体化统筹推进，以科教协同平台推动教育科技人才工作深度融合。航空航天、信息、理科、文科、医工交叉五大学科群建设成效显著，8个学科入选“双一流”建设学科，在航空宇航科学与技术、仪器科学与技术、材料科学与工程、软件工程、控制科学与工程、计算机科学与技术、力学、交通运输工程、管理科学与工程、生物医学工程等学科领域具有引领优势，高峰学科占博士点比例超30%，形成了空天信优势突出、理工文医深度交叉、新方向持续引领的学科发展新格局，国防科技主干学科稳居国内一流水平。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校名师荟萃，人杰地灵。坚持人才是第一资源，深入实施人才强校战略，发布“蓝天新时代人才行动计划”，系统谋划人才队伍发展蓝图。成立国际前沿交叉科学研究院，面向世界学术前沿建设一批国际科技创新中心，突出“共建共有共享”的建设思路，大力引进海外优秀人才。深化分类卓越的人才人事制度改革，推动分系列发展评价贯穿教师成长发展全过程、全周期，师资队伍建设再上新台阶。学校教职工总数6141人，其中专任教师3108人。专任教师中，79%具有高级职称，88%具有博士学位。入选各类国家重大人才工程679人次，其中在校工作两院院士37人，领军人才284人次、青年人才358人次，国家级创新团队45个。人才队伍中涌现出众多国家一等奖获得者、领域专家和型号总师，以及一大批年轻有为、造诣精深的专家学者。完善“思想引领、榜样示范、底线约束”三位一体的教师思政工作体系，加强师德师风建设，设立“立德树人奖”作为最高荣誉，连续6年评选表彰74位师德楷模。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校精育良才，立德树人。现有在校生37656人，其中本科生16294人、研究生20240人、留学生1122人。学校坚持为党育人、为国育才，全面实施新时代人才培养领航行动计划，提出了“厚植情怀、强化基础、突出实践、科教融通”的人才培养方针，打造“强情怀、强基础、强实践、强融通”的人才培养“四强”模式，持续推动科研优势转化为人才培养优势，构建高质量人才培养体系，全面提高人才自主培养质量。积极构建思政课程、课程思政与学生工作相互浸润、三位一体的思政育人体系，完善“大思政”育人格局。教学工作体系不断完善，拥有国家级一流本科专业建设点49个，省部级一流本科专业建设点11个，国家级实验教学示范中心5个，国家级虚拟仿真实验中心3个，教育部虚拟教研室建设试点12个。建立全国示范性工程专业学位研究生联合培养基地3个、工信部校企协同育人示范基地6个。名师、名课、名教材和教学成果建设成效显著，现有国家级教学名师9名、教学团队5个，“全国高校黄大年式教师团队”3个，国家级一流本科课程74门，全国专业学位研究生在线示范课4门，获国家级教材建设优秀教材奖3项，12项成果获2022年高等教育国家级教学成果奖，其中一等奖4项。学校致力于拔尖创新人才自主培养，强化“大类招生”“大类培养”“书院制”改革，开设10个本博贯通试验班，8个专业入选“强基计划”，5个专业入选“拔尖计划2.0”。首批入选国家试点学院、国家卓越工程师学院、未来技术学院、国家集成电路学院、特色化示范性软件学院、“一流网络安全学院建设示范项目高校”创新创业学院等国家级人才培养示范项目。与北京协和医学院共建“协和医班”，探索复合型拔尖创新人才培养新模式。建设杭州国际校园，培养国际化高精尖创新人才。打造“基础教学、校内竞赛、国内平台、国际舞台”四位一体的学生科创体系，连续34年举办北航“冯如杯”竞赛，吸引了9万余名学生开展创新研究，点亮学生科学思维，提升科学探索能力。本科生“冯如三号”无人机团队两创世界纪录，学生大型综合项目“北航4号”临近空间火箭动力飞行器、亚太空间合作组织大学生小卫星项目主星“北航亚太一号”先后成功发射。在全国“挑战杯”竞赛中唯一连续18届捧得“优胜杯”，3次获最高荣誉“挑战杯”。近年来，学校生源质量稳步提升，大部分省份招生生源高考成绩平均排名在前5‰，部分省份已进入全省排名前1‰，理工类生源整体质量稳居全国前9名。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校服务国家，锐意创新。自觉履行高水平科技自立自强的使命担当，突出“四个面向”，坚持“四大”模式，强化有组织科研，着力强化纵向创新链、横向交叉链，引导和支持创新要素向关键瓶颈技术汇聚，产学研用深度融合，打造一流创新平台和一流科研团队，全面提升科技创新能力。作为副主任单位承建2个国家实验室，参与8个国家实验室建设。获批建设1个国家重大科技基础设施。牵头建设7个全国重点实验室，共建7个全国重点实验室。另有10个国家级科技创新基地、4个北京市高精尖创新中心、111个省部级重点实验室。强化关键技术攻关，牵头承担“机载”“高分”等百余项重大任务，在无人机、增材制造、发动机叶片涂层、紧缩场、电磁兼容等关键核心技术领域啃下“硬骨头”，学校团队参与论证并助力研制的国产大飞机C919成功首飞。“十五”以来，共获国家三大科技奖励80项，2004年以来获得15项国家级科技奖励一等奖、3项国家自然科学二等奖，创造了一所大学连续获国家高等级科技奖的纪录，被社会誉为科技创新的“北航模式”。学术论文数量和质量协同增长，在《自然》《科学》等顶级期刊持续发表科研成果。大力推进协同创新，与航天、航空、船舶、兵器、电子、发动机等国家重点骨干企业开展战略合作。联合中国工程院成立中国航空工程科技发展战略研究院，打造我国航空工程科技领域首个国家级智库，强化国家战略科技力量。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校面向全球，开放交融。坚持党管外事原则，坚持服务外交大局，坚持世界一流愿景，持续深化“UPS国际化发展战略”，积极构建全域全方位的全球北航工作格局。拓展和深化与国际著名高等学校、一流研究机构、知名跨国公司及国际组织的交流合作，与全球200余所高校、研究机构、公司及国际组织等建立了长期、稳定的合作伙伴关系。发起成立及加入了“欧洲顶尖工科大学联盟（T.I.M.E.）”“一带一路航天创新联盟”“国际宇航联合会”等13个国际大学联盟及学术组织。与法国中央理工大学集团联合创办中法工程师学院，历经18年发展，被誉为“中法高等教育国际合作典范”。在教育部、工业和信息化部悉心指导和浙江省全力支持下，与法国国立民航大学共建中法航空学院，扎实推进中法航空研究院建设，积极探索高水平、精英式、本硕贯通的国际卓越工程师教育培养新范式。成立费尔北京研究院、中法未来城市实验室、中英空间科学与技术联合实验室、中德先进制造联合实验室等41个高端国际教育科技合作平台。获批成立11个国家级“高等学校学科创新引智基地”，师资队伍国际化程度不断加深，国际科研合作成果显现。大力实施“远航计划”，通过双学位、联合培养、校际学生交换、海外实习以及国际暑期学校、科技竞赛、文化交流等形式，全力推动我校学生参与国际化培养、丰富海外经历、促进多元文化交流。在全球范围内吸引优秀学生，国际学生规模、生源质量、培养层次、教育水平进入全国高校前列。获批设立了“联合国附属空间科学与技术教育亚太区域中心（中国）”、“亚太空间合作组织教育培训中国中心”和“北斗国际交流培训中心”。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">学校党建领航，内涵发展。突出党的政治建设统领，坚持把习近平新时代中国特色社会主义思想作为办学根本遵循，以实际行动坚决做到“两个维护”。把党的领导贯穿办学治校、教书育人全过程，完善党委领导下的校长负责制的组织体系、制度体系、工作机制，健全党委常委会和校长办公会议事规则。严格执行民主集中制，全面优化校级常设议事协调组织，完善分级分类的决策机制。建立上下贯通、执行有力的“三大会议”“学习日”机制，推动中央精神直达一线。坚持系统观念，全面深化综合改革，推进治理体系和治理能力现代化，以高质量党建引领高质量发展。大力弘扬以“空天报国”为内核的北航精神，布局新校史馆、航空航天博物馆等文化场所，建设“空天报国”主题雕塑、“天空之境”等文化地标，打造北航大讲堂、北航艺术节、“感动北航”人物评选等特色文化品牌，创作排演《罗阳》等“校园大师剧”，弘扬一流大学精神，孕育一流大学气质。推进校园媒体融合向纵深发展，精心打造以官微“航小萱”为核心的新媒体传播矩阵，聚焦大事热点、聚焦基层一线，营造崇尚立德树人成效、崇尚学术成就的浓郁氛围，激发师生爱校荣校热情，激发干事创业内生动力。2016年，学校党委被党中央授予“全国先进基层党组织”。2021年，获评全国脱贫攻坚先进集体、“首都文明校园”。2022年，获批教育部“全国党建工作示范高校”培育创建单位。</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">新时代赋予新使命，新征程呼唤新作为。学校将坚持以习近平新时代中国特色社会主义思想为指导，深入学习贯彻党的二十大精神，深刻领悟“两个确立”的决定性意义，增强“四个意识”、坚定“四个自信”、做到“两个维护”，坚定信心、乘势而上，以更加奋发有为的精神状态推动学校高质量内涵式发展，加快建设中国特色世界一流大学，为中国特色社会主义教育强国建设提供有力支撑，为全面建设社会主义现代化国家作出更大贡献！</span></p><p style=\"text-align: justify;\"><span style=\"color: rgb(89, 89, 89); background-color: rgb(255, 255, 255);\">（数据截至2024年6月）</span></p><p style=\"text-align: justify;\"><br></p><p style=\"text-align: justify;\"><br></p><p style=\"text-indent: 2em;\"><br></p><h2 style=\"text-align: left;\">周边环境</h2><p><span style=\"color: black; font-family: 宋体;\"> &nbsp; &nbsp;北京航空航天大学地处北京中关村高科技园核心区的学院路上，毗邻国家奥林匹克中心，邻近新东方外语学校，贴近四环路；北京软件出口基地、高科技北航园区均落户北航校园。</span></p><h2 style=\"text-align: left;\">通讯地址</h2><p>北京市海淀区学院路37号</p>', 3.50);
INSERT INTO `university` VALUES (8, 'xh', '123', '西湖大学', 'http://localhost:9090/files/download/1751945819401-西湖大学.jpg', 'UNIVERSITY', '0571-88996767', 'office@westlake.edu.cn', '审核通过', 21, '云谷校区 浙江省杭州市西湖区 墩余路600号', '地方', '独立学院', 'https://www.westlake.edu.cn/', '本科', '<h2 style=\"text-align: left;\">学校领导</h2><p><span style=\"color: rgb(18, 43, 85); background-color: rgb(255, 255, 255); font-size: 19px;\">西湖大学是一所社会力量举办、国家重点支持的新型高等学校。前身为浙江西湖高等研究院，于2018年2月14日正式获教育部批准设立，是教育部、浙江省共建高校。学校按照“高起点、小而精、研究型”的办学定位，致力于集聚一流师资、打造一流学科、培育一流人才、产出一流成果，努力为国家科教兴国和创新驱动发展战略作出突出贡献。</span></p><h2 style=\"text-align: left;\">学校简介</h2><p><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px;\">西湖大学是一所社会力量举办、国家重点支持的新型高等学校，前身为浙江西湖高等研究院，于2018 年2 月14 日正式获教育部批准设立，致力于集聚一流师资、打造一流学科、培育一流人才、产出一流成果，努力为国家科教兴国和创新驱动发展战略作出突出贡献。</span></p>', 4.00);
INSERT INTO `university` VALUES (9, 'ntlg', '123', '南通理工学院', 'http://localhost:9090/files/download/1751946116744-南通理工学院.jpg', 'UNIVERSITY', '0513-85601616/85601919', 'zhaos@ntit.edu.cn', '审核通过', 22, '江苏省南通市崇川区永兴路211号', '地方', '独立学院', 'https://www.ntit.edu.cn', '本科', '<h2 style=\"text-align: left;\">学校简介</h2><p><img src=\"http://localhost:9090/files/download/1751964099065-image.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"/></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">南通理工学院是经国家教育部批准建立的一所全日制普通本科高校，创始于2000年。目前学校有南通和海安两个校区，占地面积1600亩。现有全日制在校学生2.7万余人，</span><span style=\"font-size: 16px;\">设有14</span><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">个二级学院，设置本科专业52个。</span></p><p style=\"text-indent: 2em; text-align: center;\"><strong>江海门户 &nbsp;核心区位</strong></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">南通位于江苏东南部，长三角北翼，是中国首批对外开放的14个沿海城市之一，东抵黄海，南望长江，与上海、苏州灯火相邀，西、北与泰州、盐城接壤，“据江海之会、扼南北之喉”，被誉为“北上海”。南通集“黄金海岸”与“黄金水道”优势于一身，是中国历史文化名城。</span></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">南通理工学院主校区坐落在风景秀丽、经济发达的南通市区。学校距离南通火车站7公里、南通机场17公里、距离南通西高铁站约8公里（乘坐高铁约40分钟抵达上海虹桥枢纽），交通十分便利。学校毗邻万达广场、欧尚、华润苏果、山姆会员店、迪卡侬等大型商业综合体，生活配套设施齐全。新校区——海安校区位于国家级海安经济技术开发区，距离主校区约45分钟车程。我校现代化的校园，教学条件、生活环境均按高标准规划设计并打造，融校园、花园为一体，校园内鸟语花香、小桥流水、一步一景，是莘莘学子读书学习、陶冶情操、放飞梦想的理想家园。</span></p><p style=\"text-indent: 2em; text-align: center;\"><strong>设施先进 &nbsp;条件优越</strong></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">学校建有高标准现代化教学楼、学生宿舍楼、实验中心、实训中心、图书馆、体育馆、运动场、大学生活动中心、科技创业园等教学文体设施。教学科研仪器设备总值2.44亿元，校园网实现了“多链路出口、双万兆主干、千兆到桌面”和全覆盖，满足了教育教学和师生工作生活的需要。</span></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">学校除了对学生的知识学习高要求外，还非常重视对学生实践能力、应用技能、创新能力和人文素质的培养。购置了技术含量高、性能先进的仪器设备，充实和加强了机械、数控、船舶、汽车、电工电子、建筑、软件、新能源、物流、财务和公共基础类的共148个实验实训室的建设。学校内建成了国内一流的3D打印实验室、国内领先的机械加工、数控技术、机器人、汽车维修、电子电工、风力发电、船舶、建筑、物流、财务、软件设计等实验室。图书馆馆藏图书资源总量200多万册，纸质期刊1575种，电子期刊18568种。</span></p><p style=\"text-indent: 2em; text-align: center;\"><strong>名师荟萃 &nbsp;人才强校</strong></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">学校高度重视师资队伍建设，充分发挥体制机制优势，制定特殊政策引进高素质人才，聘请了南京师范大学、江苏大学、扬州大学、南通大学等高校的一批知名专家、教授担任教学和管理工作。学校师资队伍中博、硕士学位教师占比近90%。现有省教学名师4名，市教学名师4名，省“青蓝工程”人才19名。为充分利用优秀人才资源,加快学校师资队伍建设,提高教学质量,营造浓厚的学术氛围,促进教学和科研水平提高,学校还特聘了160多名行企业高管及高级工程技术人员。学校建立了一支专兼结合、知识渊博、教学经验丰富的高水平师资队伍。</span></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">学校奉行专家治校的原则，先后成立了由专家、教授、企业家组成的“教授委员会”、“专业建设指导委员会”、“教学指导委员会”、“招生就业指导委员会”，成立了由南通市政府主导的“产教研合作委员会”，对学科建设、专业设置、教学质量、学生思想政治教育、招生就业等工作进行研究和指导，对教育教学质量定期进行考评，确保了高水准的学科建设和一流的教育教学质量，并使教学与生产、教学与科研、教学与地方经济社会紧密结合。</span></p><p style=\"text-indent: 2em; text-align: center;\"><strong>狠抓内涵 &nbsp;提升质量</strong></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">为贯彻落实《国家中长期教育改革和发展规划纲要》，学校结合自身实际制定《南通理工学院“十四五”事业发展规划》，确立了人才强校、质量立校、特色优校、顶天立地、服务社会、管理创新六大战略，坚持走内涵发展、特色发展、创新发展之路。学校以“厚德强能、知行精进”为校训，全面开展素质教育，注重培养学生实践能力。通过开展与参加各类技能竞赛活动，培养学生动手操作能力，提高学生就业竞争力。学校获批江苏省“十四五”一级重点学科2项（机械工程、工商管理），学校现有省高校品牌专业建设工程一期项目1个、省高校品牌专业建设工程二期项目9个（省一流专业5个，省产教融合型品牌专业3个，省卓越工程师教育培养计划2.0专业1个），省高校品牌专业建设工程三期项目3个。建有江苏省一流本科课程7门，获批推荐参加国家一流本科课程3门，省级产教融合型一流课程1门，省级在线开放建设课程7门。2019年以来，学生参加市级及以上学科竞赛获奖超7500人次，在2024年《普通高校大学生竞赛院校指数》中位列全国第179名，较去年提升25名，位列全国民办高校第2名。毕业生考研上线人数在同类高校中名列前茅，毕业生就业率均高于全省本科院校平均水平。</span></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">学校两度荣获江苏省高校毕业生就业工作先进集体，获“2018年全省毕业生就业创业工作专项督查考核优秀单位”，连续获评“全省高校毕业生就业工作量化督导A等高校”。学校毕业生深受社会欢迎，近三年毕业生的年终去向落实率平均为95%以上。</span></p><p style=\"text-indent: 2em; text-align: center;\"><strong>构建平台 &nbsp;服务社会</strong></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">学校坚持以服务地方经济社会发展为宗旨，积极打造各类平台为地方经济社会发展服务。学校是国家级汽车检测与维修实训基地、江苏省新能源应用技术实训基地、江苏省汽车运用技术实训基地、江苏省国际服务外包人才培训基地、江苏省产业人才培训基地、江苏省风力发电技术研究开发中心、江苏省3D打印装备及应用技术重点实验室、江苏省高校通沪产业协同发展研究基地、江苏省科普教育基地、机械工业高技能人才培养示范基地、江苏省高新技术创业服务中心、江苏省科技创业园、江苏省机动车维修人员从业资格考试点等，完备的办学条件为培养学生实践能力和创新能力奠定了坚实基础。学校还设有10个国家职业技能鉴定站(点)，可以为28个工种开展职业技能培训和鉴定工作，并获得国家、省市鉴定中心颁发的职业资格及专项技能证书。学校是国家标准化指导性技术文件《质量管理体系GB/T 19001在教育组织中的应用指南》的起草单位之一。近年来，学校教师共主持市厅级及以上纵向科研项目636项，其中国家级项目5项、省部级项目125项，获横向项目267个到账经费3800多万元。2021年以来，学校“四技”服务指标在江苏省民办高校持续排名第一。在2023年全国385所民办本科院校中基于实力评价的科研竞争力排名14位，基于增值评价的科研竞争力排名5位。在2024年中国民办本科院校综合竞争力排名中，学校位列30位。</span></p><p style=\"text-indent: 40px; text-align: left;\"><br></p><p style=\"text-indent: 2em; text-align: center;\"><strong>真心办学 &nbsp;美誉八方</strong></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(0, 0, 0); font-size: 16px;\">建校以来，学校坚持“真心办学、良心育人”的办学理念，坚持“以学生为中心”的育人理念，把“立一等品格、学一等技能、创一等事业”作为育人目标，坚持以服务地方经济社会发展为宗旨，办学业绩得到了政府和社会各界的肯定和赞赏。2020年，学校顺利通过教育部组织的普通高等学校本科教学工作合格评估。学校成为硕士学位建设单位。学校先后被评为“江苏省文明校园”、 “江苏省平安校园建设示范高校”、 “江苏省民办教育先进单位”、“江苏省高等学校和谐校园”、 “江苏省平安校园”、“江苏省教育工作先进集体（先进基层党组织）”、“江苏省高校思想政治教育工作先进集体”、“江苏省模范教职工之家”、“江苏省高校‘文明宿舍’先进单位”、“江苏省高校‘文明食堂’”、“江苏省高校毕业生就业工作先进集体”等荣誉，连续两年获评“江苏省高校毕业生就业工作量化督导A等高校”。学校是中国民办教育协会高等教育专业委员会副理事长单位、江苏省高等教育学会副会长单位等。CCTV、新华社、人民日报、光明日报、中国教育报、新华日报等10余家媒体记者曾集中走进校园，多角度采访报道了学校的办学成绩。</span></p><h2 style=\"text-align: left;\">周边环境</h2><p><span style=\"color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-size: 14px;\">南通，地处中国华东地区、江苏东南部、长江入海口，东抵太平洋、南濒扬子江，与上海、苏州灯火相邀，“据江海之会、扼南北之喉”，素有“江海门户”之称，是国家历史文化名城，是中国近代民族工业发祥地之一，史称“中国近代第一城”，是上海大都市圈门户、扬子江城市群核心、长三角C9联盟成员之一，中国首批14个沿海开放城市之一，是全国有影响力的“纺织之乡”、“建筑之乡”、“教育之乡”、“体育之乡”、“文博之乡”、“长寿之乡”“平安之乡”、“新侨之乡”。目前南通城市轨道交通1号线、2号线已正式通车，成为江苏省第六个地铁城市。</span></p><h2 style=\"text-align: left;\">通讯地址</h2><p><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px;\">校址：江苏省南通市崇川区永兴路211号 （南通校区） 江苏省海安市经济技术开发区上湖大道1号 （海安校区） E-mail：zhaos@ntit.edu.cn电话:0513-85601616、85601717、85601818 传真:0513-85601919</span></p>', 3.00);
INSERT INTO `university` VALUES (10, 'bjwz', '123', '北京物资学院', 'http://localhost:9090/files/download/1751946360012-北京物资学院.jpg', 'UNIVERSITY', '010-89534409、010-89534469', '101149', '审核通过', 31, '北京市通州区富河大街321号北京物资学院', '地方', '独立学院', 'https://news.bwu.edu.cn/www.htm', '本科', '<h2 style=\"text-align: left;\">学校简介</h2><p style=\"text-indent: 2em; text-align: left;\">北京物资学院是一所以物流和流通为特色，以经济学科为基础，以管理学科为主干，经、管、理、工、文、法等多学科协调发展的公办普通高等院校。1980年建校，先后隶属于国家物资总局、物资部、国内贸易部，1998年10月划归北京市管理。2018年2月，经北京市人民政府批准，北京市商务科技学校并入北京物资学院。</p><p style=\"text-indent: 2em; text-align: left;\">北京物资学院位于北京市朝阳北路东段，北京城市副中心核心区域，地处古老的京杭大运河源头，文化底蕴深厚，环境优美宜人，是北京市授予的“美丽校园”、“文明校园”和“花园式单位”。校园占地670余亩，建筑面积20万余平方米，教学、科研和生活设施齐全。学校建有国家级一流本科专业建设点——物流管理、信息管理与信息系统，国家级特色专业——物流管理、经济学，国家级人才培养模式创新实验区——具有国际化视野的实战型物流人才培养实验区，国家级实验教学示范中心——物流系统与技术实验教学中心，北京市属高校重点建设一流专业——物流管理，北京市级一流本科专业建设点——采购管理，北京市特色专业建设点——经济学、物流管理、信息管理与信息系统，建有北京市物流系统与技术重点实验室、智能物流系统北京市重点实验室、北京现代物流研究哲社基地、北京市高校物流工程中心、北京市协同创新中心五个市级科研平台，是学习和科研的良好场所。</p><p style=\"text-indent: 2em; text-align: left;\">1993年，学校开办国内高校第一个期货专业；2010年，开办国内高校第一个采购管理专业。目前，学校设有经济学院、物流学院、信息学院、商学院、法学院、外国语言与文化学院、国际学院、继续教育学院等8个学院，另设有马克思主义学院、体育部等教学机构。学校现有28个本科专业：经济学、国际经济与贸易、金融学、物流管理、物流工程、机械设计制造及其自动化、采购管理、质量管理工程、供应链管理、计算机科学与技术、信息工程、物联网工程、信息与计算科学、应用统计学、信息管理与信息系统、电子商务、数据科学与大数据技术、大数据管理与应用、会计学、财务管理、工商管理、市场营销、人力资源管理、劳动与社会保障、劳动关系、法学、英语、商务英语。</p><p style=\"text-indent: 2em; text-align: left;\">学校自1986年开始招收硕士研究生，目前拥有5个一级学科硕士学位授权点（应用经济学、理论经济学、管理科学与工程、工商管理、计算机科学与技术），下设20个二级学科/专业；4个专业学位硕士授权类别（工程管理、工商管理、金融、会计）。学校拥有2个北京市重点建设学科，管理科学与工程学科入选北京高校“高精尖”学科建设队列并与北京交通大学进行共建。学校与首都经济贸易大学、北京交通大学开展博士研究生联合培养工作。</p><p style=\"text-indent: 2em; text-align: left;\">学校目前有本科生、硕士研究生、留学生等各类在校生近8000人，其中本科生6000余人，硕士研究生1000余人。学校面向全国30个省、自治区、直辖市招生。几十年来，学校为国家培养了大批流通领域的高级专业人才，尤其在物流、证券期货等行业中，毕业生享有较高社会声誉。</p><p style=\"text-indent: 2em; text-align: left;\">学校现有教职工775人，其中专任教师489人，具有副教授及以上职称的教师276人，占专任教师总数的56.4%；具有博士学位教师282人，占专任教师比例为57.7%，具有硕士以上学位教师占专任教师比例为93%。享受政府特殊津贴专家9人，长城学者6人，全国五一劳动奖章获得者1人，北京市劳动模范1人，首都劳动奖章获得者1人，北京市骨干教师和骨干人才51人，北京市青年英才和青年拔尖人才24人，北京市创新人才7人，北京市优秀人才资助培养15人，北京市科技新星3人，北京市高创名师3人，北京市高等学校教学名师10人，北京市高等学校青年教学名师1人，北京市高创计划青年拔尖人才2人，北京市师德先锋1人，北京市师德先进个人3人，北京市优秀教师4人，北京市优秀教育工作者2人，北京高校优秀德育工作者12人，北京市优秀辅导员13人。</p><p style=\"text-indent: 2em; text-align: left;\">学校建有国家级一流本科专业建设点2个、国家级特色专业建设点2个，“本科教学工程”地方高校本科专业综合改革试点1个，国家级人才培养模式创新实验区1个，国家级实验教学示范中心1个，国家级大学生校外实践教育基地1个，获批北京地区高校示范性创业中心，北京市级一流本科专业建设点1个、北京市属高校重点建设一流专业1个、北京市特色专业建设点3个，北京市高等学校实验教学示范中心2个，北京市高等学校校外人才培养基地5个，北京市高等学校示范性校内创新实践基地2个，北京市精品课程4门，北京高校“优质本科课程”4门，国家级规划教材9部，北京市精品教材8部，北京高等教育精品教材建设立项6部，北京高校“优质本科教材课件”3部，市级本科优秀教学团队5个，本科生科学研究与创业行动项目立项2170项。2008年5月，学校本科教学工作被教育部评为“优秀”，2018年10月接受教育部普通高等学校本科教学工作审核评估。在近两届北京市教育教学成果奖评选中共获得一等奖2项，二等奖9项。</p><p style=\"text-indent: 2em; text-align: left;\">学校重视培养学生综合素质，促进学生德智体美劳全面发展。多年来，学校逐渐形成了培养科学精神与人文精神、发展共性与突出个性相结合，面向未来、与时俱进、丰富多彩、健康向上，既充满活力、又有深厚底蕴的校园文化。学校设有门类广泛的专业以及兴趣社团，建有涉及国际交流、公益环保、扶贫支教、文物保护、文化传承等多类型的社会实践基地，挂牌建设“北京市大学生艺术团”，拥有足球、篮球、棒垒球以及田径等多支高水平运动队；近年来，学生在中国互联网+大学生创新创业大赛、“挑战杯”大学生课外学术科技作品竞赛、国际大学生数学建模竞赛、全国大学生物流设计大赛、全国大学生数学建模与计算机应用竞赛、全国大学英语竞赛、全国大学生物理竞赛、全国大学生艺术展演比赛、西班牙哈巴涅拉国际合唱比赛等大赛中取得骄人的成绩。</p><p style=\"text-indent: 2em; text-align: left;\">学校坚持以科研促进教学，围绕建设有特色高水平应用型大学的目标和国家物流业发展中长期规划，不断加大科研力度，在流通现代化研究等领域取得了显著成果。学校建有流通经济研究所、农业与食品物流研究所、区域经济与城市发展研究中心、物流统计研究所、电子商务研究所、期货研究所、中国盐业研究中心、大运河研究院等研究机构。近三年来，学校承担国家自然科学基金、国家社会科学基金等国家级项目16项，省部级课题115项；出版专著、译著、教材170多部；发表学术论文1500多篇，其中国内外权威期刊学术论文200余篇；获国家授权专利157项。</p><p style=\"text-indent: 2em; text-align: left;\">学校积极推进政产学研用深度合作，社会服务能力显著提升。以对外合作办公室为平台，整合校内优势学科和专业力量，创新合作模式。近年来，建立市级大学科技园、中关村智慧物流产业技术研究院、中关村开放实验室和中关村科技型企业创业孵化集聚区、中国物流学会产学研基地等合作平台，为科技成果转化创造良好条件。积极推进与中关村国家自主创新示范区、中国物流与采购联合会为代表的行业协会、全国商务系统、期货行业系统以及地方政府在内的“五大合作”，与北京市贸促会、北京市扶贫协作和支援合作工作领导小组办公室、中关村管委会、通州区、平谷区、洛阳市、十堰市、赤峰市、拉萨市、三门峡市、南通市、山东省科技厅等政府机关和北京物流与供应链管理协会等行业机构建立战略合作关系，成立南方物流研究院、京津冀物流一体化研究中心、西藏现代物流研究中心、曹妃甸现代产业发展研究院、平谷现代产业发展研究院等产学研合作机构，提供了包括政策咨询、企业诊断、人才培训等多方面的服务，逐步形成服务地方的共赢合作模式。</p><p style=\"text-indent: 2em; text-align: left;\">发展与国内外院校，尤其是与国内外著名大学及研究机构的交流合作关系是学校工作的一个重要组成部分。目前，北京物资学院已经与美国、德国、法国、英国、澳大利亚、新西兰、日本、韩国等20个国家和地区的68所大学或研究机构建立了良好的交流合作关系。在科研课题、合作办学、互派留学生、教师互访、师资培训等方面开展了一系列合作，促进了学校的学科建设以及教学和科研的发展，扩大了学校在国际上的影响力。</p><p style=\"text-indent: 2em; text-align: left;\">古韵今风相辉映，文脉相承育新人。如今，北京物资学院秉承“厚德博学、笃行日新”的校训，求真务实，开拓创新，正努力建设首都乃至全国的高素质物流人才培养中心、物流理论研究中心、物流政策与决策咨询中心和物流技术创新中心，朝着建设有特色的高水平应用大学的目标阔步前进。</p><h2 style=\"text-align: left;\">通讯地址</h2><p><span style=\"color: rgb(102, 102, 102); background-color: rgb(255, 255, 255); font-size: 14px;\">北京市通州区富河大街321号北京物资学院，邮编：101149</span></p>', 2.50);
INSERT INTO `university` VALUES (11, 'nk', '123', '南开大学', 'http://localhost:9090/files/download/1752129275538-南开大学.jpg', 'UNIVERSITY', '022-60365167，022-23504845', 'nk@qq.com', '审核通过', 30, '八里台校区： 天津市南开区卫津路94号 [300071] 津南校区： 天津海河教育园区同砚路38号 [300350]', '教育部', '“双一流”建设高校', 'https://www.nankai.edu.cn/', '本科', '<h2 style=\"text-align: left;\">学校领导</h2><p style=\"text-indent: 2em;\">杨庆山</p><p style=\"text-indent: 2em;\">党委书记</p><p style=\"text-indent: 2em;\">全面主持党委工作，负责党校工作。</p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">陈雨露</p><p style=\"text-indent: 2em;\">校长、党委副书记</p><p style=\"text-indent: 2em;\">全面负责学校教学、科研和其它行政管理工作。</p><p style=\"text-indent: 2em;\"><br></p><h2 style=\"text-align: left;\">学校简介</h2><p style=\"text-indent: 2em;\">南开大学是教育部直属重点综合性大学，是敬爱的周恩来总理的母校。学校肇始于1904年，成立于1919年，由近代爱国教育家严修、张伯苓秉承教育救国理念创办。1937年校园遭侵华日军炸毁，学校南迁，与北京大学、清华大学组建国立长沙临时大学，1938年迁至昆明改名为国立西南联合大学。1946年回津复校并改为国立。</p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">新中国成立以来，学校发展始终得到党和国家的亲切关怀。毛泽东主席题写校名、亲临视察；周恩来总理三回母校指导；邓小平同志会见数学大师陈省身，批示成立南开数学研究所；江泽民同志、胡锦涛同志先后视察南开。特别是党的十八大以来，习近平总书记多次对南开的发展给予肯定，并对相关工作回信和勉励，更在百年校庆之际亲临南开视察。 </p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">1952年全国高等学校院系调整后，学校成为文理并重的全国重点大学。改革开放以来，经教育部与天津市共建支持，学校发展成为国家“211工程”和“985工程”重点建设的综合性研究型大学。2015年9月，新校区建成启用后，初步形成了八里台校区、津南校区、泰达校区“一校三区”办学格局。2017年9月，学校入选国家“双一流”建设高校。</p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">学校坚持“允公允能，日新月异”的校训，弘扬“爱国、敬业、创新、乐群”的传统和“文以治国、理以强国、商以富国”的理念，以“知中国，服务中国”为宗旨，以杰出校友周恩来为楷模，作育英才，繁荣学术，强国兴邦，传承文明，努力建设世界一流大学。</p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">学校占地443.12万平方米，其中八里台校区占地121.60万平方米，津南校区占地245.89万平方米，泰达校区占地6.72万平方米。校舍建筑总面积194.49万平方米。</p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">学校是国内学科门类齐全的综合性、研究型大学之一，在长期办学过程中，形成了文理并重、基础宽厚、突出应用与创新的办学特色。学校有专业学院28个，学科门类覆盖文、史、哲、经、管、法、理、工、农、医、教、艺等。有国家“双一流”建设学科6个，一级学科国家重点学科6个（覆盖35个二级学科），二级学科国家重点学科9个，一级学科天津市重点学科32个。在全球学科评价体系中，前1%学科17个，化学、材料科学和工程科学进入前1‰。</p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">学校落实立德树人根本任务，重视学生德、智、体、美、劳全面发展，深化推进教育教学改革，建南开特色“公能”素质教育体系。学校有在籍学生34806人，其中本科生17339人、硕士研究生11863人、博士研究生5604人。有本科专业84个；硕士学位授权一级学科10个，硕士专业学位授权点24个；博士学位授权一级学科32个，不在一级学科覆盖下的二级博士点1个，博士专业学位授权点4个。有基础学科拔尖学生培养计划2.0基地8个，国家级一流本科专业建设点56个，“强基计划”专业7个，各类国家级实验教学、教材建设、文化传承、创新创业等基地平台10余个。入选国家级一流本科课程59门，获得国家级教学名师奖9人，获评国家级教学团队9个，获得国家级教学成果奖58项。</p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">学校把教师队伍建设作为基础性工作，着力培养造就政治素质过硬、业务能力精湛、育人水平高超的高素质专家型教师队伍。学校现有专任教师2286人，其中教授959人、副教授896人；有博士生导师1052人、硕士生导师795人。有中国科学院院士13人，中国工程院院士3人，发展中国家科学院院士7人，国家“万人计划”领军人才38人、青年拔尖人才37人，教育部“长江学者奖励计划”特聘教授49人、青年学者34人，“国家杰出青年科学基金”获得者70人、“国家优秀青年科学基金”获得者56人，国家“百千万人才工程”入选者33人，国家自然科学基金创新研究群体7个，教育部创新团队10个，全国高校黄大年式教师团队2个。国家级有突出贡献的专家21人，国务院学位委员会学科评议组成员17人，“973计划”、“863计划”、国家重点研发计划等重大项目首席科学家40余人。</p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">学校坚持“四个面向”，瞄准世界科技前沿和国家重大需求，大力加强基础研究和原始创新。学校现有全国重点实验室4个、国家重点实验室1个、国家工程研究中心1个、国家地方联合工程研究中心1个、2011协同创新中心3个、前沿科学中心1个，自然科学类省部级科研基地80余个，积极推进基础研究中心、交叉科学中心等培育建设。周其林院士领衔项目获2019年度国家自然科学奖一等奖。学校发挥哲学社会科学重镇优势，积极服务新时代治国理政，推动文化文明繁荣发展。学校现有教育部高校人文社会科学重点研究基地6个、教育部哲学社会科学实验室1个、国家人权教育与培训基地1个，人文社科类省部级科研机构50余个，入选国家哲学社科成果文库数量稳居全国高校前茅，一批优秀智库成为国家部委和地方政府的“智囊团”“人才库”。学校全面对接国家和区域发展战略，积极融入经济社会发展主战场，与一批高校、企业、科研院所、政府部门建立了紧密合作关系。</p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">学校立足“两个大局”，持续推进高水平对外开放，不断扩大学校国际知名度和影响力。与近340所国际知名大学和学术机构建立了合作关系，在师生互访、联合培养、协同科研等方面开展高层次交流与合作。学校现有外籍教师及来校讲学外国专家近600人，来自90多个国家和地区的1300余名留学生在校学习。承建英国格拉斯哥大学孔子学院等8所海外孔子学院及汉语中心，与英国伯明翰大学等共建国际联合研究机构，与联合国工业发展组织、世界工程组织联合会、世界经济论坛等国际组织保持密切联系并深化实质合作。先后授予陈省身等10余位国际著名人士名誉博士称号，多位诺贝尔奖获得者、国际政要等受聘我校名誉教授，一批海内外知名学者、著名政治家、企业家受聘我校客座教授、兼职教授。</p><p style=\"text-indent: 2em;\"><br></p><p style=\"text-indent: 2em;\">南开大学将深入贯彻落实习近平总书记来校视察重要讲话精神，全面贯彻党的教育方针，坚持社会主义办学方向，落实立德树人根本任务，践行“四个服务”重要使命，加快建设南开品格、中国特色、世界一流大学，培养德智体美劳全面发展的社会主义建设者和接班人，为实现中华民族伟大复兴作出新一代南开人的历史贡献。</p><p style=\"text-align: right;\"><span style=\"font-size: 16px;\">（数据截至2023年12月）</span></p><h2 style=\"text-align: left;\">通讯地址</h2><p>八里台校区： 天津市南开区卫津路94号 [300071] 津南校区： 天津海河教育园区同砚路38号 [300350]</p>', 3.50);
INSERT INTO `university` VALUES (12, 'hb', '123', '河北大学', 'http://localhost:9090/files/download/1761034482406-1752131503294-河北大学.jpg', 'UNIVERSITY', '0312-5079698', 'hb@qq.com', '审核通过', 29, '河北省保定市五四东路180号', '地方', '独立学院', 'https://www.hbu.edu.cn/', '本科', '<h2 style=\"text-align: left;\">学校领导</h2><table style=\"width: auto;\"><tbody><tr><td colspan=\"1\" rowspan=\"1\" width=\"200\" style=\"text-align: left;\"><strong>郭健</strong><br>党委书记</td><td colspan=\"1\" rowspan=\"1\" width=\"200\" style=\"text-align: left;\"><strong>康乐</strong><br>党委副书记、校长</td></tr></tbody></table><p style=\"text-indent: 2em;\"> </p><h2 style=\"text-align: left;\">学校简介</h2><p><br></p><p style=\"text-indent: 43px;\"><span style=\"font-family: 华文仿宋;\">河北大学是教育部与河北省人民政府“部省合建”、河北省人民政府和国家国防科技工业局共建的重点综合性大学，也是河北省重点支持的国家一流大学建设一层次高校。</span></p><p style=\"text-indent: 2em; text-align: left;\"><br></p><p style=\"text-indent: 43px;\"><span style=\"font-family: 华文仿宋;\">学校始建于1921年，初名天津工商大学，为法国天主教耶稣会创办，校址位于天津市马场道141号。1933年，学校因不足大学之规模，遂改名天津工商学院，1948年具备3院10系之规模后更名为津沽大学。1951年，中央人民政府接收津沽大学并改之为国立，由天津市政府领导，学校迎来新的历史纪元，并建成3院13系之规模。1952年，中央人民政府对全国高校布局及院系进行调整，津沽大学的工学院、财经学院分别并入天津大学、南开大学，另以师范学院为基础，在原址建成天津师范学院，续成河北大学之史脉，并于数年内由6系发展为9系。1958年，天津师范学院扩建为天津师范大学，其后被确定为全省5所重点大学之一。1960年，天津师范大学改建为综合性大学并定名河北大学。1970年，河北大学由天津迁至国家历史文化名城——河北省保定市。2000年，河北省技术监督学校并入河北大学。2005年，河北省职工医学院及其附属医院并入河北大学。</span></p><p style=\"text-indent: 2em; text-align: left;\"><br></p><p style=\"text-indent: 43px;\"><span style=\"font-family: 华文仿宋;\">学校占地2430亩，有本部、新校区和医学部等校区，建筑面积133万平方米，固定资产总值32亿元。设有一级学科博士点15个；一级学科硕士点46个，硕士专业学位授权类别30种；95个本科专业。学科专业分布在哲学、经济学、法学、教育学、文学、历史学、理学、工学、农学、医学、管理学、艺术学12大门类，是全国学科门类设置最齐全的高校之一。另设独立学院1所——河北大学工商学院，有本科专业59个。</span></p><p style=\"text-indent: 2em; text-align: left;\"><br></p><p style=\"text-indent: 43px;\"><span style=\"font-family: 华文仿宋;\">学校现有全日制本专科生、研究生等各类在籍学生约42000人，其中，全日制博士、硕士研究生6100余人，全日制本科生约26900人，工商学院学生8990人。现有教职员工3278人，其中，专任教师1960人，具有博士学位教师达到53.3%；拥有两院院士、“长江学者”、国家杰青、“万人计划”、国家级教学名师、国家“百千万人才工程”人选、国家有突出贡献中青年专家、国务院特殊津贴专家等国家级优秀人才67人次，燕赵学者、省管优秀专家等省部级以上高层次人才342人次。</span></p><p style=\"text-indent: 2em; text-align: left;\"><br></p><p style=\"text-indent: 43px;\"><span style=\"font-family: 华文仿宋;\">学校办学实力雄厚，设有国家重点（培育）学科1个、河北省世界一流学科建设项目3个，河北省国家一流学科建设项目4个、河北省国家重点学科培育项目3个、河北省强势特色学科4个、河北省重点学科18个，博士后科研流动站7个和博士后科研工作站1个；建有国家地方联合工程实验室及省部级重点实验室（基地）、工程实验室17个，教育部人文社科重点研究基地等省部级人文社科重点研究基地（中心）16个，河北省“2011”协同创新中心4个，与央企共建重点实验室2个；拥有实验教学示范中心、特色专业等国家级“质量工程”项目14个，专业综合改革试点、卓越人才培养计划、大学生实践教育基地等国家级“本科教学工程”项目11个，以及省级“本科教学质量与教学改革工程”项目112个。学校还是国家大学生文化素质教育基地、国家专业技术人员继续教育基地和中国延安精神教育基地。</span></p><p style=\"text-indent: 2em; text-align: left;\"><br></p><p style=\"text-indent: 43px;\"><span style=\"font-family: 华文仿宋;\">学校坚持开放办学，先后与世界上100多所高校建立起合作交流关系，设有教育部批准的中外合作办学机构——河北大学－中央兰开夏传媒与创意学院，在俄罗斯、马来西亚等国家设有汉语教学中心，承办了巴西里约热内卢天主教大会孔子学院、美国路易斯安那泽维尔大学孔子学院、毛里塔尼亚努瓦克肖特大学孔子学院，为90多个国家、地区培养博士、硕士、学士及短期留学生3000余名，是“教育部留学出国人员培训与研究中心”试点高校、河北省首家具有接收中国政府奖学金生资格的高校。</span></p><p style=\"text-indent: 2em; text-align: left;\"><br></p><p style=\"text-indent: 43px;\"><span style=\"font-family: 华文仿宋;\">河北大学自发轫至今，历时九十余载。九十余年来，一代代学者捧土培根、筚路蓝缕，一代代学子努力向学、蔚为国用，历数代而共同育就了“实事求是”的校训传统，“博学、求真、惟恒、创新”的校风精神，并以此作为理想追求和价值取向，作育英才，服务社会，培养了30多万名优秀学子，校友遍及世界各地；创造了一大批原创性、前沿性科技成果，产生了蔚为大观的经济效益和社会效益。今天的河北大学，在河北省委、省政府与教育部、财政部等国家部委的重点建设下，各项工作日新月异，呈现蓬勃向上的发展态势。全校师生正以入选“部省合建”为契机，齐心协力，攻坚克难，向着建设“特色鲜明，国际知名”的高水平综合性大学阔步前行！</span></p><p><br></p><h2 style=\"text-align: left;\">通讯地址</h2><p>河北省保定市五四东路180号</p><p><br></p>', 4.00);
INSERT INTO `university` VALUES (13, 'sx', '123', '山西大学', 'http://localhost:9090/files/download/1761034467483-1752131836760-山西大学.jpg', 'UNIVERSITY', '0351-7018101', 'sx@qq.com', '审核通过', 28, '山西省太原市坞城路92号', '地方', '“双一流”建设高校', 'https://www.sxu.edu.cn', '本科', '<h2 style=\"text-align: left;\">学校领导</h2><p><br></p><p style=\"text-indent: 2em;\"><a href=\"https://www.sxu.edu.cn/xxgk/xrld/index.html\" target=\"_self\">山西大学现任领导</a><br></p><h2 style=\"text-align: left;\">学校简介</h2><p><br></p><p style=\"text-indent: 2em;\"><a href=\"https://www.sxu.edu.cn/xxgk/xxjj/index.html\" target=\"_self\">山西大学学校简介</a><br></p><h2 style=\"text-align: left;\">周边环境</h2><p><br></p><p style=\"text-indent: 2em;\"><a href=\"https://www.sxu.edu.cn/zty/whshzt/index.html\" target=\"_self\">山西大学周边环境</a><br></p><h2 style=\"text-align: left;\">通讯地址</h2><p>山西省太原市坞城路92号</p>', 3.33);
INSERT INTO `university` VALUES (14, 'nmgtzdz', '123', '内蒙古丰州职业学院', 'http://localhost:9090/files/download/1761034500951-1752132633950-内蒙古丰州职业学院.jpg', 'UNIVERSITY', '18847130994', NULL, '审核通过', 27, '中山分院：呼和浩特市乌兰察布东路统计局街5号（南校区）', '地方', '独立学院', 'http://nmgzsxy.cn/', '高职(专科)', '<h2 style=\"text-align: left;\">学校简介</h2><p style=\"text-indent: 2em;\"> &nbsp;内蒙古丰州职业学院是经自治区政府批准，国家教育部备案，是自治区最早由国家教育部批准的高等职业院校。是办学的先进单位，全国职业院校就业先进单位。1985年列入全国普通高校系列，成为有学历教育和非学历教育资质的普通全日制普通高校。</p><p style=\"text-indent: 2em;\"> &nbsp;学院注重对学生就业观念的培养，突出“职业教育即就业教育”的理念。把就业指导课程纳入教学计划，定期举办就业指导专家讲座，并积极开展对外交流合作，与区内外多家单位建立了稳定的毕业生就业合作关系。学院还充分利用民主党派办学的优势，广泛联络民主党派人士办企业，扩展毕业生就业渠道。自2007年以来，我校的就业率均保持在90%以上。</p><p style=\"text-indent: 2em;\"> &nbsp;学院提倡“双证教育”，是国家劳动部批准认定的国家职业技能培训定点单位和国家信息产业部IT技术资格认证定点院校。学生毕业前，经职业资格培训和技能鉴定合格后，可取得中、高级职业技能等级证书和电子信息产业技术资格证书，为学生就业上岗提供了有力的保证。</p><p style=\"text-indent: 2em;\"> </p><h2 style=\"text-align: left;\">周边环境</h2><p style=\"text-indent: 2em;\"> &nbsp; &nbsp;学院周边分布有内蒙古图书馆、文化商城、内蒙古医院、内蒙古植物园，人文环境优雅，交通便利，生活设施完善。部分专业在大学城教学。</p><h2 style=\"text-align: left;\">通讯地址</h2><p>中山分院：呼和浩特市乌兰察布东路统计局街5号（南校区）；乌兰察布街69号（北校区） 青城分院：呼和浩特赛罕区兴安南路59号（校本部）；呼和浩特大学城 （新校区）</p>', 3.33);
INSERT INTO `university` VALUES (15, 'hgd', '123', 'hgd', NULL, 'UNIVERSITY', NULL, NULL, '待认证', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);

-- university_certification 模块已下线，相关表与测试数据已删除

-- ----------------------------
-- Table structure for university_specialtys
-- ----------------------------
DROP TABLE IF EXISTS `university_specialtys`;
CREATE TABLE `university_specialtys`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `university_id` int NULL DEFAULT NULL COMMENT '学校ID',
  `categorys_id` int NULL DEFAULT NULL COMMENT '门类ID',
  `specialtys_id` int NULL DEFAULT NULL COMMENT '专业ID',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '专业介绍',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 54 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '学校专业' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of university_specialtys
-- ----------------------------
INSERT INTO `university_specialtys` VALUES (1, 2, 13, 75, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\">哲学系、宗教学系（哲学类）<br>北大哲学系创建于1914年，是中国最早的哲学系。九十多年来，已培养8000余名毕业生，具有世界声誉的哲学家、文学家、历史学家，如梁漱溟、胡适、朱自清、汤用彤、冯友兰、熊十力、顾颉刚等曾在这里求学或执教。北大哲学系，因此被誉为“思想家的摇篮”。<br>宗教学系成立于1995年，是中国最早的宗教学系。哲学系1982年在国内率先设立本科宗教学专业，宗教学系以此为基础，积极开拓，目前已是国内外著名的世界及中国各大宗教的研究重镇。两系实行联体运作，合并招生，共同培养。<br>两系学科齐全、师资雄厚，教师65人（其中教授30人，副教授32人，讲师3人），科研、教学水平均居国内领先地位，多次获得国家级教学成果奖，是教育部最早确认的国家文科人才培养基地，2003年又获教育部学科评估全国排名第一。两系拥有8个博士点、8个硕士点以及一级学科博士后流动站，拥有马克思主义哲学、中国哲学、外国哲学和美学四个全国重点学科，并有外国哲学研究所、美学与美育研究中心两个教育部重点研究基地；两系还有挂靠的两家研究所、九个研究中心以及《儒藏》编纂中心。<br>两系现有在校本科生138人，在读双学位112人，在校硕士生173人、博士生127人。近三年本科毕业生有近一半攻读国内外研究生（本系就有8个硕士专业方向可供毕业生选择），其余或去高等院校、科研机构从事教学科研工作，或去国家机关、新闻出版、企业公司、民主党派、宗教部门等单位从事行政管理、党务工作、经济管理或文化产业开发，就业率连续保持100%。<br>哲学系、宗教学系从2003年开始实施“加强基础、淡化专业”的新教学计划，要求学生能够系统掌握哲学基本理论和中外哲学的历史、现状，具有广博的人文、社会科学和自然科学知识。学生在前三个学期进行基础训练，主要包括：哲学导论、高等数学、马克思主义哲学导论、中国哲学史、西方哲学史、宗教学导论等；第四学期开始分专业方向学习，两系共有以下三个专业方向。<br>哲学专业<br>该专业培养具有丰富的哲学史知识和较高的哲学思维能力的理论人才以及具有广博知识背景的复合型人才，主要专业课程：中国哲学专题、西方哲学专题、形而上学、知识论、科学哲学、伦理学导论、美学原理。<br>哲学专业（科技哲学与逻辑学方向）<br>该方向培养兼具自然科学和哲学知识背景的综合型理论人才和科技传播、科技管理人才，主要专业课程：科学通史、科学哲学、博物学导论、科学传播导论、科学社会学、逻辑史、逻辑哲学。<br>宗教学专业<br>该专业培养宗教学理论人才和宗教事务管理人才，主要课程：宗教哲学、宗教社会学、基督教史、中国宗教史、道教史、印度佛教史、中国佛教史、中国基督教史、伊斯兰教史、宗教现状与宗教事务。<br>哲学系、宗教学系的详细介绍，参见网页 http://www.disa.pku.edu.cn</span></p>');
INSERT INTO `university_specialtys` VALUES (2, 2, 12, 70, '<table style=\"width: auto; text-align: left;\"><tbody><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\" style=\"text-align: left;\"><br>经济学院（经济学类）<br>北京大学经济学院至今已经走过了百余年的历程，从1898年的京师大学堂商科，到1912的经济学系，再经历1985年率先撤系设院，风雨百年，其间多有名世者。一部《新人口论》撼动中国政学两界的马寅初先生，学贯中西的经济学名师陈岱孙先生，皆曾摄行经济系事务。<br>经济学院是国内经济学研究的重要基地，其学科齐全、师资力量雄厚、梯队完善。现有经济学、国际经济与贸易、金融学、风险管理与保险学、财政学、环境资源与发展经济学等六个本科专业，六个硕士学位专业，六个博士学位专业，一个经济学博士后流动站。<br>2004年2月，经济学院与北大中国经济研究中心签订合作协议，经济研究中心的教授、副教授均被聘为经济学院的兼职教师，经济学院和经济研究中心的学生可以相互选课，由此整合了教学科研资源，形成了强大的经济学科阵容，吴敬琏、吴树青、肖灼基、晏智杰、刘伟、孙祁祥、林毅夫、海闻等知名学者皆执教于经济学院。目前经济学院有专职教授21位，副教授28位，讲师20位，在站博士后36位。2001年至2005年，学院承担国家、省、部级科研项目100项，科研总经费逾千万元，是北大文科获各种社科基金课题立项最多的院系之一。<br>经济学院是全国最早设立经济学博士后流动站的学院，是全国文科率先实行硕博连读制的学院，是国家教育部“全国经济学人才培养基地”评比唯一连续两次排名第一的学院。<br>经济学院每年招收和培养来自大江南北、五湖四海的优秀学生。每年都有众多的各省高考状元和排名占各省、市前列的优秀学生选择经济学院。我们的毕业生毕业选择范围宽广，有40%的学生在国内读研，有20%的学生在美国、英国、加拿大等国家留学，有40%的学生在中央、国务院各大部委、省市机关、银行以及外资企业就业。多年来，经济学院为国家和社会发展输送了数以万计的优秀人才。<br>经济学院是国际性、开放性的学院，国际交流十分广泛，置身于此，可以放眼世界，胸怀天下。现有来自不同国家和地区的120名留学生在经济学院求学，每年都有世界著名的经济学家莅临我院发表演讲，每年都有众多老师和学生到世界各个国家和地区学习、访问、讲学和进修。<br>经济学院是北大学生社团最为活跃的院系之一，除紧张有序的学习外，经济学院学生的业余生活也丰富多彩。学生们扎实的知识功底、良好的人际关系、精妙的组织领导能力，得到了北大和社会各界的高度认同和赞赏。<br>2006年经济学院仍然按照学科大类招生。新生进入经济学院以后，本着“宽口径、厚基础”的教学方针，前两年以学习经济学的主干基础课程为主，不分专业。从第三年开始，学生可以根据自己的特点、兴趣和人生规划选择适合自己的专业领域和培养方向。<br>专业方向如下：<br>（1）经济学专业 该专业课程设置与国外大学经济学专业接轨，为有志成为经济理论研究者、宏观经济管理者和职业经理的青年学生提供一个成长和发展的舞台。毕业生既适合到政府经济决策部门、金融研究机构、教学研究机构和公司企业工作，也为在国内或出国继续深造打下坚实的基础。<br>（2）国际经济与贸易专业 该专业主要培养适应经济全球化趋势，具备国际经济基本理论与较高的外语和电子商务运用等实践技能的，能从事国际经济、贸易、金融、商务工作的高级专门人才。毕业生以深厚的理论基础与开阔的创新思维为竞争优势，有较为自由的选择空间。<br>（3）金融学专业 该专业在与国际上金融学专业教学接轨的同时，也提供实践应用性课程，从而全面提升学生个人的竞争能力。毕业生既有去国外名校留学深造的，也有选择到咨询管理公司、投资银行、中央银行、外资或国有商业银行、保险公司、国家部委机关等工作的。<br>（4）风险管理与保险学专业 该专业致力于培养“有专长、基础宽、素质高”，能够胜任国内外风险管理与保险经营管理工作的复合型人才及风险管理与保险教学科研工作的学术人才。毕业生或者去国外名校留学，或者供职于各大保险公司、保险监督管理机构、金融证券机构。<br>（5）财政学专业 该专业顺应公共管理事务在中国的勃兴，旨在培养具有宽厚扎实的经济学理论基础，熟悉财政税务、财务会计知识，具备较高的外语和计算机运用水平、较强的研究能力、决策能力和管理能力的高级专门人才。毕业生可从事政府部门的公共经济研究和政策制定工作，可任职于各类大型企业、会计师事务所、律师事务所等中介机构的资产评估、税务代理等工作，还可以留在大学或是研究机构，从事研究教学工作。<br>（6）环境资源与发展经济学专业 该专业是一门兼有文、理、工三栖特点的综合型经济学科，侧重于环境、资源与可持续性发展的研究，毕业生将能胜任在政府部门、大中型企业、跨国公司、科研机构、高等院校及国际组织等的管理与研究工作。<br>目前，全体北大经院人在院长刘伟教授的带领下，积极加强学院的各方面建设，同时，面向海内外诚聘英才，充实教学科研队伍，加大与国外著名大学的合作与交流力度，并增设新的专业，力争早日成为全国乃至亚洲最好的、并有国际影响的一流学院。<br>我们真诚地欢迎你加入经济学院这个大家庭。在这里，您的金色华年将熠熠生辉，您的灿烂生活将由此开始。这里将成为您一生最美好的回忆！<br>经济学院的详细介绍参见网页：http://econ.pku.edu.cn</td></tr></tbody></table><p><br></p>');
INSERT INTO `university_specialtys` VALUES (3, 2, 11, 69, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(240, 249, 246); font-size: 16px;\">法学院（法学）<br>北京大学法学院是中国近现代法学高等教育的发源地，2004年是她的百年华诞。<br>北大法学院学科齐全、名师云集，开展的法学教育涵盖法学本科、知识产权第二学士学位、法学硕士、法律硕士、法学博士等多个层面。法学院现有学科中的法理学、经济法学、刑法学和宪法行政法学是全国重点学科。法学院设有法学一级学科博士点和博士后流动站，10个硕士点。法学院拥有许多蜚声中外的知名学者、跨世纪的中青年学术骨干，现有在职教授33名，副教授38名，讲师11名。他们在我国法学教育、科研和立法、司法实践中发挥着重要作用。在名师的言传身教之下，在法学院悠久法律文化传统的熏陶下，法学院的学生能够接受高水平的、系统的法学教育。<br>百年来，北大法学院一直走在中国法学教育的前列，不断推进法学教育的发展。1998年，本着“加强基础、淡化专业、因材施教、分流培养”的办学方针，法学院率先取消了法学本科教育的专业划分，只设立法学专业，目的在于培养“厚基础、宽口径”的新型法律人才。本科教育之培养目标，在于使学生系统掌握宪法、民法、刑法、经济法、行政法、诉讼法、国际法等领域的法学原理和法律规则，具备处理法律实务、运用外语进行国际交流和从事法学研究的素养。根据2003年开始实施的新的本科生教学计划，法学本科学制为4年。学生在4年内修满最低140分并完成实习和学士学位论文后，准予毕业、授予法学学士学位。<br>北大法学院学术气氛浓郁，具有良好的科研条件。法学院教师的学术研究硕果累累，并多次获得国家级和省部级奖项。法学院现有25个研究中心（所），它们是开展学术研究与交流的重要舞台。法学院创办的法制信息中心拥有全国高校最大的法律电脑检索系统，学术刊物《中外法学》是全国法学界最权威性的学术刊物之一。法学院图书馆是藏书丰富的法律图书馆，也是北京大学的法律文献信息中心，并被指定为联合国资料保存图书馆。法学院图书馆现有中外文书刊9万余册，馆内设有期刊阅览室、图书阅览室、电子阅览室、中文书库、外文书库、台港澳阅览室，并有50余台连通国际互联网和法律数据库的电脑。设施更先进、功能更完备的新法学楼正在筹建之中。<br>北大法学院始终坚持“立足中国、胸怀世界”的开放精神，与世界上的多所著名法律院校建立了稳定的合作关系。经过多年的经验积累，法学院已经建立起了多样化的国际交流模式：举办大型国际会议及学术活动；海外知名学者、法官、政府官员及律师莅临演讲；海外访问学者讲授外国法律课程；法学院教师与学生赴海外交流、研究与进修；招收欧、美、亚、非国家的留学生。<br>为培养和提高学生的综合素质，法学院大力提倡和支持学生的学术和实践活动。法学院研究生独立编辑的《北大法律评论》被同行公认为是最好的研究生学术刊物。作为法学院院刊的《北大法律人》是一份由学生自主编辑的报纸。此外，法学院还有“北大法学社”、“北大法律援助协会”等多个学生社团或组织。法学院的学生还建立了自己的网站“北大法律学生网”，经常举办模拟法庭、学术讲座、辩论比赛、学术论文竞赛、法律义务咨询等活动。<br>对于品学兼优的学生，除了全校性的奖学金之外，法学院还设有“阿兰克西·高特奖学金”、“岳成律师事务所奖学金”、“白仁杰奖学金”、“理律奖学金”、“小松·柏奖学金”、“贝克·麦肯思奖学金”、“钱列阳奖学金”、“微软奖学金”、“斯缔尔奖学金”等专项奖学金。对于经济困难的学生，除学校提供的各种助学途径外，法学院的老师和校友还捐助了“甘雨霈先生助困基金”、“育才助学基金”、“杨桢教授助困基金”、“长城律师助困基金”、“君合律师事务所北大法学院毕业生扶助经济困难本科生基金”、“杨少为助学金”、“8829校友助学金”。<br>北大法学院的毕业生以理论基础扎实、综合素质高、适应能力强而著称。本科毕业生或继续在国内或国外深造，或多被各级国家机关、司法部门、国内外著名律师事务所、著名企业录用，在国内和国际法律舞台上表现出众，受到用人单位的普遍好评。<br>北大法学院期待你成为一名北大法律人。<br>法学院的详细介绍参见网页：http://www.law.pku.edu.cn</span></p>');
INSERT INTO `university_specialtys` VALUES (4, 2, 9, 58, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\">英语语言文学系<br>一种语言乃是一个世界。在未名湖畔学英语，就是要走入一个由英语语言、文学和文化构成的丰富多彩的世界。 我们成长在中文的世界里，世界在我们眼里是中国人的世界，当我们观察这个世界的时候，我们处在中文的笼罩之下，看到独属于这个民族的一些特质。而如果说中国人仍可以通过学习中文来增加文化自知，那么，学习英文则可以使自己在那些由罗马字母垒起来的句子里发展出不同的眼光，看见不同的世界。当我们能够在两个世界之间自由穿梭时，我们会发现世界的丰富远超过自己的想象，渺小的自我被置入一个大的精神空间，被嵌入深厚的历史层面中。这些都不是仅仅把英语当作简单的工具所能得到的。 为实践我们的教育理念，英语系不仅强调过硬的基本技能，也注重专业学科的基础学术训练，所开设课程包括英语精读、写作、视听、口语、口译、笔译以及一整套涉及文学、文化、语言学、人文思想、宗教与神话、电影与戏剧实践等方面的专题课程。我们对自己的毕业生有如下期待：具备良好的专业英语素质，对欧美文化有深层了解，具有开阔的视野和一定的人文素养。我们认为这样的本科毕业生无论在就业、上研或出国发展等方面都有较好的适应性，不仅在本专业领域，也包括在其他专业领域，都可以继续深造和发展。北京大学文理并包的教育特点、各学科间的交叉互补、灵活的选课制度以及丰富的校园文化活动等因素更有助于我们实现自己的抱负。 详细介绍参见北京大学外国语学院网页：http://sfl.pku.edu.cn<br>北京大学“国家外语非通用语种本科人才培养基地”网站：http://olc.pku.edu.cn</span></p>');
INSERT INTO `university_specialtys` VALUES (5, 2, 9, 59, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(240, 249, 246); font-size: 16px;\">俄罗斯语言文学系<br>俄罗斯语言文学系的前身是1920年北京大学设立的俄文系。1952年，在著名翻译家、教育家曹靖华的主持下，北京大学正式成立俄罗斯语言文学系。曹靖华教授为第一任系主任。 1978年我系被批准建立硕士学位授予点，1990年被批准建立博士学位授予点。俄语系师资力量雄厚，现有在职教学科研人员19人，其中教授3人，副教授15人，讲师1人，获得博士学位的教师15人，在校本科生、硕士生、博士生总数120人左右。 俄语系为本科生开设的课程有：基础和高级俄语、俄语写作、语法、视听说、修辞、口译、新闻听力、翻译等语言类课程；俄罗斯文学史、文学选读、俄罗斯国情、俄罗斯艺术史、文学翻译、俄国作家创作专题研究、俄罗斯社会思想史、民间文学、俄罗斯文学与音乐、民俗民情、大众传媒与政治等文学文化类课程。 本系毕业生遍布文化部、中联部、外交部、教育部、新华社、中国国际广播电台、商务部及所属各大公司和驻外办事机构，商务印书馆、高等教育出版社、人民画报社、人民文学出版社等各出版机构。许多高等院校均有我系的毕业生从事俄罗斯语言文学文化的教学、研究和翻译等工作。<br>详细介绍参见北京大学外国语学院网页：http://sfl.pku.edu.cn<br>北京大学“国家外语非通用语种本科人才培养基地”网站：http://olc.pku.edu.cn</span></p>');
INSERT INTO `university_specialtys` VALUES (6, 2, 8, 51, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(240, 249, 246); font-size: 16px;\">历史学系（历史学类） 北京大学历史学系始建于1899年秋（时称京师大学堂史学堂），是近代中国最早建立的史学教育科系，在全国高校同类学科中历史最久，培养人才最多，社会影响最大。改革开放以来，学科建设又有长足的发展。1981年中国古代史、中国近现代史、世界地区国别史、世界近现代史和考古学（当时属历史学系）5个学科点获得首批硕士、博士学位授予权；1987年中国古代史、世界近现代史学科点被批准为第一批国家级重点学科。1992年历史学系被评为全国高校历史学科第一家博士后流动站。1994年被评为国家文科基础学科人才（本科）培养基地。1998年获得国家首批历史学一级学科博士授予权。2000年中国古代史研究中心被评为教育部人文社科重点研究基地。2001年中国古代史和世界史学科点再次被评为国家级重点学科。2004年教育部组织一级学科评估，北京大学历史学科在全国高校中排名首位。现有在职教师67人。具体包括：教授35人，副教授27人（教授、副教授中博士生导师共39人），讲师5人。设有中国古代史教研室、中国近现代史教研室、世界上古中古史教研室、欧美近现代史教研室、亚非拉近现代史教研室、专门史教研室、历史文献学与电子资源学教研室、民族史教研室、中国古代史研究中心和世界史研究所共10个教学研究实体。<br>百余年来，近现代中国著名的历史学家——李大钊、胡适、马叙伦、陈寅恪、陈垣、陈翰笙、傅斯年、董作宾、钱穆、顾颉刚、翦伯赞、向达、郑天挺、齐思和、邓广铭、周一良等，都曾在这里工作和学习过。历史学系不仅为国家培养为数众多的历史学家，还有不少毕业生在其他岗位上取得了重大成就，做出重要贡献。<br>本科生招生专业名称为历史学。必修课程包括中国古代史、中国近代史、中华民国史、中华人民共和国史、世界上古史、世界中古史、欧美近代史、亚非拉近代史、世界现代史、世界当代史、中国历史文选、史学概论、中国史学史和外国史学史共14门。至大学三年级，分流为历史学（中国历史）和世界历史两个专业。轮流滚动开设的选修课程有断代史、专题史、国别史、史料选读等100余门。<br>历史学系每年评选的奖助学金资源丰富，主要有：光华、优龙、细越、董氏东方、松下电器、五四、谢培智、杨乃英、华藏、唐仲英、侨心、安重根、宝钢、摩托罗拉优、玫琳凯、雏鹰、卡乐B日本研究、韩国学、依田熹家、刘绍唐等。学校每年评选三好学生标兵、三好学生和学习优秀单项奖，并评选校长、 政、泰兆三种基金资助本科生进行科研活动。家庭经济困难的学生可以申请国家奖学金以及郑格如、晨兴、香港校友会、曾宪梓、浩瀚等助学金，或申请国家助学贷款。<br>历史学系与美国、日本、韩国、英国、法国、德国、荷兰、香港、台湾等十几个国家和地区著名高等院校的相关系所建立了教学、科研合作关系。聘请了多名海外著名学者担任客座教授，每年接待数十名海外学者、研究生前来访问或进修，也选派若干教师和学生赴海外进行学术交流、讲学、进修等活动。经常举办海外学者学术讲座和国际学术会议。<br>历史学系1999至2004六年间共毕业本科生210人，其中56%就读硕士研究生，9%出国，35%在各省市机关及事业单位工作。2005年毕业本科生29人，其中19人继续就读硕士研究生，3人出国，7人参加工作。<br>历史学系的详细介绍参见网页：http://www.hist.pku.edu.cn</span></p>');
INSERT INTO `university_specialtys` VALUES (7, 2, 8, 53, '<table style=\"width: auto; text-align: left;\"><tbody><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\" style=\"text-align: left;\">考古文博学院（考古学类） 北京大学考古文博学院拥有雄厚的师资力量、丰富的图书文物资料、良好的教学实验设备，学科水平居于国内外领先地位。招收有来自国内外的本科生、硕士生、博士生各个层次的学生，并设有博士后流动站。历年来，北京大学考古文博学院培养的学生已有两千多人，他（她）们活跃在全国各地以及世界许多国家，成为文物、考古、博物馆事业乃至于其它领域的中坚力量。学院设有考古学及博物馆学和文物保存科学技术两个系，考古学、博物馆学、文物建筑和文物保护四个专业（或专业方向），2006年度招生的专业有：<br>考古学专业 考古学科创建于1922年，是北京大学具有悠久历史的专业。考古专业作为国家该领域唯一的重点学科，拥有一批在国内外考古界享有很高威望的专家和学术带头人，考古教学和科研水平居于国内领先地位，在国际上有很大的影响力，被誉为“中国考古学家的摇篮”和“中国考古学研究的中心”。本专业具有文理交叉性质，要求学生具有扎实的本专业基础知识和基本技能，较广泛的人文科学知识和一定的艺术修养，能够进行考古学和文化遗产的初步研究。毕业生既能够从事考古、文物和博物馆等专业工作，也能够适应于人文社会科学各相关方面的工作，并为继续深造，攻读本专业和相关专业的研究生打下坚实的基础。<br>博物馆学专业 博物馆学专业创办于1988年，该专业依托于首都北京为数众多的不同类型的博物馆和大量的专家学者，拥有一座现代化的北京大学赛克勒考古与艺术博物馆，与国外博物馆学界有着广泛的交流和密切联系。专业注重基础理论和实际应用的结合，除了博物馆学的理论课程外，还开设了博物馆陈列设计、博物藏品管理等实践性很强的课程。此外，文物研究、文物保护、工艺美术方面的课程，更扩充了学生的知识面和提高了学生的艺术修养。博物馆学专业的本科毕业生除了进入各级政府文化文物行政管理部门工作或成为各类博物馆的业务骨干外，还可以继续攻读博物馆学及相关专业的硕士学位。<br>文物建筑专业方向 文物建筑专业方向是应国家文物事业的急需于1998年新设立的专业。主要培养文物建筑保护、维修、复原的具有文物与文献并重素质的专门人才。该专业具有文理交叉性质和实践应用性强的特点，要求学生除了掌握建筑学的所必须的专业知识和技能外，还要掌握一定的历史学、考古学和文物保护的基本方法和基础知识，具有一定的艺术和美学修养。毕业后能够从事文物建筑的保护维修、方案设计和施工管理等工作，并为继续从事建筑历史与理论的初步研究奠定基础。毕业生除了可以继续攻读文物建筑方向的研究生外，还可以选择到国家文物部门所属的古代建筑研究所、文物考古研究所、文化文物行政管理部门、高等院校等单位工作。<br>考古文博学院的详细介绍参见网页：http://www.pku.edu.cn/academic/archeology</td></tr></tbody></table><p><br></p>');
INSERT INTO `university_specialtys` VALUES (8, 2, 7, 47, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\">物理学专业<br>北大物理学专业师资雄厚，设备先进，学术气氛浓厚。几十年来，几乎所有物理学的主要基础和专业课程的教材均首先出自北大，并在全国广泛使用，深刻影响并推动了中国物理的教学和人才培养。自1987年以来，获国家特等奖、一等奖的教材和教学研究项目已有16项，在全国高校中遥遥领先。北大物理在科学研究及学科建设方面也屡开中国之先河，一直走在全国高校前面。北大物理学科是1991年评定的全国第一批理科基础研究和教学人才培养基地。经过8年的建设，于1999年11月通过了教育部组织的专家组验收评估，历次被评为优秀基地点。<br>北大物理学科具有教学和人才培养的优秀传统，汇聚了一大批我国老一辈物理学家和著名学者。近年来，又引进了一批活跃在科学研究第一线的年富力强的青年学者，为物理系的教师队伍增添了新鲜血液。物理学专业现有中科院院士9名，长江特聘教授7名、国家杰出青年9名，教授70多名，博士生导师50多名，副教授50多名。拥有一个国家重点实验室及一个教育部重点实验室，设有理论物理、凝聚态物理与材料物理、光学、粒子物理与核物理、核技术及应用等五个二级学科，包括物理学的众多研究方向，具有物理学一级学科博士学位授予权，设有两个博士后流动站。<br>物理学专业即是活跃的物质世界基础研究前沿，又是现代高科技的基础。受到良好物理教育的学生，即适合在微观、介观和宇观物质科学前沿从事研究，同时在信息科学、生物工程、通讯、航天、新材料开发、新能源等方面也有独特的优势。在科学技术飞速发展的时代，物理学院的毕业生由于基础宽、能力强而具有很好的就业前景和广阔的就业领域，比如国内外物理学研究、高等教育、材料科学技术、信息产业、生物技术、能源技术、高科技产品开发、企业管理、金融研究和管理等等。<br>物理学科最近几年的本科毕业生约百分之五十多在国内攻读硕士或博士学位，约百分之三十多获得美国、欧洲的著名大学的奖学金出国深造，本科毕业时直接参加工作的学生只有百分之十几。物理学院对本院上世纪八十年代本科毕业生进行的问卷调查，得到他们的就业领域分布百分比为：科研、教育32%；IT业28% ；金融、贸易、商务、咨询13%；半导体14%；生物产业2%；传统工业类6%；文体、卫生2%；律师1%；新闻媒体1%等等。他们都认为物理学习为他们后来的发展打下了终生受用的牢固基础。</span></p>');
INSERT INTO `university_specialtys` VALUES (9, 2, 7, 50, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\">化学与分子工程学院（化学类） 化学与分子工程学院的前身化学系成立于1910年，是我国公立高等院校中成立最早的化学系，为我国化学人才培养体系的建设做出了杰出贡献。2002年，全国一级学科整体水平评估，北京大学化学学科排名全国第一。在2001年举行的国家重点学科评比中，化学学院的无机化学、有机化学、分析化学、物理化学和高分子化学与物理再次被评为国家重点学科，重点学科数目居全国高校化学学科首位。目前，化学学院设有5个系：化学系、材料化学系、高分子科学与工程系、应用化学系和化学生物学系；7个研究所（无机化学，分析化学，有机化学，物理化学，高分子化学与物理，理论与计算化学，应用化学）；学院还设有北京大学分析测试中心和化学基础教学实验中心；2个国家重点实验室和2个教育部重点实验室：稀土材料化学与应用国家重点实验室、分子动态与稳态结构国家重点实验室，生物有机与分子工程、纳米器件物理与化学教育部重点实验室。2003年11月，科技部批准由北京大学和中科院化学研究所共同筹建“北京分子科学国家实验室”。高分子科学与工程系申报的“高分子化学与物理”教育部重点实验室已于2003年11月底获教育部批准立项建设。学院具有优良的实验教学和科研条件，全院大中型仪器等固定资产已达1.7亿元，为全国高校化学学科之冠。1993年被原国家教委批准为“国家理科基础科学研究和教学人才培养基地”。1998年在全国化学基地初评中被评为第一名，1999年全国中期检查评估又被评为优秀基地，2004年9月通过了教育部和基金委的验收评估，并再次被评为优秀基地。目前，化学学院有教职员工210人，其中中科院院士8人，长江特聘教授12人（含讲座教授1人），教授57人，副教授50人。3个研究群体被基金委评为创新群体，25人获得国家自然科学基金委杰出青年基金资助，9人与国外学者合作获得B类杰出青年基金资助，10人获得教育部跨世纪人才和教育部新世纪优秀人才基金资助。<br>2006年学院继续按化学大学科招生，入学三年后学生可根据自己的兴趣和志向选择三个专业（化学、材料化学和应用化学）方向进一步学习。根据北京大学“加强基础，淡化专业，因材施教，分流培养”的本科生教育方针，化学专业不再分无机、有机等专业，学生只在高年级按不同的研究方向做毕业论文。除学校规定的公共必修课和通选课外，设置了模块化的化学类课程，主要基础课程包括普通化学及实验、分析化学（含仪器分析）及实验、有机化学及实验、无机化学及实验、物理化学及实验、结构化学、高分子化学、生命化学基础、化工基础、计算机基础和综合化学实验等必修课程。化学学院十分重视本科生教学工作，许多知名学者参加本科生基础课教学工作，多门课程先后被评为教育部基地建设名牌课程、北京市和教育部精品课程。此外，学院还设置了大量的选修课程供学生选修学习，学生可以在顾问教师指导下，不断调整选修课程，实现基础牢固、个性发展的培养目标。学院鼓励学有余力的学生提前进入各课题研究小组参与科学研究和创新活动。许多学生在本科阶段就在国内外学术刊物上发表了高水平的研究论文。在最近两届（2002，2004）的全国大学生化学实验竞赛中和全国大学生“挑战杯”竞赛中，化学学院的学生均取得优异成绩，反映化学学院教学水平和人才培养的成果2005年被教育部评为国家教学成果奖二等奖。<br>历年来每年获得中学生国际化学奥赛奖牌的选手以及获得全国中学生化学竞赛的一等奖的近30名优秀高中毕业生被保送到本院，全国高考中也吸引了非常优秀的生源。目前在校学生共1190人，其中本科生701人，研究生489人；博士后工作人员 64人。近三年的统计表明，我院80%左右的毕业生被保送或考取国内外大学或研究所的研究生，15％左右的毕业生通过双向选择在国内科研、教学、大型企业等单位和国家机关工作。<br>化学与分子工程学院的详细介绍参见网页：http://www.chem.pku.edu.cn</span></p>');
INSERT INTO `university_specialtys` VALUES (10, 2, 6, 40, '<p style=\"text-indent: 2em;\">北京大学的工科教育历史悠久，1910 年 3 月即组织了工学院（当时称工科分科大学），下设土木、矿冶两个系（当时称门）。1916 年以后，北大工学院经过停办、再建、扩大，到 1952年已培养了近 5000 名学生 ；其后工学院的师生中陆续有 23人入选两院院士。1952 年全国院系调整，北大工学院的机械、电机、土木、建筑四个系合并到清华大学，化工系合并到天津大学 ；北京大学工学院的建制取消。</p><p style=\"text-indent: 2em;\">　　1952 年，著名科学家周培源教授创立了北京大学数学力学系力学专业，这是新中国的第一个力学专业。自创立之日起，以周培源为代表的一大批著名学者，如 ：钱敏、吴林襄、叶开沅、陈耀松、董铁宝、王仁、周光坰、孙天风等为北大力学的创立付出了他们的努力和智慧，奠定了北大力学系发展的坚实基础。1979 年 3 月，北京大学力学系成立。经过几代人的艰苦创业、辛勤耕耘，力学系在教学、科研和基础建设等各方面取得了很大发展，培养出一大批优秀力学与工程技术人才，他们已经成为科技、教育、国民经济与国防建设各行业的领军人物和技术骨干。入选为中国科学院院士和中国工程院院士的 16 位院友，以及入选为美国、加拿大和澳大利亚院士的 3 位院友就是他们的杰出代表。</p><p style=\"text-indent: 2em;\">　　随着我国社会的发展，现代工业技术愈加处于关键地位。北京大学原有的学科设置偏向文、理、医等学科，在基础学科教学、科研实力占据国内首屈一指地位的同时，面向现代工业技术的工程学科未得到充分发展。在这样的背景下，与国家需求、经济建设相结合，创造自主知识产权，实现工业兴国战略，帮助北京大学基础学科研究成果进行产业转化，为祖国的建设服务，就成了摆在北京大学面前的一项重要使命;另一方面，北京大学要建设成为世界一流大学，在未来尖端新技术的前沿学科和交叉学科占有一席之地，学科完备十分重要。这些需求，就要求北京大学大力发展工程学科。北京大学在工程技术人才培养、应用科学研究及技术开发等方面有进一步提高的空间。从当时的条件和国家发展形势来看，北京大学有条件组建起点较高的新的工学院模式，使之成为完备的研究型大学。2005 年 2 月，北京大学校长办公会议决定利用自身强大的理科、医科以及人文科学的综合学科优势，重新创建工学院。</p><p style=\"text-indent: 2em;\">　　工学院从成立开始就从高起点出发，立足于尖端科技、交叉学科，着眼于未来工程科学和新技术的发展方向，面向国家迫切需要及关系国家中长远经济发展的科学与技术研发。因此，北大工学院的发展以培育核心创造能力为中心，有所为、有所不为，优中求精。同时，学院采用与国际接轨的院长负责制，实行“教授治学，民主治院”。学院重建以来，在学科发展、队伍建设、科学研究、人才培养、合作与发展等方面取得了突出成绩。</p><p style=\"text-indent: 2em;\">　　学院现设有 5 个系，以及湍流与复杂系统国家重点实验室、北京市工程科学与新兴技术高精尖创新中心等多个重要研究机构，它们中不少已经进入世界先进学科的行列。其中力学学科在第四轮学科评估中被评为 A+ 学科，并入选“双一流”建设学科。学院教师实行国际通行的聘任制度(Tenure-Track) ，面向全世界公开招聘优秀人才。国家级人才计划（含青年项目）、长江学者、国家杰出青年基金获得者、国家优秀青年基金等人才计划获得者所占比例北京大学最高的学院之一。工学院现拥有 7 个本科专业、11 个博士专业（学术型 9 个，专业型 2 个）、14 个 硕 士 专 业（ 学 术 型 9 个， 专 业型 5 个）。高水平和国际化的教学体</p><p style=\"text-indent: 2em;\">　　系是学院的教学特色。学院是国家基础科学人才培养基地，在保持北京大学高水平的教学传统的同时，大力推进课程与教学改革，在培养科学家的同时，加大培养重大工程及产业领袖的 力 度， 并 通 过 联 合 培 养 和 交 流 等多种形式，加快教育国际化。例如，2009 年 学 院 开 始 的 与 美 国 佐 治 亚 理工大学和艾默里大学的生物医学工程联合博士学位项目，学生全球交换项目 Globex， 美 国 工 程 院“ 重 大 挑 战学 者 培 养 计 划 ”(Grand Challenges Scholar Program, GCSP)，与美国斯坦福大学、加拿大多伦多大学和新加坡国立大学联合举办的顶点设计项目等。学院也承办了一系列重大的国际活动，例如，2011 年 10 月成功主办了全球工程教育领袖峰会即“全球工学院院长大会”；2014 年 4 月，北京大学工学院主办 2014 亚洲工程教育领袖峰会（Asian Engineering Deans Summit，AEDS 2014）。2015 年， 北 京 大 学 工学院入选科技部（原国家外国专家局）和教育部联合实施的“高校国际化示范学院推进计划”第二批试点学院之一。2016 年 12 月授予华裔物理学家、诺贝尔物理学奖获得者、美国能源部前部长朱棣文教授北京大学名誉博士学位，2018 年 12 月 15 日授予美国国家工程院院长、中国工程院外籍院士丹尼尔 · 牟德北京大学名誉博士学位。“用世界的智慧与力量办世界一流工学院”是学院的办学理念。学院成立了由世界著名科学家组成的指导委员会，以及由国内外大型企业领袖组成的理事会，为学院的战略制定、资源拓展献计出力。产、学、研结合是学院办学 的 重 要 战 略 举 措。 学 院 尊 重 新 技术、新产业、新经济的发展规律，响应国家重大产业政策，创新发展了产学研合作机制和北京大学院企合作模式。学院积极构架“产学合作协同育人”平台 ：建设院企共建课程、完善企业实训体系、提高院企合作项目孵化效率。工学院致力于引领北京大学“新工科”发展的新思路，与业界紧密合作探索和推动国内工科发展的新方向。2021年，北大工学院“新工科国际化创新人才培养体系建设” 获北京大学教学成果特等奖。</p><p style=\"text-indent: 2em;\">具体参看：http://www.coe.pku.edu.cn/</p><p style=\"text-indent: 2em;\"><br></p>');
INSERT INTO `university_specialtys` VALUES (11, 3, 12, 70, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\">经济与金融专业<br>经济学对理解与指导中国经济的改革与发展、对帮助人们在日常工作与生活中进行理性决策都具有十分重要的作用。作为社会科学中科学性较强的一门学科，经济学本身的发展充满了活力，同时也对社会科学其他学科—特别是管理学、法学、政治学的发展起着重要的推动作用。经济学的研究和应用具有广阔的前景。金融则是经济学应用最为广泛与深入的领域之一。本科经济与金融专业的学习可为众多的职业选择打下坚实的基础。<br>清华大学经济与金融专业的培养目标是：为经济、金融、工商、政治、法律、社会等各界及各社会科学学术界培养既掌握系统的经济学与金融学理论和分析方法，又具备解决现代经济特别是金融领域中实际问题的技能、既具有国际视野同时也了解中国国情的高素质复合型人才。我们的特点是坚实的理论基础与强大的应用能力之间、高度的国际化与深入的本土化之间的有机结合。我们的师资队伍中既有长期参与中国经济与金融实践的教师，也有在哈佛大学、耶鲁大学等海外名校获得博士学位、甚至在海外研究型大学有多年教学研究经验的教师。同时，多位来自海外著名研究型大学的特聘教授也参与经济与金融本科专业的教学。<br>在教学计划上，我们既强调为学生提供一个扎实的基础，也重视让学生根据自己的兴趣与职业取向来选择专业课和其他学科的课程。基础课程包括经济学、金融学、会计与管理学基础理论课，数学和统计课，以及英语、写作与沟通、信息与网络技术等技能性课程。在基础课之上，我们开设大量经济学与金融学（包括保险）专业课程供学生选择。我们也鼓励学生选修其他院系的课程来开拓视野。本科毕业生的去向为在国内外高校继续深造（包括攻读经济学之外的研究生），进入国家经济管理部门，服务于证券公司、投资银行、商业银行、保险公司、各类投资基金及管理公司等金融机构，以及在管理与财务咨询公司和大型工商企业就业等等。以2006届毕业生为例，主要就业单位有：光大银行，外交部，先声药业，新奥燃气控股有限公司，兴业银行福州分行，招商银行，中国工商银行，中国国际金融有限公司，中国建设银行，中国农业银行，中国石油化工股份有限公司，中国银行，安永华明会计师事务所，德意志银行，高盛高华，Google，汇丰银行，麦肯锡，摩根大通，摩根斯坦利，普华永道会计师事务所，瑞士银行，英国石油等。</span></p>');
INSERT INTO `university_specialtys` VALUES (12, 3, 11, 69, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(240, 249, 246); font-size: 16px;\">法学 清华大学法学院创建于1929年，1952年由于全国高等院校院系调整，法律院系和法学教育在清华大学一度中断。1995年，清华大学正式恢复建立法律学系，1999年法学院正式复建。历史上，清华法学院曾培养出许多杰出的法学、法律人才，如前南国际法庭大法官、中国国际法学会前会长王铁崖先生，中国国际法学会前副会长陈体强教授，最高人民法院前副院长端木正先生等。 与传统法律院系不同，清华法学院秉承“学术为天下之公器，法律以明理为己任”的理念，广泛借鉴国内外优秀法学院办学¾­验，力图把“经院式”的法学教育转变为融理论和实践为一体的培养高素质法律人才的职业教育模式，即不仅要传授给学生必要的、精深的法学知识和理论，而且要培养学生具备在现实社会中灵活运用法律的技能、方法和综合素质，学会如何像律师那样思考，培养法律人良好的职业道德；把提高学生的全面素质和培养学生的创新能力放在突出位置，注重培养学生批判性思维和法律推理能力，使学生接受知识的过程同时成为参与法学研究和法律实践的过程。 今天，清华法学院已经成为名列前茅的国内著名法学院之一，在全国乃至国际法学教育界建立了自己的地位，成为我国法学教育和研究的一个重镇，同时也成为国际法学教育的一个重要交流中心。 教学设施 法学院教学设施和科研条件在国内首屈一指。建筑面积10,000平方米的法学大楼——明理楼于1999年12月正式投入使用，由前国家副主席荣毅仁同志亲自题写楼名。这也是国内第一次实现一个大学法学院拥有独立的法学楼，并且在国内率先为每一位教师提供了办公室。楼内配有现代化的教学、科研、办公设施，并专门用于教学实践的模拟法庭、学术报告厅、多功能教室等。 面积约有2,000余平方米的法律图书馆和电子阅览室集数字化与信息化于一身，配备系统空调及其他现代化设备。目前，法律图书馆拥有中外文法律书刊文献60,000册，同时订阅200余种国内外法律报刊、电子出版物等。除馆藏的现实文献外，学院还斥巨资购买国际权威法律专业数据库的使用权，读者可以利用先进的网络查询方式获取国内外的法律信息与法律研究资源。电子阅览室支持远程教学和电子教学等多项功能，可以实现与国外著名法学院的同步远程教学。 师资力量 清华法学院拥有一流的师资队伍。在50名专职教师中，有教授22人（含博士生导师19人），副教授15人。法学院师资力量具有两个比较突出的特点：一是在国外获得学位的比例在全国的法学院当中是最高的，在国外获得学位的比例占到了42%；二是在全世界前100名大学当中取得博士学位的，在全国的法学院当中是为数最多的。清华有9名，位列第二的学校有4名。 法学院名师荟萃，许多教授都是各自领域的学术权威，在国内外学界颇具影响。其中王保树教授担任中国法学会商法学研究会会长和中国法学会法学教育研究会副会长，马俊驹教授担任中国法学会民法学经济法学研究会副会长，崔建远教授担任中国民法学会副会长，朱慈蕴教授担任中国法学会商法学研究会副会长兼秘书长，贾兵兵教授当选亚洲国际法发展基金会执行委员会副主席。崔建远、张明楷和许章润等三位教授分别荣获第二届、第三届和第四届全国“十大杰出青年法学家”称号。周光权教授荣获2003年“胡绳学术奖”（中国社科青年学者最高奖）。王振民教授当选为全国人大常委会香港特别行政区基本法委员会和澳门特别行政区基本法委员会委员，成为现任委员中最年轻的一员。 此外，法学院还聘请校外兼职教授15人，客座教授3人，顾问教授1人。在不断完善队伍建设的同时，法学院还聘请海内外法学领域众多著名专家、学者，定期来校讲学或进行学术座谈。 学生培养 ——教学特色。清华法学院积极引进并倡导先进的交互式教学、讨论式教学和案例教学法，使学生主动参与课堂教学环节。在中国进行首批“诊所法律教育”，与北京市海淀区消费者权益保护协会共同设立了“消费者权益保护投诉与支持中心”，并设立劳动者权益保护法律诊所，通过对弱势群体提供无偿的法律援助，可以使学生了解最基层的民众的法律需求，了解适用法律的过程，锻炼和培养学生的公益心、执业技能和职业道德。为了培养学生良好的语言基础和广阔的学术视野，清华法学院还是国内唯一一家开设英美普通法系列课程的法学院，此外还有大量课程采用全英文教学。 ——教学模式。依照清华法学院自身培养模式，全面推行与国际接轨的学分制。除学校所规定的人文社科类课程、自然科学类课程以及必要的跨系选修课程之外，还设有法学绪论、宪法学、民法总论、商法总论、刑法总论、国际法学、民事诉讼法学、行政法与行政诉讼法学等专业必修课。学院还开设了大量由本院教师、外请专家以及外教开设的专业选修课，并且按照课程的性质分为不同的课组，其中包括法理学课组、宪法与行政法学课组、法史课组、民法学课组、商法学课组、经济法学课组、刑法学课组、环境资源法课组、诉讼与仲裁法课组、国际法学课组、实践课组以及文献阅读课组等，学生可以根据自己的爱好和志向，在教师的指导下选修完成。 ——国际比赛。清华法学院不断探索法学教育的新道路，大胆地尝试以增强学生实务能力为目标的教学改革。其中，模拟法庭和模拟仲裁的训练就是其中的两项重要内容。在国际比赛中，法学院至今保持着中国代表队在亚洲杯­模拟法庭大赛（2000/东京，第二名）、国际商事仲裁比赛（2003/维也纳，第六名）、国际空间法模拟法庭比赛（2004/悉尼，第三名）和亚太商事仲裁比赛（2004/香港，第一名）的最好成绩。 ——社会实践。清华法学院在河北、新疆等地法院建立了社会实践基地，努力引导学生利用假期深入基层进行社会实践活动。每年寒暑假，80%左右的法学院学生在学院组织下，奔赴祖国各地进行专业和社会实践活动，这不仅提高了学生处理法律实务的能力，还促进了学校的课堂教学，密切了学校与社会的联系。 ——奖助学金。除学校提供的奖、贷、助学金之外，法学院还在国内外著名法学院、律师事务所、跨国企业以及社会各界支持下设置了众多奖学金项目，以鼓励、支持同学努力完成学业。目前本科生奖助学金授予面高达60%左右，每学年发放总额超过30万人民币，个人最高获奖额达到12,000元。 教学科研 法学院学科建设一日千里。学院目前已取得“教育部国家重点学科基地”，拥有博士学位授予权一级学科点，法学理论、民商法学、国际法学、经济法学、诉讼法学、刑法学、宪法行政法学、环境与资源保护法学等八个硕士学位授予点和一个法律硕士专业学位授予点。此外，法学院还举办了面向全球招生的LLM（法学硕士）项目、与香港大学合作的中国法律第二学位课程以及远程教育项目等。 近十年来，法学院教师们在圆满完成自己的教学任务前提下，还承担了许多重大科研课题，取得了丰硕的科研成果：如组织《公司法修改稿》、《民事诉讼法修改稿》专家稿起草、参与物权法典的制定、参与外交部门决策研究工作等。法学院历年都要举办数次高水平的国际学术研讨会，一批批著名的国内外法学专家、学者，聚首清华法学院，交流、研讨国内外法学前沿问题，营造出严谨、求实、活跃、创新的学术氛围。 国际交流 为适应全球化的大趋势和中国加入WTO的大背景，法学院积极扩大对外学术交流。目前近25%的本科生有机会赴海外交流或交换学习。学院先后与美国哈佛大学、杜克大学、密歇根大学、波士顿大学、宾夕法尼亚大学、英国伦敦大学国王学院、巴黎大学、日本早稻田大学、名城大学、横滨国立大学、名古屋大学、新加坡国立大学、香港大学、香港城市大学等院校建立了密切的合作关系，定期派师生互访。 毕业前景 法学院实行“本科—硕士研究生分阶段有统筹”的培养模式，相当数量优秀学生可以通过免试推荐方式被保送进入本院硕士研究生阶段进行学习。部分优秀学生被推荐免试到清华其他院系或者其他高校攻读硕士、博士学位。此外，每年本科毕业生当中大约有15%进入世界一流的剑桥大学，牛津大学，哈佛大学，哥伦比亚大学，杜克大学，慕尼黑大学，伦敦大学等继续深造。 法学院选择就业的学生就业率在全国各大法学院名列前茅。毕业生就业领域广泛分布于与法律相关的各个领域，其中本科生参加就业的同学80%进入了中央或地方国家机关、司法机关、金融机构、国有大中型企业、国际知名律师事务所等，如外交部、国家工商行政管理总局、国家开发银行总行、中国银行总行、中国石油化工集团公司、美迈斯律师事务所等。 联系方式 电话：010-62785697 62783483 传真：010-62786513 网址：http://www. Tsinghua.edu.cn/docsn/fxy/index.htm</span></p>');
INSERT INTO `university_specialtys` VALUES (13, 3, 9, 58, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\">英语语言文学专业 英语专业旨在培养具有较扎实的英语语言知识基础、较强的英语运用能力和广泛的人文、科技、经贸等专业基础知识，毕业后能从事翻译、教学、商贸、管理、国际文化与科技交流领域工作的高级英语人才。 在课程设置方面，根据专业培养目标制订的专业课程设置，力求体现在熟练掌握英语语言技能和相关知识的基础之上，突出清华大学独特的学科交叉、文理工渗透、中外古今贯通的特点。现在清华大学已经成为涵盖理、工、文、法、经济、管理、艺术和医学等学科的综合性大学。英语专业的学生除在本系学习专业必修课程和限选课程外，还可充分利用清华大学各学科的资源和优势，选修全校各系开设的一系列旨在提高人文、科技、管理等方面素质的课程。 外语系德、智、体诸方面成绩优秀者经推荐可攻读第二学位或免试攻读硕士学位。品学兼优者可享受学校设立的各类奖学金、助学金。 英语专业自1983年恢复招生以来，由于历届学生具有文理渗透的知识结构和较强的语言运用能力，毕业生在人才市场上始终保持较强的竞争优势，具有可塑性好、适应能力强等特点，受到用人单位的广泛好评和欢迎，其中不少人已成为各行各业的骨干。毕业生去向主要为：国家机关、新闻单位、大专院校、国企及研究所、各类公司、三资企业、国内外继续读研深造等。学生实习基地多选在中国日报、中国国际广播电台、北京电视台、各类公司企业、等等。</span></p>');
INSERT INTO `university_specialtys` VALUES (14, 9, 12, 70, '<h1 style=\"text-align: left;\"><span style=\"color: rgb(192, 0, 0); font-size: 16px; font-family: 宋体;\">数字经济（专业代码：</span><span style=\"color: rgb(192, 0, 0); font-size: 16px;\">020109T</span><span style=\"color: rgb(192, 0, 0); font-size: 16px; font-family: 宋体;\">，所属学科门类：经济学）</span></h1><p style=\"text-indent: 32px; text-align: left;\"><br></p><p style=\"text-indent: 32px; text-align: left;\"><strong>专业剖析：</strong>数字经济，正在重塑世界的未来。它不仅是技术的前沿，更是新时代经济发展的核心驱动力。数字经济，作为全球经济增长的新引擎，正在深刻改变我们的生活。数字经济的蓬勃发展产生了对具有熟练数字技能的数据分析与决策人才，以及掌握产业数字化理论与技术人才的迫切需求。本专业主要研究数字经济的运行规律，测度数字经济的规模，促进数字经济产业化与产业数字化发展，实现数字技术与工业、农业、服务业等行业的深度融合。</p><p style=\"text-indent: 32px; text-align: left;\"><strong>人才培养：</strong>培养具有人文素养、社会责任感和职业道德，面向经济类企业、事业单位等行业产业领域，能够综合应用经济学、大数据科学、人工智能、区块链技术及计算机科学的基础理论、专业知识和技术，分析和解决数字经济领域的复杂问题，能够在数字经济相关的政府部门、工商企业、中介服务机构、金融机构、科研单位等技术产业部门，从事产业数字化规划与建设、数据分析与挖掘、数字化管理、数字化转型建设等工作的高素质应用型人才。</p><p style=\"text-indent: 32px; text-align: left;\"><strong>核心课程：</strong>微观经济学、宏观经济学、政治经济学、金融学、应用统计学、数字经济学、财政学、计量经济学、数字运营管理、区块链原理及应用、数据库原理及其应用、大数据技术与经济分析等。</p><p style=\"text-indent: 32px; text-align: left;\"><strong>未来发展：</strong>本专业毕业生可以就业于数字经济相关的国家各级管理部门、工商企业、金融机构、科研单位及数字产业部门，从事有关大数据、区块链、人工智能、金融科技、电子商务等新兴领域的相关经济分析、金融分析和行业管理工作。</p>');
INSERT INTO `university_specialtys` VALUES (15, 9, 12, 73, '<h1><a href=\"\" target=\"\"><span style=\"color: rgb(192, 0, 0); font-size: 16px;\">金融工程</span></a><span style=\"color: rgb(192, 0, 0); font-size: 16px;\">（专业代码：020302，所属学科门类：经济学）</span></h1><p style=\"text-indent: 32px;\"><br></p><p style=\"text-indent: 32px;\"><br></p><p style=\"text-indent: 32px;\"><strong>专业剖析：</strong><span style=\"font-family: 宋体;\">金融工程专业主要面向商业银行及各类非银行金融机构管理岗位，培养具有创新意识、金融职业素养，掌握金融管理基本理论知识、具备金融实务操作能力，能够从事银行、证券、保险、信托等金融机构中的银行业务管理、理财顾问、咨询、营销等岗位工作的应用型技术技能型专门人才。</span></p><p style=\"text-indent: 32px;\"><strong>人才培养：</strong><span style=\"font-family: 宋体;\">本专业培养具有人文素养、社会责任感和职业道德，面向银行、证券、保险等行业产业领域，掌握经济学、金融工程专业知识和基本研究方法，具备经济金融问题的分析能力、创新意识和国际化视野；能处理银行、证券、基金等方面量化分析业务的基本能力；能在各类金融机构、工商企业从事金融产品设计、金融风险管理相关工作，适应社会经济发展的应用型金融工程专业人才。</span></p><p style=\"text-indent: 32px;\"><strong>核心课程：</strong><span style=\"font-family: 宋体;\">微观经济学、宏观经济学、逻辑学、政治经济学、会计学基础、财政学、</span>Python<span style=\"font-family: 宋体;\">程序设计基础、计量经济学、统计学原理、金融学、证券投资学、国际金融、量化投资、</span>Python<span style=\"font-family: 宋体;\">数据分析、金融伦理与职业道德、金融计量学、金融法规、国际金融、金融工程学、金融风险管理、公司金融等。</span></p><p style=\"text-indent: 32px;\"><strong>未来发展：</strong><span style=\"font-family: 宋体;\">本专业毕业生主要面向商业银行、邮政金融机构、证券公司、保险公司以及相关中介机构从事银行业务管理、出纳、信用卡业务经理、证券保险业务等岗位的金融业务运作和管理工作。</span></p><p style=\"text-indent: 2em;\"><br></p>');
INSERT INTO `university_specialtys` VALUES (16, 9, 6, 44, '<h1 style=\"text-align: left;\"><a href=\"\" target=\"\"><span style=\"color: rgb(192, 0, 0); font-size: 16px;\">机械电子工程</span></a><span style=\"color: rgb(192, 0, 0); font-size: 16px;\">（专业代码：080204，所属学科门类：工学）</span></h1><p style=\"text-indent: 32px; text-align: left;\"><strong>专业剖析：</strong><span style=\"font-family: 宋体;\">高性能、智能化的机电产品研发，能助推我国制造强国战略的尽早实现，能更好地服务人民的生产和生活，为社会创造安全、舒适、便捷的工作和生活环境。本专业是集机械工程、电子科学技术、计算机科学、控制技术工程等学科知识为一体的综合性工程应用专业。现代制造业需要大量的机电专业人才，毕业生就业前景广阔。本专业是江苏省卓越工程师教育培养计划专业、校一流专业。</span></p><p style=\"text-indent: 32px; text-align: left;\"><strong>人才培养：</strong><span style=\"font-family: 宋体;\">本专业培养具备机电一体化产品和控制系统设计、制造、检测与维修等专业能力，具有良好的专业素养、创新意识和创业精神，能从事机电设备系统及元件的设计、开发，机械装备运行管理、机电技术应用研究和生产管理及产品售后技术服务等方面工作的高素质应用型技术人才。</span></p><p style=\"text-indent: 32px; text-align: left;\"><strong>核心课程：</strong><span style=\"font-family: 宋体;\">工程图学、工程力学、机械设计基础、电工技术、电子技术、控制工程基础、传感器与检测技术、液压与气压传动技术、工程材料及其成形基础、电气CAD、机械制造技术基础、数控技术、电气控制与PLC应用、单片机原理与应用、机电一体化系统设计。</span></p><p style=\"text-indent: 32px; text-align: left;\"><strong>未来发展：</strong><span style=\"font-family: 宋体;\">本专业毕业生可在企事业单位从事机电一体化产品研究、设计、制造，以及生产、质量管理等工作；进行机电一体化设备的安装调试、编程控制、运行维护、故障维修等；未来可成为企事业单位的技术和管理骨干；可在机械类、控制类等相关专业攻读硕士研究生，继续深造。</span></p>');
INSERT INTO `university_specialtys` VALUES (17, 9, 3, 21, '<h1 style=\"text-align: left;\"><a href=\"\" target=\"\"><span style=\"color: rgb(192, 0, 0); font-size: 16px;\">工程造价</span></a><span style=\"color: rgb(192, 0, 0); font-size: 16px;\">（专业代码：120105，所属学科门类：工学）</span></h1><p style=\"text-indent: 32px; text-align: left;\"><strong>专业剖析：</strong><span style=\"font-family: 宋体;\">工程造价专业是工程技术、工程经济、管理学、建筑法律及工程信息化交叉的复合性专业。本专业需接受注册造价工程师的基本训练，同时具备较强的专业综合能力、实践能力、创新能力，在国内外土木工程及其他工程领域能够胜任工程决策和从事全生命周期工程造价管理与相关专业造价管理等技术工作。</span></p><p style=\"text-indent: 32px; text-align: left;\"><strong>人才培养：</strong><span style=\"font-family: 宋体;\">工程造价专业培养掌握土木工程及其他工程领域的工程技术、管理、经济、法律和信息方面的基本理论和基础知识，全面而系统地接受科学思维、系统思维、管理思维、人文思维和工程师的基本训练，具备知识获取和应用能力，分析和解决实际工程造价及管理问题等方面的能力。</span></p><p style=\"text-indent: 32px; text-align: left;\"><strong>核心课程：</strong><span style=\"font-family: 宋体;\"> </span></p><p style=\"text-indent: 32px; text-align: left;\"><span style=\"font-family: 宋体;\">主干学科：管理科学与工程、土木工程</span></p><p style=\"text-indent: 32px; text-align: left;\"><span style=\"font-family: 宋体;\">核心知识领域：建筑工程施工技术与组织、安装工程施工技术与组织、工程成本规划与控制、建筑工程预算、建筑与装饰工程清单计价、建筑设备安装、安装工程预算、工程合同管理、安装工程清单计价、工程造价控制与管理、项目管理、工程信息管理等。</span></p><p style=\"text-indent: 32px; text-align: left;\"><strong>未来发展：</strong><span style=\"font-family: 宋体;\">毕业生适合在各类建设单位、建设主管部门、工程造价咨询公司（事务所）、银行、建筑施工企业、房地产估价咨询机构、房地产开发公司、房地产策划代理机构、保险或各类中介机构及其他相关单位从事造价与成本管理、工程审计、可行性研究、投资决策、施工管理、房地产估价、房地产经营管理等工作。</span></p>');
INSERT INTO `university_specialtys` VALUES (18, 10, 12, 70, '<p style=\"text-indent: 2em;\"><strong>经济学（实验班）</strong></p><p style=\"text-indent: 2em;\"> </p><p style=\"text-indent: 2em;\"> 培养目标</p><p style=\"text-indent: 2em;\">经济学（实验班）建设定位是培养具有社会责任感、国际视野、思路开阔，践行社会主义核心价值观的高素质人才。提升学生熟练掌握经济学分析方法和计量经济软件应用能力，打造具有扎实经济理论基础，熟知本土发展经验，有较强的创新研究能力，适应面广、可塑性强、发展潜力大的经济学研究型专业人才。借助产业经济与流通经济学科科研优势，强化复合型专业特色人才培养。全力打造能够在国内外大学继续深造，或能在政府机构、各类经济部门、高校和科研机构从事经济理论和政策研究及实际经济工作的拔尖创新人才。</p><p style=\"text-indent: 2em;\"> 培养特色</p><p style=\"text-indent: 2em;\">根据经济改革和发展对创新型人才的需要，实验班通过强化理论基础、配备优秀教师、优化课程设置、创建全员全程经济学专业导师制培养模式，吸收学生参与教师的科研项目、提高学生的科研能力以及注重国际化的培养方式等措施来实现实验班的建设目标。主要特色如下：</p><p style=\"text-indent: 2em;\">---培养双复合型人才。依托“产业经济学北京市重点建设学科”和“经济学国家级特色专业建设点”雄厚的研究基础，充分利用我校流通经济研究所在流通领域厚重的研究成果优势，发挥城市农产品流通智库的影响力，构建与经济社会发展需要相适应的新型经济学课程体系，培养具有扎实理论功底和在产业经济与流通经济领域有所专长的人才。</p><p style=\"text-indent: 2em;\">---打造研究型人才。通过开设经济理论课、数学、数理和计量经济学课程，充分利用专业实践基地，培养具有扎实的经济学理论基础，能够熟练掌握现代数据定量分析和经济模型设计软件，具有较强理论应用分析能力的研究型人才。</p><p style=\"text-indent: 2em;\">---创建导师制模式。凭借雄厚师资力量，配备最优秀的经济学专业师资实现全员全程经济学专业导师制，导师就学生求学全过程从明确发展方向，科学选课，社会专业实践指导、参与科研项目研究和经济学相关竞赛及创业项目、毕业设计指导等方面开展学术生涯规划，探索人才培养有效模式。以“请进来，走出去”方式，邀请国内外专家学者就经济学领域研究的前沿成果，开设讲座和筹办主题交流活动，加强与英国技能优才中心和英国培生集团的合作，引入教育部学校规划建设发展中心的“中英技能一带一路国际化人才港”和“1（大四）+1（国外）”本硕连读项目，开展产学研实训教学实践，开拓国际视野，搭建考研和出国留学的直通车教学服务，为学生进入相关高校和研究机构继续深造创造良好的条件。</p><p style=\"text-indent: 2em;\"> 特色课程</p><p style=\"text-indent: 2em;\">除国家开设的基础课程外，开设政治经济学、微观经济学、宏观经济学、计量经济学、博弈论与信息经济学、经济思想史、统计学、会计学、金融学、财政学、国际经济学（双语）等必修课。还有数理经济学、计量经济学模拟、产业经济学、流通经济学、经济预测与决策学、区域经济学、消费经济学、商务经济学、行为与实验经济学（双语）等专业特色课。另外，强化国内外合作，设有暑期国际课程、企业家课堂、学科竞赛等实践学习环节。</p><p style=\"text-indent: 2em;\"> 所授学位</p><p style=\"text-indent: 2em;\">经济学学士学位</p><p style=\"text-indent: 2em;\"> 就业方向</p><p style=\"text-indent: 2em;\">在国内外大学继续深造，或者在政府机构、各类经济部门、高校和科研机构从事经济理论研究、经济政策研究，针对产业或流通问题开展经济分析，有望成为经济智库研究的生力军。</p><p style=\"text-indent: 2em;\"> </p><p style=\"text-indent: 2em;\"> </p><p style=\"text-indent: 2em;\"><strong>经济学专业</strong></p><p style=\"text-indent: 2em;\">国家级特色专业建设点</p><p style=\"text-indent: 2em;\"> </p><p style=\"text-indent: 2em;\"> 培养目标</p><p style=\"text-indent: 2em;\">培养系统掌握经济学基本理论和基础专业知识，熟练掌握现代经济分析方法，了解市场运行和产业发展规律，熟悉党和国家的经济方针、政策和法规，具有运用数量分析方法和现代技术手段进行社会经济调查、经济分析和实际操作的能力；能够从事经济分析和经济管理工作的专门型人才，以及培养具有更高理论层次的经济学后备人才。</p><p style=\"text-indent: 2em;\"> 培养特色</p><p style=\"text-indent: 2em;\">学科基础强大。北京物资学院经济学专业拥有“产业经济学北京市重点建设学科”、“经济学国家级特色专业建设点”、“北京市经济学品牌建设专业”、“经济学实验教学与数据处理中心”、“流通经济研究所”、“流通改革与流通现代化科研创新团队”、“现代产业经济研究中心”和“物流经济信息处理中心”，丰富的教学和科研资源为经济学专业的发展奠定了扎实的学科基础。</p><p style=\"text-indent: 2em;\">突出流通行业特色，培养行业分析研究人才。经济学专业传承已有的流通领域的行业背景和研究优势，致力于打造具有流通特色的经济学专业。在流通领域的教学科研，以及学生就业方面，本专业形成了自身突出的特色和优势。</p><p style=\"text-indent: 2em;\">国家级特色专业建设点，注重专业素养和量化分析能力培养，为学生进一步深造（考研、出国）夯实专业基础。</p><p style=\"text-indent: 2em;\"> 主干课程</p><p style=\"text-indent: 2em;\">微观经济学、宏观经济学、政治经济学、计量经济学、金融学、财政学、会计学、统计学、国际经济学、中国经济改革专题、发展经济学、产业经济学、区域经济学、流通经济学、商务经济学、博弈论与信息经济学、经济预测与决策学、物流学概论、运输经济学、消费经济学、商业银行经营学、金融市场学、投资学、商品期货实务、经济法等。</p><p style=\"text-indent: 2em;\"> 所授学位</p><p style=\"text-indent: 2em;\">经济学学士学位</p><p style=\"text-indent: 2em;\"> 就业方向</p><p style=\"text-indent: 2em;\">人才市场上对经济学专业人才的需求与日俱增，各级政府部门、综合经济管理部门、贸易部门、金融机构、企事业单位的经济分析、预测及其管理都需要大量的经济学专业人才。本专业毕业生能够胜任综合经济管理部门、政策研究部门、金融机构、咨询公司、企事业单位以及经济研究和教学部门经济分析、预测、规划、管理以及经济研究、教学和科研工作。</p><p style=\"text-indent: 2em;\"><br></p>');
INSERT INTO `university_specialtys` VALUES (19, 10, 12, 73, '<p style=\"text-indent: 2em; text-align: left;\"><strong>金融学专业</strong></p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> 培养目标</p><p style=\"text-indent: 2em; text-align: left;\">金融学专业致力于培养具有国际化视野，系统掌握金融知识和理论，具有金融创新、风险管理能力，能够在银行、证券、期货、基金、投资公司、保险等相关金融领域从事业务和管理工作的高素质应用型人才。</p><p style=\"text-indent: 2em; text-align: left;\"> 培养特色</p><p style=\"text-indent: 2em; text-align: left;\">金融学专业注重培养学生的理论素养与实践能力。设有国际金融、商业银行经营学、货币金融学3门校级精品课程。拥有商业银行模拟实验中心、信用评级分析实验室，依托实验室开设了《商业银行经营实务模拟》、《互联网金融》、《信用评级模拟》等独立实验课和课程实验。</p><p style=\"text-indent: 2em; text-align: left;\">2006年开始与海外大学合作，创办了“中外合作金融拔尖人才培养项目——国际金融课程班”。2015年开始与中央财经大学推出国际金融方向“双培计划”，进一步拓宽了专业领域。</p><p style=\"text-indent: 2em; text-align: left;\">此外还与多家期货公司、商业银行和科技金融企业开展合作，共同建设校外培训实习基地。</p><p style=\"text-indent: 2em; text-align: left;\"> 主干课程</p><p style=\"text-indent: 2em; text-align: left;\">货币金融学、国际金融、商业银行经营学、财政学、投资学、金融工程、保险学、金融风险管理、金融市场学、金融经济学、公司金融、金融市场与金融机构（双语）、中央银行学、金融数学、个人理财、税收学、农村金融学、商业银行经营实务模拟、金融时间序列、互联网金融等。</p><p style=\"text-indent: 2em; text-align: left;\"> 所授学位</p><p style=\"text-indent: 2em; text-align: left;\">经济学学士学位</p><p style=\"text-indent: 2em; text-align: left;\"> 就业方向</p><p style=\"text-indent: 2em; text-align: left;\">学生毕业后可到银行、基金公司、证券公司、期货公司、信托投资公司、保险公司、小额信贷公司、投资咨询公司等各类金融机构从事金融业务的开发、营销、经营与管理工作；可到中央银行、金融监管部门和政府其他经济管理部门从事宏观金融管理工作；也可到企事业单位从事相关金融与财务工作。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>金融学（期货与证券）</strong></p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> 培养目标</p><p style=\"text-indent: 2em; text-align: left;\">本专业是国内高校首家创设专业，学校被誉为期货人才培养的黄埔军校。该专业旨在培养掌握金融、证券、期货基础理论和方法，熟悉证券、期货等现代金融机构各项业务、证券期货政策和法规，以及证券、大宗商品期现市场和境内外市场运行规律，熟练运用外语及数理统计量化分析方法，胜任证券公司、期货公司、基金公司、投资公司、现货企业投融资业务和风险管理业务及相关工作，并具有良好政治素养和职业道德、较强的持续学习能力和社会适应能力、富有创新精神和实践能力及国际化视野的高素质应用型人才。</p><p style=\"text-indent: 2em; text-align: left;\"> 培养特色</p><p style=\"text-indent: 2em; text-align: left;\">依托学校物流流通特色、经济学院扎实的经济学和金融学背景以及本专业优良的历史传承，秉承“厚基础、宽口径、重实践、强能力”的培养理念，在加强经济、金融、证券、期货基础理论和实务知识教学的同时，突出学生证券期货业务实操能力、运用衍生工具进行风险管理能力、数学建模技巧与程序化交易能力、证券期货研究能力以及证券投资财富管理能力的培养，打造学生在证券、期货及衍生品投资、风险管理领域的优势竞争力。</p><p style=\"text-indent: 2em; text-align: left;\">1．建有学历、年龄、职称结构合理的高素质专业教师团队，拥有由业界知名专家、学者、杰出校友构成的强大外聘专家团队以及丰富的校外专家库资源。</p><p style=\"text-indent: 2em; text-align: left;\">2．建有国家级大学生校外实践教育基地以及配置先进的现代金融衍生品综合实验室。</p><p style=\"text-indent: 2em; text-align: left;\">3．与期货业协会、期货交易所、期货公司、证券公司、基金公司、大型现货企业等各类机构全方位合作，校企联合授课和定制化培养人才。</p><p style=\"text-indent: 2em; text-align: left;\">4．“课堂教学+社会实践+仿真实验+实盘大赛+创新创业能力”、“期货论坛+社会考证”的高素质复合型、创新型、应用型人才培养模式。</p><p style=\"text-indent: 2em; text-align: left;\"> 主干课程</p><p style=\"text-indent: 2em; text-align: left;\">政治经济学、微观经济学、宏观经济学、金融学、会计学、统计学、计量经济学、国际金融、财政学、金融市场学、期货市场学、公司理财、证券投资学、固定收益证券、金融衍生工具（双语）、金融工程、金融量化交易策略、投资银行学、期货投资分析、产业经济分析、期货法律基础、金融数据库应用与实践、金融计量分析、金融市场热点问题分析（双语）、金融计算与编程、金融风险管理等。</p><p style=\"text-indent: 2em; text-align: left;\"> 所授学位</p><p style=\"text-indent: 2em; text-align: left;\">经济学学士学位</p><p style=\"text-indent: 2em; text-align: left;\"> 就业方向</p><p style=\"text-indent: 2em; text-align: left;\">未来30年，国内股票市场、债券市场、私募市场、期货市场、证券期货经营机构、资本市场开放将得到稳定健康发展，社会亟需大量证券、期货专业人才。学生毕业后可以在证券公司、期货公司、商业银行、基金公司、投资公司、实体企业从事资产管理、财富管理以及风险管理等各类证券、期货业务。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>中外合作金融拔尖人才培养项目－国际金融课程班</strong></p><p style=\"text-indent: 2em; text-align: left;\">中外合作金融拔尖人才培养项目-国际金融课程班是北京物资学院经济学院国际化试点班，旨在培养国际金融领域的国际化、高素质、应用型专业人才。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> 项目特色</p><p style=\"text-indent: 2em; text-align: left;\">1．人才培养专业化：以国际化视野为引领，以突出国际金融业务为特色，注重实际案例分析和学生行业技能培养。</p><p style=\"text-indent: 2em; text-align: left;\">2．课程体系国际化：专业课程设置与国外知名大学商科专业保持一致。采用外语教学：专业课程采取从中英文双语教学逐步实现全英语教学的循序渐进的教学方式。</p><p style=\"text-indent: 2em; text-align: left;\">3．强化英语教学：大学英语教学和雅思英语教学相结合，听说读写互相融合的英语强化教学，使学生成为既掌握金融专业知识又具备英语专业毕业生水平的复合型人才。</p><p style=\"text-indent: 2em; text-align: left;\">4．选用国外最新原版教材：专业教材采用国外知名大学商科专业英文最新原版教材，所选教材适用于国际金融领域发展进程并保持学习内容和资讯的不断更新。</p><p style=\"text-indent: 2em; text-align: left;\"> 师资情况</p><p style=\"text-indent: 2em; text-align: left;\">课程班采用中教与外教相结合，双语与全英文授课相结合的教学模式。聘请国外合作大学或相关专业领域内的高水平外教，在强化英语训练的基础上进行部分专业课授课；同时，聘请学校最优质的教师团队或其他高校的优质教师，确保学生获得最优的教育。</p><p style=\"text-indent: 2em; text-align: left;\"> 选拔条件</p><p style=\"text-indent: 2em; text-align: left;\">中外合作金融拔尖人才培养项目－国际金融课程班是北京物资学院经济学院与国外合作大学共同创办的自费留学项目。凡被北京物资学院本科专业正式录取的学生，均可自愿报名参加中外合作金融拔尖人才培养项目－国际金融3+1或2+2课程班的学习选拔，从中择优录取25人。</p><p style=\"text-indent: 2em; text-align: left;\">学生前3年（去英国）或前2年（去美国或澳大利亚）在北京物资学院经济学院完成专业课程和英语学习后，达到国外合作大学的入学要求，转入国外相应大学的对应专业，继续专业方向课的学习。在规定期限内达到北京物资学院和国外合作大学学业要求的学生可获得两所大学的本科学位证书。</p><p style=\"text-indent: 2em; text-align: left;\"> 学习费用</p><p style=\"text-indent: 2em; text-align: left;\">国内住宿费：人民币750元－1,500元/学年（根据实际情况而定）。</p><p style=\"text-indent: 2em; text-align: left;\">国内学习费用：人民币22,000元/学年（学费和培训费），赴国外学习期间仍需缴纳北京物资学院所录取专业学费。</p><p style=\"text-indent: 2em; text-align: left;\">国外学习费用：学费和生活费为15－20万人民币（仅供参考）。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\">国外合作大学</p><table style=\"width: auto; text-align: left;\"><tbody><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">地区</td><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">序号</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">合作院校</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">美国</td><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">1</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">肯特州立大学</td></tr><tr><td colspan=\"1\" rowspan=\"4\" width=\"113\" style=\"text-align: left;\">英国</td><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">2</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">普利茅斯大学Plymouth University</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">3</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">德蒙福特大学De Montfort University</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">4</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">朴茨茅斯大学University of Portsmouth</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">5</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">格罗斯特大学University of Gloucestershire</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">澳大利亚</td><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">6</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">麦考瑞大学Macquarie University</td></tr></tbody></table><p><br></p>');
INSERT INTO `university_specialtys` VALUES (20, 10, 11, 69, '<p style=\"text-indent: 2em; text-align: left;\"><strong>金融学专业</strong></p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> 培养目标</p><p style=\"text-indent: 2em; text-align: left;\">金融学专业致力于培养具有国际化视野，系统掌握金融知识和理论，具有金融创新、风险管理能力，能够在银行、证券、期货、基金、投资公司、保险等相关金融领域从事业务和管理工作的高素质应用型人才。</p><p style=\"text-indent: 2em; text-align: left;\"> 培养特色</p><p style=\"text-indent: 2em; text-align: left;\">金融学专业注重培养学生的理论素养与实践能力。设有国际金融、商业银行经营学、货币金融学3门校级精品课程。拥有商业银行模拟实验中心、信用评级分析实验室，依托实验室开设了《商业银行经营实务模拟》、《互联网金融》、《信用评级模拟》等独立实验课和课程实验。</p><p style=\"text-indent: 2em; text-align: left;\">2006年开始与海外大学合作，创办了“中外合作金融拔尖人才培养项目——国际金融课程班”。2015年开始与中央财经大学推出国际金融方向“双培计划”，进一步拓宽了专业领域。</p><p style=\"text-indent: 2em; text-align: left;\">此外还与多家期货公司、商业银行和科技金融企业开展合作，共同建设校外培训实习基地。</p><p style=\"text-indent: 2em; text-align: left;\"> 主干课程</p><p style=\"text-indent: 2em; text-align: left;\">货币金融学、国际金融、商业银行经营学、财政学、投资学、金融工程、保险学、金融风险管理、金融市场学、金融经济学、公司金融、金融市场与金融机构（双语）、中央银行学、金融数学、个人理财、税收学、农村金融学、商业银行经营实务模拟、金融时间序列、互联网金融等。</p><p style=\"text-indent: 2em; text-align: left;\"> 所授学位</p><p style=\"text-indent: 2em; text-align: left;\">经济学学士学位</p><p style=\"text-indent: 2em; text-align: left;\"> 就业方向</p><p style=\"text-indent: 2em; text-align: left;\">学生毕业后可到银行、基金公司、证券公司、期货公司、信托投资公司、保险公司、小额信贷公司、投资咨询公司等各类金融机构从事金融业务的开发、营销、经营与管理工作；可到中央银行、金融监管部门和政府其他经济管理部门从事宏观金融管理工作；也可到企事业单位从事相关金融与财务工作。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>金融学（期货与证券）</strong></p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> 培养目标</p><p style=\"text-indent: 2em; text-align: left;\">本专业是国内高校首家创设专业，学校被誉为期货人才培养的黄埔军校。该专业旨在培养掌握金融、证券、期货基础理论和方法，熟悉证券、期货等现代金融机构各项业务、证券期货政策和法规，以及证券、大宗商品期现市场和境内外市场运行规律，熟练运用外语及数理统计量化分析方法，胜任证券公司、期货公司、基金公司、投资公司、现货企业投融资业务和风险管理业务及相关工作，并具有良好政治素养和职业道德、较强的持续学习能力和社会适应能力、富有创新精神和实践能力及国际化视野的高素质应用型人才。</p><p style=\"text-indent: 2em; text-align: left;\"> 培养特色</p><p style=\"text-indent: 2em; text-align: left;\">依托学校物流流通特色、经济学院扎实的经济学和金融学背景以及本专业优良的历史传承，秉承“厚基础、宽口径、重实践、强能力”的培养理念，在加强经济、金融、证券、期货基础理论和实务知识教学的同时，突出学生证券期货业务实操能力、运用衍生工具进行风险管理能力、数学建模技巧与程序化交易能力、证券期货研究能力以及证券投资财富管理能力的培养，打造学生在证券、期货及衍生品投资、风险管理领域的优势竞争力。</p><p style=\"text-indent: 2em; text-align: left;\">1．建有学历、年龄、职称结构合理的高素质专业教师团队，拥有由业界知名专家、学者、杰出校友构成的强大外聘专家团队以及丰富的校外专家库资源。</p><p style=\"text-indent: 2em; text-align: left;\">2．建有国家级大学生校外实践教育基地以及配置先进的现代金融衍生品综合实验室。</p><p style=\"text-indent: 2em; text-align: left;\">3．与期货业协会、期货交易所、期货公司、证券公司、基金公司、大型现货企业等各类机构全方位合作，校企联合授课和定制化培养人才。</p><p style=\"text-indent: 2em; text-align: left;\">4．“课堂教学+社会实践+仿真实验+实盘大赛+创新创业能力”、“期货论坛+社会考证”的高素质复合型、创新型、应用型人才培养模式。</p><p style=\"text-indent: 2em; text-align: left;\"> 主干课程</p><p style=\"text-indent: 2em; text-align: left;\">政治经济学、微观经济学、宏观经济学、金融学、会计学、统计学、计量经济学、国际金融、财政学、金融市场学、期货市场学、公司理财、证券投资学、固定收益证券、金融衍生工具（双语）、金融工程、金融量化交易策略、投资银行学、期货投资分析、产业经济分析、期货法律基础、金融数据库应用与实践、金融计量分析、金融市场热点问题分析（双语）、金融计算与编程、金融风险管理等。</p><p style=\"text-indent: 2em; text-align: left;\"> 所授学位</p><p style=\"text-indent: 2em; text-align: left;\">经济学学士学位</p><p style=\"text-indent: 2em; text-align: left;\"> 就业方向</p><p style=\"text-indent: 2em; text-align: left;\">未来30年，国内股票市场、债券市场、私募市场、期货市场、证券期货经营机构、资本市场开放将得到稳定健康发展，社会亟需大量证券、期货专业人才。学生毕业后可以在证券公司、期货公司、商业银行、基金公司、投资公司、实体企业从事资产管理、财富管理以及风险管理等各类证券、期货业务。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>中外合作金融拔尖人才培养项目－国际金融课程班</strong></p><p style=\"text-indent: 2em; text-align: left;\">中外合作金融拔尖人才培养项目-国际金融课程班是北京物资学院经济学院国际化试点班，旨在培养国际金融领域的国际化、高素质、应用型专业人才。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> 项目特色</p><p style=\"text-indent: 2em; text-align: left;\">1．人才培养专业化：以国际化视野为引领，以突出国际金融业务为特色，注重实际案例分析和学生行业技能培养。</p><p style=\"text-indent: 2em; text-align: left;\">2．课程体系国际化：专业课程设置与国外知名大学商科专业保持一致。采用外语教学：专业课程采取从中英文双语教学逐步实现全英语教学的循序渐进的教学方式。</p><p style=\"text-indent: 2em; text-align: left;\">3．强化英语教学：大学英语教学和雅思英语教学相结合，听说读写互相融合的英语强化教学，使学生成为既掌握金融专业知识又具备英语专业毕业生水平的复合型人才。</p><p style=\"text-indent: 2em; text-align: left;\">4．选用国外最新原版教材：专业教材采用国外知名大学商科专业英文最新原版教材，所选教材适用于国际金融领域发展进程并保持学习内容和资讯的不断更新。</p><p style=\"text-indent: 2em; text-align: left;\"> 师资情况</p><p style=\"text-indent: 2em; text-align: left;\">课程班采用中教与外教相结合，双语与全英文授课相结合的教学模式。聘请国外合作大学或相关专业领域内的高水平外教，在强化英语训练的基础上进行部分专业课授课；同时，聘请学校最优质的教师团队或其他高校的优质教师，确保学生获得最优的教育。</p><p style=\"text-indent: 2em; text-align: left;\"> 选拔条件</p><p style=\"text-indent: 2em; text-align: left;\">中外合作金融拔尖人才培养项目－国际金融课程班是北京物资学院经济学院与国外合作大学共同创办的自费留学项目。凡被北京物资学院本科专业正式录取的学生，均可自愿报名参加中外合作金融拔尖人才培养项目－国际金融3+1或2+2课程班的学习选拔，从中择优录取25人。</p><p style=\"text-indent: 2em; text-align: left;\">学生前3年（去英国）或前2年（去美国或澳大利亚）在北京物资学院经济学院完成专业课程和英语学习后，达到国外合作大学的入学要求，转入国外相应大学的对应专业，继续专业方向课的学习。在规定期限内达到北京物资学院和国外合作大学学业要求的学生可获得两所大学的本科学位证书。</p><p style=\"text-indent: 2em; text-align: left;\"> 学习费用</p><p style=\"text-indent: 2em; text-align: left;\">国内住宿费：人民币750元－1,500元/学年（根据实际情况而定）。</p><p style=\"text-indent: 2em; text-align: left;\">国内学习费用：人民币22,000元/学年（学费和培训费），赴国外学习期间仍需缴纳北京物资学院所录取专业学费。</p><p style=\"text-indent: 2em; text-align: left;\">国外学习费用：学费和生活费为15－20万人民币（仅供参考）。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\">国外合作大学</p><table style=\"width: auto; text-align: left;\"><tbody><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">地区</td><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">序号</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">合作院校</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">美国</td><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">1</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">肯特州立大学</td></tr><tr><td colspan=\"1\" rowspan=\"4\" width=\"113\" style=\"text-align: left;\">英国</td><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">2</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">普利茅斯大学Plymouth University</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">3</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">德蒙福特大学De Montfort University</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">4</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">朴茨茅斯大学University of Portsmouth</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">5</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">格罗斯特大学University of Gloucestershire</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">澳大利亚</td><td colspan=\"1\" rowspan=\"1\" width=\"113\" style=\"text-align: left;\">6</td><td colspan=\"1\" rowspan=\"1\" width=\"348\" style=\"text-align: left;\">麦考瑞大学Macquarie University</td></tr></tbody></table><p><br></p>');
INSERT INTO `university_specialtys` VALUES (21, 10, 9, 58, '<p style=\"text-indent: 2em; text-align: left;\"><strong>商务英语（实验班）</strong></p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\">为更好地满足学生个性化发展的需求，着力培养具有国际视野和人文素养，熟悉国际商务通行规则和惯例的高素质、应用型、复合型的国际化精英人才，外语学院商务英语专业自2020年起开设商务英语（实验班）。实验班注重培养学生的专业知识、实践能力和科研素质，强调因材施教促进学生的个性化发展。核心课配备一流师资，专业导师对学生进行全程一对一学业指导，鼓励学生开展研究型学习、参加商务实践活动，指导学生参与学科竞赛和科研项目，支持学生参加国内外交流活动，成长为商务实战型和英语学科研究型人才。该实验班将国际知名的剑桥商务英语考试、雅思考试、托福考试纳入培养方案的课程体系中来，定期邀请国外院校教师来院授课，加快商务英语人才的国际化。</p><p style=\"text-indent: 2em; text-align: left;\"> 实验班的优势</p><p style=\"text-indent: 2em; text-align: left;\">1. 配备一流师资：实验班配备一流师资，教学由外语学院教授、市院两级获奖教师实施全英授课，跨专业课程邀请学校优势学科的教授或副教授进行双语授课。</p><p style=\"text-indent: 2em; text-align: left;\">2. 一对一学业指导：实验班学生配备导师，对学生学业、生活和就业进行一对一指导，促使学生达成成长目标。</p><p style=\"text-indent: 2em; text-align: left;\">3. 人才培养高端化：通过英文和双语教学，学生英语运用能力和商务技能显著提升，通过强化实践教学提升国际商务领域的实操能力。学生拥有更多的海外学习、国际交流机会，为学生国际化发展奠定基础。</p><p style=\"text-indent: 2em; text-align: left;\">4．学生就业高质化：优先推荐实验班学生赴国外合作高校交换学习、读研深造；定期为实验班学生进行就业指导，邀请企业走进实验班，提供企业实习和就业面试机会。</p><p style=\"text-indent: 2em; text-align: left;\"> 主干课程</p><p style=\"text-indent: 2em; text-align: left;\">综合商务英语、国际人才英语、商务英语阅读与写作、商务英语听说、英语演讲与辩论、商务导论、研究方法与学术写作、跨境电子商务概论、商务英语笔译、商务英语口译、国际贸易实务、跨文化交际、管理学（双语）、经济学原理（双语）、国际商法、同声传译等。</p><p style=\"text-indent: 2em; text-align: left;\"> 所授学位</p><p style=\"text-indent: 2em; text-align: left;\">文学学士学位</p><p style=\"text-indent: 2em; text-align: left;\"> 就业方向</p><p style=\"text-indent: 2em; text-align: left;\">中国境内外企业对外交流部门，各级政府对外交流部门，经贸企业、金融机构、企事业单位的管理岗位等。</p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"> </p><p style=\"text-indent: 2em; text-align: left;\"><strong>商务英语专业</strong></p><p style=\"text-indent: 2em; text-align: left;\"> 专业前景</p><p style=\"text-indent: 2em; text-align: left;\">随着世界经济贸易往来日益频繁，我国将朝着经济多元化的方向发展，各类涉外产业蓬勃发展，各种形式的涉外经济实体与日俱增，商贸经济的往来与文化传播的范围在迅速扩大。市场需要适应性强、知识面广、综合能力突出的复合型、应用型英语人才。商务英语专业顺应了对这种人才的新要求，就业市场巨大，前景可观。北京作为国际大都市，外事活动、商贸活动、文化交流异常活跃，而且北京物资学院所在的通州区，作为北京城市副中心，正在规划建设国际医疗区、国际旅游区、国际商务区，将聚集大量涉外企业和国际机构，这都给学生提供了丰富的实习机会和就业机会。另外，学生毕业后还可以报考英语专业、国际商务或经济管理类专业的研究生。</p><p style=\"text-indent: 2em; text-align: left;\"> 培养目标</p><p style=\"text-indent: 2em; text-align: left;\">商务英语专业致力于培养英语基本功扎实，具有国际视野和人文素养，熟悉国际商务的通行规则和惯例，具备英语应用能力、商务实践能力、跨文化交流能力、思辨与创新能力、自主学习能力，能够在金融经济、文化交流、中外信息传播等多种国际商务领域胜任外事、外贸、管理、翻译、经济信息采编等工作的高素质应用型、复合型英语人才。</p><p style=\"text-indent: 2em; text-align: left;\"> 培养特色</p><p style=\"text-indent: 2em; text-align: left;\">本专业以培养应用型、复合型商务英语人才为目标，在夯实英语语言文学基础的同时，依托学校的经济和管理学科优势，强化对国际商务实践和商务英语翻译能力的培养，构建宽口径、实践和创新能力强的应用型、复合型人才培养模式。教学中使用英语专业教材和国际商务英语原版教材，并根据学生实际情况采用全英文授课或双语教学。根据学生的个性化成才需求和社会需求，设置专业选修课。注重实践教学，强调英语专业技能训练和国际商务实践并重，并通过暑期国际学校和企业家进课堂等方式，培养学生较强的专业实践能力。</p><p style=\"text-indent: 2em; text-align: left;\"> 主干课程</p><p style=\"text-indent: 2em; text-align: left;\">商务英语专业的课程包括通识教育课、学科基础课、跨学科平台课、专业必修课、专业选修课。专业核心课程包括综合商务英语、商务英语听说、商务英语阅读、商务英语写作、商务英语笔译、商务英语口译、国际贸易实务、工商导论、跨文化交际、经济学原理、管理学、国际商法等。</p><p style=\"text-indent: 2em; text-align: left;\"> 就业前景</p><p style=\"text-indent: 2em; text-align: left;\">本专业学生可在国家机关、企事业单位、中外贸易公司就职，从事外事、外贸、管理、翻译、经济信息采编等工作。近几年外语学院毕业生就业形势良好，就业单位包括国际新闻机关（如中国国际广播电台、中国日报社）、外（交）事部门（如英国驻华大使馆、新西兰驻沪总领馆）、国家重要企事业单位（如中国工商银行、中国电信股份有限公司、联想集团）、出版机构（如外语教学与研究出版社、外文出版社）和中外知名金融机构和贸易公司（如毕马威会计师事务所、德勤会计师事务所、汇丰银行）等。</p><p style=\"text-indent: 2em; text-align: left;\"> 所授学位</p><p style=\"text-indent: 2em; text-align: left;\">文学学士学位</p>');
INSERT INTO `university_specialtys` VALUES (22, 8, 7, 50, '<p style=\"text-indent: 32px; text-align: left;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">化学是对变化的研究——我们周围的社会和自然世界以及宇宙在不断变化，化学自然成为所有人类知识和研究的核心，并扮演着中心科学的角色。化学是关于自然界的基础知识，与物质科学、生物和医学科学、工程学、计算科学和工程、经济和其他社会科学的几乎所有分支都有密切的联系。现代化学尤其侧重于在原子和分子水平上理解、预测和操纵物质的结构、性质和反应。化学家发展并成为了大型科学协作的职业，拥有极高的专业化标准，并且在全球活跃的专业协会中相互支持。</span></p><p style=\"text-indent: 32px; text-align: left;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">西湖大学化学专业旨在通过平衡的课程和研究机会，提供关于自然界的宽广的知识基础和深入学科核心的创新研究。在化学学科的核心内容，即合成化学、物理和理论化学、生物化学和材料化学的基础上，还注重通过化学物理学与物理科学和通过化学生物学与生物医学科学的跨学科联系与交叉。</span></p><p style=\"text-indent: 32px; text-align: left;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">专业课程设计旨在教授学生化学实验的技艺和严谨的科学概念框架，这些是化学家们在原子和分子水平上理解、预测和操纵物质所需要的知识基础。化学的核心课程将围绕化学的主要分支学科来组织，并辅以必修的数学和物理课程。除了深入的核心培训外，还为学生提供了广泛多样的选修课和可选择的高级课程。这些选修课旨在让学生探索自己的兴趣，同时在相关科学学科中运用化学的概念和思维方法。</span></p>');
INSERT INTO `university_specialtys` VALUES (23, 8, 7, 47, '<p style=\"text-indent: 32px; text-align: left;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">物理学，也被称为是“自然哲学”。它研究的是物质的原理以及物质在时空中的运动规律。西湖大学物理系致力于为社会培养具有广阔视野和创造性思维的优秀物理研究人员。学科重点研究凝聚态物理、理论物理、原子、分子和光学物理等方面的研究方向，高能物理和天体物理也将是下一步发展的主要目标。</span></p><p style=\"text-indent: 32px; text-align: left;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">本专业旨在引导学生培养物理学家的思维方式、较强的实验或研究能力、优秀的数据分析能力和适应性，使学生能够学习凝聚态物理、量子材料、AMO物理等科学研究领域。</span></p><p style=\"text-indent: 32px; text-align: left;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">物理专业的学生将接受数学、理论和实验物理方面的扎实的训练。他们将通过课程学习、实验以及参加学术研讨会和学术报告来发展广泛的兴趣和技能。在此过程中学习到的知识和能力，将为他们的未来职业生涯打下坚实的基础。物理专业学生在毕业后，通常会在各种专业中取得成功，包括电气工程、计算机科学、化学、生命科学，甚至是金融。对于年轻的学生来说，这是一个值得奉献一生的领域。</span></p>');
INSERT INTO `university_specialtys` VALUES (24, 8, 6, 79, '<p style=\"text-indent: 32px; text-align: left;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">电子信息工程专业旨在培养具有全球视野、全面素养、持续学习能力和创造性思维的电子技术研究领域的未来引领者。通过培养学生的创新精神和实践能力，为其未来从事相关领域的研究、工作与创业奠定良好的基础。</span></p><p style=\"text-indent: 32px; text-align: left;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">专业课程体系包括基础数理、电子器件、模拟和数字集成电路、光学与光子学、半导体物理与器件、信号处理、控制理论、机器人学、计算机体系结构、人工智能和生物工程，为学生打下扎实的专业基础和实践能力。</span></p><p style=\"text-indent: 32px; text-align: left;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">通过采用小班教学、项目教学和主动学习，培养独立性和团队合作精神。学生有机会进入到顶尖的科研实验室或高科技公司并组建跨学科的团队，利用所掌握的技能和创造性思维解决现实世界的挑战。</span></p><p style=\"text-indent: 32px; text-align: left;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">本专业毕业生有望在全球顶尖大学进行研究生学习，在全球顶尖公司开始职业生涯，亦或成为一个优秀的创业者，推动包括集成电子和光学设计与测试、微纳制造、计算机系统、数据科学、人工智能、智慧城市、生物工程等领域的技术转化。</span></p>');
INSERT INTO `university_specialtys` VALUES (25, 8, 4, 29, '<p style=\"text-indent: 32px;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">医学是保障人类健康与生命质量的基石，也是推动生物科技与现代医疗技术创新的关键领域。在医疗技术的不断演进和医疗服务的持续拓展下，复合交叉已成为医学创新的新形态；临床与科研的相互支撑及相互转化是催生新药、新技术、新方法、新思维的关键要素。</span></p><p style=\"text-indent: 32px;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">临床医学专业致力于培养顶尖医师科学家，探索医学人才培养新路径。医师科学家是指接受过系统的生物医学科研训练，具有优秀基础研究水平和卓越临床实践能力，并且能够同时驾驭基础研究和临床实践两者迥异的思维模式，推进医疗创新的复合型领军人才。</span></p><p style=\"text-indent: 32px;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">临床医学专业注重因材施教和个性化培养，坚持“兴趣先导”“寓教于研”“学科交叉”的培养理念。本专业倡导探究式教学，注重激发学生对医学的兴趣，引导其深入理解医疗卫生领域的职业精神与核心内涵，夯实自然科学与人文社会科学的基础素养。同时，专业强调基础研究与临床实践的多层次、深度融合，依托西湖大学及国内外多元优质资源与平台，为学生提供丰富的科研训练与临床实践机会。专业致力于打破传统医学的学科界限，发挥交叉融合优势，重点培养学生的跨学科认知能力与科研思维方式，为其投身医学创新奠定坚实基础。</span></p><p style=\"text-indent: 32px;\"><span style=\"color: rgb(18, 43, 85); background-color: white; font-size: 19px;\">临床医学专业的学生将在条件成熟时继续完成医学教育的终极学位，最终成为具有强烈社会责任、扎实基础研究功底、宽广国际视野、卓越临床实践能力与医学科研创新能力的顶尖医师科学家，成为符合未来医学发展趋势的领军型人才。</span></p><p style=\"text-indent: 2em;\"><br></p>');
INSERT INTO `university_specialtys` VALUES (26, 3, 9, 60, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\">新闻学<br>清华大学新闻与传播学院成立于2002年4月，其前身是清华大学1985年开设的中文系编辑学专业和1998年成立的传播系。人民日报前总编辑范敬宜任院长。新闻传播学科是清华大学重点发展的学科。学院设有国际传播研究中心、影视传播研究中心、新媒体传播研究中心、媒介经营与管理研究中心和马克思主义新闻学与新闻教育改革研究中心。国家文化产业研究中心挂靠在学院。这些中心承担多项国际、国内重要科研项目，出版学术著作，并为国家有关部门提供大量决策和建议，在新闻学、国际传播、影视传播、新媒体传播、文化产业和媒介经­营管理等领域，具有较大的社会影响和学术影响。<br>清华大学新闻与传播学科发展迅速。1995年获新闻学硕士学位授予权；2000年增列传播学硕士学位授予权；2003年获传播学博士学位授予权；2006年获新闻传播学一级学科博士学位授予权；2007年被批准设立博士后流动站。学院的新闻学专业入选2007年度第一批高等学校特色专业建设点，为同类型高校相关专业建设和改革起到示范和带动作用。学院的整体实力包括教师人均科研经费、人均发表的科研著作和论文数均居国内高校同行前列；近几年来，人民大学、复旦大学等名校新闻院系的本科毕业生第一名均有选择到我院继续学习深造，显示出清华大学新闻与传播学科对优秀学生的吸引力。<br>“三高”的师资队伍<br>学院共有全职教师25人，其中教授13人（包括博士生导师7人），副教授 7人，讲师5人。教师队伍特色鲜明：一是国际化程度高，大部分教师在国外学习、工作过；二是获得博士学位的教师比例高，占教师数的72%；三是具有在媒体从业经历的教师比例高，约70%的教师具有媒体从业经历。如院长范敬宜教授，曾任《人民日报》总编辑；李希光教授，曾在新华社和《华盛顿邮报》等担任高级记者；司久岳教授，曾担任新华社常驻美国的高级记者长达八年；张小琴曾获“金话筒奖”，兼任中央电视台《社会经纬》栏目主持人，《新闻调查》栏目出镜记者等。此外，学院还聘有校内兼职教授2名，校外兼职教授8名，包括原英文《中国日报》总编辑朱英璜、凤凰卫视著名主持人曹景行先生及著名国际学者和媒体人多人常年在学院任教。<br>厚基础、宽口径、重实践的育人模式<br>学院以“素质为本、实践为用、面向主流、培养高手”为教育教学理念，注重培养学生广博深厚的文化底蕴、开阔的国际视野及交流能力、娴熟的新闻传播技巧。在课程设置上，人文社会科学和自然科学课程、跨学科课程约占总学分50%；专业课程约占50%。其中包括：新闻学原理、中国新闻传播史、外国新闻传播史、新闻采写、传播学原理、新闻评论、报刊编辑、广播电视新闻、网络新闻学、新媒体导论、影视艺术、媒体经营与管理、媒介伦理与法规、媒介批评、电视摄像、电视编辑和新闻摄影等。其中，“新闻采访与写作”被评为国家级精品课。学院绝大多数教授均为本科生开设专业课，同时学院经常邀请海内外知名专家和业界骨干开设讲座。<br>在人才培养上，学院一方面强调“读万卷书”，倡导学贯中西，融会古今，要求学生打下广博而坚实的知识基础；另一方面重视“行万里路”，积极引导学生深入社会，面向基层，关注国计民生，了解国情民情。学生的社会实践和新闻实践足迹涉及新疆楼兰古城、内蒙古草原、太行山老区、红军长征路、罗布泊、珍宝岛、北大荒等，收到良好效果。2003级李强同学，利用寒假在山西沁源县进行社会调查，写成4万余字《乡村八记》，《人民日报》以半版篇幅刊发。温家宝总理亲笔复信院长范敬宜教授，称赞“《乡村八记》是一篇有建议有内容的农村调查”。2006年2月7日，《光明日报》头版头条全文刊发中宣部和教育部联合调查组的报告《培养深爱国家和人民的当代大学生—清华大学新闻与传播学院教学与实践相结合的调查》，同时教育部以1号文件转发全国高校。<br>清华新闻与传播学院积极开展与中央新闻媒体的合作，人民日报、新华社、光明日报、经济日报、中央电视台、中国日报、中国青年报等单位都是学生的实习平台。大部分同学都能够到主流媒体实习一个学期。同时，为进一步培养熟悉境外传媒机构具有国际视野的人才，新闻与传播学院还与境外媒介机构进行探索性的合作，如选派学生到《南华早报》、路透社北京分社和韩国放送公社（KBS）等媒介机构实习。<br>学生的“第二课堂”丰富多彩。学生自己创办的报纸《清新时报》，在美清华园得到广大学子的认可与称道，2007年法国总统萨科奇来清华发表演讲，我院学生上台致意，同时赠送了一份《清新时报》。由2005届毕业生拍摄的纪录片在中央电视台《纪事》栏目播出，并获得2007年国际纪录片评选“金熊猫”奖。许多学生还直接参与教师的科研活动，2004级同学在教师指导下完成完成的“首都农民工媒体接触行为调查报告”，被中共中央理论刊物转发。2006年，清华大学出版社出版学院学生的作品集《学在清华（新闻传播卷）》，汇集一批学生的科研成果。<br>培养具有国际视野的创新人才<br>为了培养具有国际视野的新型创新人才，清华大学新闻与传播学院特别强化学生的英语训练，提高听、说、读、写及实际应用能力。除学校开设的普通英语课程外，学院还为本科生每个学期都开设了专业英语课，不少专业课程也都采用英语或者双语教学。清华新闻与传播学院国际化的另一体现就是，本科每一个班中，有约三分之一的学生是外国学生，各国学生在一起上课，促进了文化的交流与沟通；学院与国际知名媒体及公司建有联合研究机构，如“清华—路透联合新闻研究室”、“清华—奥美公共形象研究室”、“清华—拜尔公共健康与媒体研究室”、“清华—日本经济新闻社媒体研究所”等等，为学生参与国际合作研究提供条件；许多国际上的传媒机构在学院设立了奖学金，如东南亚最大的英文报纸《南华早报》奖学金、世界四大通讯社之一英国路透社奖学金、韩国KBS电视台奖学金以及法国杜孟奖学金等。清华新闻与传播学院的本科学生将有机会在本科阶段到海外学习交流。从2007年起，学院开设了全英文授课的“财经新闻”硕士研究生国际项目，有志在该方向继续深造的国内本科毕业生，可选择该硕士项目与来自世界各国的学生一起学习。<br>就业前景<br>新闻与传播方向毕业生主要就业领域为新闻出版、广播电视、网络传播、广告公关等媒体或机构从事采编、策划、管理和研究等工作。无论实习还是就业，学生的综合素质和专业素养均获得用人部门的高度评价，到主流媒体和党政机关就业是毕业生的主要选择。<br>成绩优良的毕业生有机会免试直接攻读新闻传播学及相关专业的硕士学位。清华大学新闻与传播学院本科毕业生继续攻读研究生的比例在全国新闻传播院系中名列前茅。2007年46位本科生毕业中18位获得推荐免试攻读研究生的资格，约占学生总数的40%，同时有5位出国(境)继续深造。<br>联系方式<br>网址：http://www.tsjc.tsinghua.edu.cn/</span></p>');
INSERT INTO `university_specialtys` VALUES (27, 3, 7, 47, '<p style=\"text-indent: 2em; text-align: left;\"><strong>招生专业：物理学、数理基础科学</strong></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(128, 0, 0);\"><strong>专业前景</strong></span></p><p style=\"text-indent: 2em; text-align: left;\"> &nbsp; &nbsp; &nbsp;物理学是自然科学中最重要的基础学科。物理学经过20世纪以相对论和量子力学建立为标志的革命，21世纪进入新的发展阶段，物理学与技术创新结合得更加紧密。物理系的毕业生将在科学研究和技术革新等更广阔的空间施展拳脚。</p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(128, 0, 0);\"><strong>比较优势</strong></span></p><p style=\"text-indent: 2em; text-align: left;\"> &nbsp; &nbsp; &nbsp; &nbsp;规模小而精，清华大学物理系现只有教师78 人，其中中科院院士9位，“千人计划”入选者5 人，“长江特聘教授”13 人，国家杰出青年基金获得者10 人。学术水平强，清华大学物理系在当今物理学发展相当迅速的热点领域，如凝聚态物理（纳米技术、拓扑绝缘体）、量子信息、天体物理等取得了一大批在国际上颇有影响的成果。人才培养质量高，作为教育部“基础学科拔尖学生培养试验计划”组成部分的清华学堂物理班，是攀登世界科学高峰突击队的培训基地，精心培养有志于从事物理学研究的拔尖创新人才。2012年，首批2008级的18名学堂班学生中有13名去国际顶尖大学或研究机构继续深造，5名学生保送清华研究生。</p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(128, 0, 0);\"><strong>人才培养</strong></span></p><p style=\"text-indent: 2em; text-align: left;\"> &nbsp; &nbsp; &nbsp; 物理系现设有“物理学”和“数理基础科学”两个本科专业。物理学专业培养具有扎实理论基础和较强科学实验能力的高质量的基础研究型和应用研究型的物理人才。数理基础科学专业培养具有良好理科素养，在以数学、物理为基础的学科领域（如信息、材料、能源、经济、生命等）开拓创新的应用型人才。</p><p style=\"text-indent: 2em; text-align: left;\"> &nbsp; &nbsp; &nbsp;全系学生在本科阶段前两年学习共同的数学和物理的基础课程，从本科二年级第二学期开始分流培养。基础科学班的科研专题训练（常简称Seminar）是三个学期的必修课。同学根据兴趣和志向自由选择学科、研究方向和导师，在导师的研究组里做科研训练。目前，物理系本科生科研训练的学科分布于物理、天文、数学、能源、信息、金融、材料、心理、生物等多个领域。</p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(128, 0, 0);\"><strong>物理系2009—2012届本科毕业生去向统计</strong></span><img src=\"http://join-tsinghua.edu.cn/publish/bzw/7529/20120412222956570239260/wuli.jpg\" alt=\"\" data-href=\"\" style=\"\"></p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(128, 0, 0);\"><strong>知名校友</strong></span></p><p style=\"text-indent: 2em; text-align: left;\"> &nbsp; &nbsp; &nbsp; 1999 年国家表彰的23 位“两弹一星”功勋奖章获得者中，有1 0位是清华物理系的毕业生。在物理系学习和工作过的两院院士达84人。物理系在各领域的杰出校友层出不穷</p><p style=\"text-indent: 2em; text-align: left;\"><strong>张朝阳</strong> 1981年入学，搜狐总裁</p><p style=\"text-indent: 2em; text-align: left;\"><strong>瞿晓铧</strong> 1981年入学，CSI阿特斯太阳能公司董事长兼首席执行官</p><p style=\"text-indent: 2em; text-align: left;\"><strong>许州</strong> 1983年入学，中国工程物理研究院应用电子学研究所所长</p><p style=\"text-indent: 2em; text-align: left;\"><strong>高海燕 </strong>1984年入学，美国杜克大学物理系系主任，终身教授</p><p style=\"text-indent: 2em; text-align: left;\"><strong>戴宏杰 </strong>1984年入学，美国斯坦福大学化学系教授，美国艺术与科学院院士</p><p style=\"text-indent: 2em; text-align: left;\"><span style=\"color: rgb(128, 0, 0);\"><strong>联系方式</strong></span></p><p style=\"text-indent: 2em; text-align: left;\">网址 | <a href=\"http://www.phys.tsinghua.edu.cn/\" target=\"\">http://www.phys.tsinghua.edu.cn</a></p>');
INSERT INTO `university_specialtys` VALUES (28, 3, 7, 50, '<table style=\"width: auto; text-align: left;\"><tbody><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\" style=\"text-align: left;\">化学系 招生专业：化学 化学是在原子和分子层面上研究物质的性质、组成、结构、变化规律及其应用的一门自然科学，是现代生命科学、材料科学和环境科学发展的基础。进入二十一世纪后，化学与生命科学、材料科学、信息科学的交叉日益紧密。面对生命科学、材料科学、信息科学等其它学科迅猛发展的挑战和人类对认识和改造自然提出的新要求，化学在不断开拓新的研究领域和思路的同时，不断地创造出新的物质和品种来满足人民的物质文化生活，造福国家，造福人类。我国未来发展中所面临的一系列问题，包括资源的有效开发利用、环境保护与治理、社会和经济的可持续发展、人口与健康和人类安全、高新材料的开发和应用等，都需要化学家的参与和贡献。 基本概况 清华大学化学系成立于1926年，先后共有50位系友当选为中国科学院院士和工程院院士，是国务院学位委员会批准的化学一级学科博士学位授予点。清华大学化学系师资力量雄厚，拥有一批充满朝气的中青年学术带头人，教师中现有教授34人，其中中国科学院院士2人（赵玉芬教授、张希教授），工程院院士1人（沈德忠教授）、长江特聘教授6人、国家杰出青年科学基金获得者10人、全国优秀博士论文获得者6人，还聘请了中科院理化技术研究所佟振合院士、华南理工大学曹镛院士、中科院物理研究所陈立泉院士等著名学者参与本系的教学和研究工作。 化学系目前设有无机化学、有机化学、分析化学和物理化学四个二级学科研究所，建有生命有机磷化学及化学生物学教育部重点实验室、有机光电子与分子工程教育部重点实验室，同时还设有分析中心、基础化学实验中心以及国家能谱中心、功能晶体与薄膜研究所等教学和科研机构。 化学系的科研方向不仅涵盖了现代化学的各主要领域，而且也包括了21世纪化学发展的最新生长点。研究内容有：生命过程中的化学问题及酶的作用机制与应用，有机光电子材料及器件，新型晶体功能材料，超分子自组装和纳米结构材料，中药复方的分子生物学研究，导电高分子材料的合成与性能研究，以新能源及环境保护为目标的新催化系统的研究等。 化学系拥有如俄歇电子能谱仪、X-射线光电子能谱仪、透射电子显微镜、扫描电子显微镜、超导核磁共振谱仪（200M、300M和600M）、液相色谱-质谱联用谱仪、气相色谱-质谱联用谱仪、X-射线荧光光谱仪、多晶和单晶X-射线衍射仪、拉曼光谱仪、傅立叶变换红外光谱仪、紫外可见吸收光谱仪等大型分析测试仪器。 学生培养与课程设置 化学系是化学一级学科博士、硕士学位授权点。清华大学化学系致力于培养能够跻身于世界科学前沿的优秀化学人才。在课程设置、科研训练和社会实践等环节上努力瞄准国际一流大学的理科培养模式，结合清华大学强大的工科优势，培养创新与实践能力强、理论基础扎实、知识面广、重视学术道德、追求科学真理、有团结和进取心的一流化学研究与管理人才，满足我国未来科学事业的发展对化学尖端人才的需求。 化学专业本科学制为四年，实行学分制教学计划。培养方案的课程结构体系为：人文社科通识教育（35学分）和理科基础平台课程（51学分），占最低学分要求的61%；化学主干课群（40学分），占最低学分要求的29%；选修课（15学分），占最低学分要求的10%；暑期实践14学分，综合论文训练15学分。学生在第三、第四学年可按不同的主修方向，选修适当的本科专业课程和研究生课程。 目前化学系本科四门主要课程都已经入选清华大学精品课，其中“有机化学与实验”和“仪器分析”课程已经被评为国家级精品课。2004年4位学生代表清华大学化学系参加全国大学生化学竞赛，获得了团体第一名的好成绩。化学系培养的学生中，涌现了一批佼佼者，获得的奖励包括全国优秀博士论文奖，国际化学热力学联合会优秀博士论文奖，国际催化理事会青年科学家奖，国际纯粹及应用化学联合会青年化学家奖等。 奖、助学金 化学系的在校生可以同时申请全校性的奖、助学金和专为化学系学生设立的奖学金，每年学生获奖面约为50%，全系本科生奖学金总额超过20万元。 毕业前景 化学系的毕业生主要在化学及其相关领域（如化工、生物、医药、材料、环境、能源、信息等）从事教学与科研工作。化学系每年有80% 以上的本科毕业生在国内、外深造，继续攻读硕士、博士学位。以2007年化学系的73名本科毕业生为例，60名学生选择了在国内外继续深造，准备继续报考研究生和继续联系出国的8名。 联系方式 电话：010-62783096 传真：010-62771149 邮箱：hxxjwk@mail.tsinghua.edu.cn； 网址：http://ns.chem.tsinghua.edu.cn</td></tr></tbody></table><p><br></p>');
