INSERT INTO `university_specialtys` VALUES (39, 12, 13, 75, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\">本专业培养具有一定马克思主义哲学理论素养和系统的专业基础知识，有进一步培养潜质的哲学专门人才，以及能在国家机关、文教事业、新闻出版、企业等部门从事实际工作的应用型、复合型高级专门人才。 <br> &nbsp; &nbsp; &nbsp;毕业生应获得以下几方面的知识和能力： <br> &nbsp; &nbsp; &nbsp;1.比较系统地掌握马克思主义哲学、中国哲学和西方哲学的理论和历史；<br> &nbsp; &nbsp; &nbsp;2.具有一定的社会科学、人文科学、自然科学、思维科学的相关知识；</span></p>');
INSERT INTO `university_specialtys` VALUES (40, 12, 12, 70, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\"> 本专业采用“开放式”教学与“实践型”人才培养模式，辅以现代化的教学手段和专业实验室教学，以培养“宽口径、厚基础、重实践”的经济理论研究和经济管理人才。主干课程有：政治经济学、西方经济学、会计学、统计学、计量经济学、国际经济学、货币银行学、财政学、国际金融、《资本论》选读、发展经济学、信息经济学、世界经济等。本专业特色是注重经济学理论研究、经济学方法研究，并紧密与现实经济相结合。本专业拥有河北省省级教学质量工程《经济学人才培养模式创新实验区》，并依托实验区建设，构建了旨在增强学生创新能力五大工程：(1)建立于上世纪90年代中期的双导师制；(2)创办于1998年的学生学术刊物《求索》杂志；(3)创办于2008年初的试验区；(4)创办于2008年的跨学科读书会；(5)创办于2009年的河北大学“行者”大学生能力建设基金会。毕业生就业方向主要是：报社、电台、出版社及理论宣传部门；企事业单位；政府经济管理部门等。</span></p>');
INSERT INTO `university_specialtys` VALUES (41, 12, 11, 69, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\">业务培养目标：本专业培养系统掌握法学知识，熟悉我国法律和党的相关政策，能在国家机关、企事业单位和社会团体、特别是能在立法机关、行政机关、检察机关、审判机关、仲裁机构和法律服务机构从事法律工作的高级专门人才。 <br> &nbsp; &nbsp; &nbsp;业务培养要求：本专业学生主要学习法学的基本理论和基本知识，受到法学思维和法律实务的基本训练，具有运用法学理论和方法分析问题和运用法律管理事务与解决问题的基本能力。</span></p>');
INSERT INTO `university_specialtys` VALUES (42, 12, 9, 58, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(240, 249, 246); font-size: 16px;\">一、培养目标： 本专业培养具有扎实的英语语言基础和比较广泛的科学文化知识，能在外事、经贸、文化、新闻出版、教育、科研、旅游等部门从事翻译、研究、教学、管理等工作的英语高级专门人才。 二、专业培养要求： 本专业学生主要学习英语语言、文学、历史、政治、经济、社会文化等方面的基本理论和基本知识，接受英语听、说、读、写、译等方面的严格训练，掌握一定的科研方法，具有从事翻译、研究、教学、管理工作的业务水平及较好的素质和较强的能力。 毕业生应获得以下几方面的知识和能力； 1、了解我国有关的方针、政策、法规； 2、掌握语言学、文学及相关人文和科技方面的基础知识； 3、具有扎实的英语语言基础和较熟练的听、说、读、写、译能力； 4、了解我国国情和英语国家的社会与文化； 5、具有较好的英语表达能力； 6、学习一门第二外国语； 7、掌握文献检索、资料查询的基本方法，具有初步科学研究的能力。 三、修业年限：四年； 授予学位：文学学士。 四、主要课程： 基础英语、高级英语、报刊选读、视听、口语、英语写作、翻译理论与实践、语言理论、语言学概论、主要英语国家的文学史及文学作品选读、主要英语国家国情。</span></p>');
INSERT INTO `university_specialtys` VALUES (43, 12, 9, 56, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(245, 245, 245); font-size: 16px;\">含汉语言文学、对外汉语、古典文献专业。</span></p>');
INSERT INTO `university_specialtys` VALUES (44, 14, 3, 21, '<p style=\"text-indent: 2em; text-align: -webkit-left;\"><strong>培养目标及就业方向：培养具有工程管理、工程技术、会计、工程监理等基础理论知识，具备工程造价及审计、招投标、成本核算和控制、工程项目管理等专业知识和技能的高等技术应用型人才。学生在校可考取二级建造师、造价员、质检员、资料员、安全员等相关证书。</strong></p><p style=\"text-indent: 2em; text-align: -webkit-left;\"><strong>主干课程：投资学、建筑材料、工程测量、建筑施工技术、施工企业会计、施工企业财务管理、工程造价控制、建筑工程计价技术、建设工程招投标与合同管理、建设工程监理等。</strong></p>');
INSERT INTO `university_specialtys` VALUES (45, 13, 13, 75, '<p><a href=\"http://zxxy.sxu.edu.cn/\" target=\"_self\" style=\"text-indent: 32px; text-align: left;\">山西大学哲学学院</a></p>');
INSERT INTO `university_specialtys` VALUES (46, 13, 12, 70, '<p><span style=\"color: rgb(102, 102, 102); background-color: rgb(240, 249, 246); font-size: 16px;\"> &nbsp; </span><a href=\"http://jgxy.sxu.edu.cn/\" target=\"_self\" style=\"text-indent: 32px; text-align: left;\">山西大学经济与管理学院</a><span style=\"color: rgb(102, 102, 102); background-color: rgb(240, 249, 246); font-size: 16px;\"> &nbsp;</span></p>');
INSERT INTO `university_specialtys` VALUES (47, 13, 12, 73, '<p><a href=\"http://jgxy.sxu.edu.cn/\" target=\"_self\" style=\"text-indent: 32px; text-align: left;\">山西大学经济与管理学院</a></p>');
INSERT INTO `university_specialtys` VALUES (48, 13, 11, 69, '<p><a href=\"http://fxy.sxu.edu.cn/\" target=\"_self\" style=\"text-indent: 32px; text-align: left;\">山西大学法学院</a></p>');
INSERT INTO `university_specialtys` VALUES (49, 13, 10, 68, '<p><a href=\"http://tyy.sxu.edu.cn/\" target=\"_self\" style=\"text-indent: 32px; text-align: left;\">山西大学体育学院</a></p>');
